INSERT INTO "public"."magic_items" ("category_specifier_text", "created_at", "ddb_id", "description_text", "id", "is_consumable", "is_cursed", "magic_item_category", "magic_item_rarity_id", "name", "requires_attunement", "slug", "updated_at", "variant_rarities") VALUES
	('Any Light, Medium, or Heavy', '2026-05-15 05:45:35.621161+00', '5351', 'The archfey Baba Yaga crafted many of these magic brooms. No two appear exactly alike. While holding the broom, you can take a Magic action to transform it into an Animated Broom under your control. The broom then moves into an unoccupied space as close to you as possible. The broom acts immediately after you on your Initiative count and remains animate until you take a Bonus Action and use a command word to render it inanimate.

On your turn, you can mentally command the animated broom if it is within 30 feet of you and you don’t have the Incapacitated condition (no action required). You decide what action the broom takes and where it moves during its next turn, or you can issue it a general command, such as to attack your enemies or guard a location.

If the broom is reduced to 0 Hit Points, it shatters and is destroyed. If the broom reverts to its inanimate form before losing all its Hit Points, it regains all of them.', 'd9ac91ed-1e88-404f-b515-194cb417ca6b', false, false, 'Wondrous Item', 'Very Rare', 'Luck Blade', false, 'instrument-of-scribing', '2026-05-15 05:45:35.621161+00', NULL),
	('Battleaxe, Greataxe, Halberd, or Handaxe', '2026-05-15 05:45:35.621161+00', '9228527', 'While this polished agate is on your person, you gain a +1 bonus to ability checks and saving throws.', 'ba720593-912b-4278-a9c4-256d92b1a2ec', true, false, 'Wondrous Item', 'Artifact', 'Dancing Sword', true, 'wand-of-orcus', '2026-05-15 05:45:35.621161+00', NULL),
	('Dagger', '2026-05-15 05:45:35.621161+00', '11295689', 'This staff can be wielded as a magic Quarterstaff that grants a +2 bonus to attack rolls and damage rolls made with it. It also has the following additional properties. Once one of these properties is used, it can’t be used again until the next dawn.

Lightning. When you hit with a melee attack using the staff, you can cause the target to take an extra 2d6 Lightning damage (no action required).

Thunder. When you hit with a melee attack using the staff, you can cause the staff to emit a crack of thunder audible out to 300 feet (no action required). The target you hit must succeed on a DC 17 Constitution saving throw or have the Stunned condition until the end of your next turn.

Thunder and Lightning. Immediately after you hit with a melee attack using the staff, you can take a Bonus Action to use the Lightning and Thunder properties (see above) at the same time. Doing so doesn’t expend the daily use of those properties, only the use of this one.

Lightning Strike. You can take a Magic action to cause a bolt of lightning to leap from the staff’s tip in a Line that is 5 feet wide and 120 feet long. Each creature in that Line makes a DC 17 Dexterity saving throw, taking 9d6 Lightning damage on a failed save or half as much damage on a successful one.

Thunderclap. You can take a Magic action to cause the staff to produce a thunderclap audible out to 600 feet. Every creature within a 60-foot Emanation originating from you makes a DC 17 Constitution saving throw. On a failed save, a creature takes 2d6 Thunder damage and has the Deafened condition for 1 minute. On a successful save, a creature takes half as much damage only.', '52c1858c-4e48-4476-9a3a-a403b084ea5c', false, false, 'Weapon', 'Very Rare', 'Nolzur’s Marvelous Pigments', false, 'sword-of-sharpness', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '4569', 'This amulet is fashioned from a shard of resilient material originating from an otherworldly realm. While you are wearing it, you gain the following benefits.

Spellcasting Focus. You can use the amulet as a Spellcasting Focus for your Warlock spells.

Unknown Spell. As a Magic action, you can try to cast a cantrip that you don’t know. The cantrip must be on the Warlock spell list and have a casting time of an action, and you make a DC 10 Intelligence (Arcana) check. On a successful check, you cast the spell. On a failed check, the spell fails, and the action used to cast it is wasted. In either case, you can’t use this property again until you finish a Long Rest.', 'b0e100e2-fe58-4cf9-86f5-1a062fda0874', false, false, 'Potion, Rarity Varies', 'Rare', 'Potion of Fire Breath', true, 'perfume-of-bewitching', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '9228367', 'This wand has 7 charges. While holding it, you can take a Magic action to expend 1 charge to cause a thin blue ray to streak from the tip toward a creature you can see within 60 feet of yourself. The target must succeed on a DC 15 Constitution saving throw or have the Paralyzed condition for 1 minute. At the end of each of the target’s turns, it repeats the save, ending the effect on itself on a success.

Regaining Charges. The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand’s last charge, roll 1d20. On a 1, the wand crumbles into ashes and is destroyed.', 'e4ae2db8-d8e0-43ff-b2e3-5c2ff1af3016', true, false, 'Potion', 'Legendary', 'Horn of Blasting', true, 'iron-bands-of-bilarro', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '27042', 'This ring has 3 charges, and it regains 1d3 expended charges daily at dawn. While wearing the ring, you can expend 1 charge to cast one of the following spells (save DC 13) from it:', 'a341c35c-b946-4965-afb7-f748a1ce4642', false, false, 'Weapon', 'Rare', 'Nolzur’s Marvelous Pigments', true, 'potion-of-fire-breath', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '9228348', 'The contents of this foul manuscript are the meat and drink of the wicked. It contains knowledge so horrid that to even glimpse the scrawled pages invites doom.

Most believe the lich-god Vecna authored the Book of Vile Darkness. He recorded in its pages every horrid idea, every corrupt thought, and every example of foul magic he came across or devised.

Other practitioners of evil have added their own input to the book’s catalog of vile knowledge. Their additions are clear, for the writers of later works stitched whatever they were writing into the tome or, in some cases, made notations and additions to existing text. There are places where pages are missing, torn, or covered so completely with ink, blood, and scratches that the original text can’t be divined.

Nature can’t abide the book’s presence. Ordinary plants wither in its presence, common animals are unwilling to approach it, and the book gradually destroys whatever it touches. Even stone cracks and turns to powder if the book rests on it long enough.

Whenever a creature that isn’t a Fiend or an Undead attunes to the Book of Vile Darkness, that creature makes a DC 17 Charisma saving throw. On a failed save, the creature is magically transformed into a Larva under the DM’s control. Only a Wish spell can reverse this vile transformation.

A creature attuned to the book must spend 80 hours reading and studying it to digest its contents and use its Adjusted Ability Scores, Tireless Form, Spells, Vile Lore, and Vile Speech properties.

The Book of Vile Darkness remains with you only as long as you strive to work evil in the world. If you fail to perform at least one evil act within the span of 10 days, or if you willingly perform a good act, the book disappears, your Attunement to it ends immediately, and you lose all benefits granted by it. If you die while attuned to the book, an entity of great evil claims your soul. You can’t be restored to life by any means while your soul remains imprisoned.

Adjusted Ability Scores. One ability score of your choice increases by 2, to a maximum of 24. Another ability score of your choice decreases by 2, to a minimum of 3. The book can’t adjust your ability scores again.

Tireless Form. While the book is on your person, you have Immunity to the Exhaustion condition.

Random Properties. The Book of Vile Darkness has the following random properties (see “Artifacts” in this chapter):

Spells. While attuned to the book, you can cast the following spells (save DC 18) from it:

Once you use the book to cast a spell, you can’t cast that spell again from it until the next dawn.

Vile Lore. You can reference the Book of Vile Darkness whenever you make an Intelligence check to recall information about some aspect of evil, such as lore about demons. When you do so, you have Advantage on that check.

At the DM’s discretion, the book might reveal secrets no mortal should know, such as the true names of powerful Fiends, foul rites that allow one to transform into a death knight or lich, or long-lost spells crafted by beings so evil their names ought never to be spoken aloud.

Vile Speech. While the book is on your person, you can take a Magic action to recite words from its pages in a foul, dead language. Each time you do so, you take 1d12 Psychic damage, and each creature within 15 feet of you takes 3d6 Psychic damage unless the creature is a Fiend or an Undead.

Destroying the Book. The Book of Vile Darkness allows pages to be torn from it, but any evil lore contained on those pages finds its way back into the book eventually, usually when a new author adds pages to the tome.

If a solar tears the book in two, the book is destroyed for 1d100 years, after which it re-forms in some far corner of the multiverse.

A creature attuned to the book for 100 years can unearth a phrase hidden in the original text that, when translated to Celestial and spoken aloud, destroys both the speaker and the book in a flash of radiance. However, as long as evil exists in the multiverse, the book re-forms 1d10 × 100 years later.', '404c93ee-2923-4279-ac92-b07d7b0ec0e6', true, false, 'Potion', 'Legendary', 'Wand of Orcus', false, 'axe-of-the-dwarvish-lords', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '9228922', 'When you attack an object with this magic weapon and hit, maximize your weapon damage dice against the target.

When you attack a creature with this weapon and roll a 20 on the d20 for the attack roll, that target takes an extra 14 Slashing damage and gains 1 Exhaustion level.', '6a7e2e4a-d4bb-4f8e-9376-ead5e242c320', false, false, 'Armor', 'Uncommon', 'Staff of Flowers', true, 'gem-of-brightness', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '5359', 'Whenever you roll this six-sided die, you can control which number it rolls.', 'a3147060-4b42-4bb8-8928-50a543ed59bb', false, false, 'Weapon', 'Rare', 'Headband of Intellect', true, 'sword-of-kas', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '9228524', 'While wearing this armor, you have a Swim Speed equal to your Speed. In addition, if you start your turn underwater with 0 Hit Points, you immediately regain 1d4 Hit Points. The armor can’t heal anyone again until the next dawn.

The armor is decorated with fish and shell motifs.', 'ebfbe84c-f9b6-4ddb-9505-97f4518ebfef', false, false, 'Wondrous Item', 'Very Rare', 'Wand of Fireballs', true, 'sending-stones', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '9058960', 'While you are attuned to this magic weapon, your Strength is 20 unless your Strength is already equal to or greater than that score. The weapon deals an extra 1d8 Thunder damage to any creature it hits and an extra 3d8 Thunder damage to objects it hits that aren’t being worn or carried.

The weapon has the following additional properties.

Clap of Thunder. As a Magic action, you can strike the weapon against a hard surface to create a loud clap of thunder audible out to 300 feet. You also create a 30-foot Cone of thunderous energy. Each creature in the Cone must succeed on a DC 15 Strength saving throw or have the Prone condition. Nonmagical objects in the Cone that aren’t being worn or carried take 3d8 Thunder damage.

Earthquake. As a Magic action, you can strike the weapon against the ground to create an intense seismic disturbance in a 50-foot-radius circle centered on the point of impact. Structures in contact with the ground in that area take 50 Bludgeoning damage, and each creature on the ground in that area must succeed on a DC 20 Dexterity saving throw or have the Prone condition. If that creature is also concentrating, it must succeed on a DC 20 Constitution saving throw, or its Concentration is broken. In addition, you can cause a 30-foot-deep, 10-foot-wide fissure to open up on the ground anywhere in the area. Any creature on a spot where the fissure opens must make a DC 20 Dexterity saving throw, falling into the fissure on a failed save or moving with the fissure’s edge on a successful one. Any structure on a spot where the fissure opens collapses into the fissure. Once you use this property, it can’t be used again until the next dawn.', 'befde254-6ac8-4fe9-8f31-85d01a3a63b4', false, false, 'Wondrous Item', 'Very Rare', 'Rod of Absorption', false, 'rod-of-the-pact-keeper', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '4755', 'An alchemical process has bonded silver to this magic weapon. When you score a Critical Hit with it against a creature that is shape-shifted, the weapon deals one additional die of damage.', '0c1b0622-fbf6-4bb5-a251-ea4771f12a34', true, false, 'Wondrous Item', 'Very Rare', 'Rope of Mending', false, 'spirit-board', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '9228928', 'You regain Hit Points when you drink this potion. The number of Hit Points depends on the potion’s rarity, as shown in the table below.

Whatever its potency, the potion’s red liquid glimmers when agitated.

Potion | HP Regained | Rarity
Potion of Healing | 2d4 + 2 | Common
Potion of Healing (greater) | 4d4 + 4 | Uncommon
Potion of Healing (superior) | 8d4 + 8 | Rare
Potion of Healing (supreme) | 10d4 + 20 | Very Rare', '228eb66d-ee55-42c4-845f-8c091df77699', false, false, 'Wondrous Item', 'Rare', 'Staff of the Python', true, 'quaals-feather-token', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '9229201', 'A Figurine of Wondrous Power is a statuette small enough to fit in a pocket. If you take a Magic action to throw the figurine to a point on the ground within 60 feet of yourself, the figurine becomes a living creature specified in the figurine’s description below. If the space where the creature would appear is occupied by other creatures or objects, or if there isn’t enough space for the creature, the figurine doesn’t become a creature.

The creature is Friendly to you and your allies. It understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. If you issue no commands, the creature defends itself but takes no other actions.

The creature exists for a duration specific to each figurine. At the end of the duration, the creature reverts to its figurine form. It reverts to a figurine early if its creature form drops to 0 Hit Points or if you take a Magic action while touching the creature to make it revert to figurine form. When the creature becomes a figurine again, its property can’t be used again until a certain amount of time has passed, as specified in the figurine’s description.

This bronze statuette is of a griffon rampant. It can become a Griffon for up to 6 hours. Once it has been used, it can’t be used again until 5 days have passed.

This ebony statuette, carved in the likeness of a horsefly, can become a Giant Fly (see the accompanying stat block) for up to 12 hours and can be ridden as a mount. Once it has been used, it can’t be used again until 2 days have passed.

These gold statuettes of lions are always created in pairs. You can use one figurine or both simultaneously. Each can become a Lion for up to 1 hour. Once a lion has been used, it can’t be used again until 7 days have passed.

Large Beast, Unaligned

AC 11 Initiative +1 (11)

HP 19 (3d10 + 3)

Speed 30 ft., Fly 60 ft.

Senses Darkvision 60 ft.; Passive Perception 10

Languages None

CR 0 (XP 0; PB +2)

These ivory statuettes of goats are always created in sets of three. Each goat looks unique and functions differently from the others. Their properties are as follows:

Goat of Terror. This figurine can become a Giant Goat for up to 3 hours. The goat can’t attack, but you can (harmlessly) remove its horns and use them as weapons. One horn becomes a +1 Lance, and the other becomes a +2 Longsword. Removing a horn requires a Magic action, and the weapons disappear and the horns return when the goat reverts to figurine form. While you ride the goat, any Hostile creature that starts its turn within a 30-foot Emanation originating from the goat must succeed on a DC 15 Wisdom saving throw or have the Frightened condition for 1 minute, until you are no longer riding the goat, or until the goat reverts to figurine form. The Frightened creature repeats the save at the end of each of its turns, ending the effect on itself on a success. Once it succeeds on the save, a creature is immune to this effect for the next 24 hours. Once the figurine has been used, it can’t be used again until 15 days have passed.

Goat of Traveling. This figurine can become a Large goat with the same statistics as a Riding Horse. It has 24 charges, and each hour or portion thereof it spends in goat form costs 1 charge. While it has charges, you can use it as often as you wish. When it runs out of charges, it reverts to a figurine and can’t be used again until 7 days have passed, when it regains all expended charges.

Goat of Travail. This figurine can become a Giant Goat for up to 3 hours. Once it has been used, it can’t be used again until 30 days have passed.

This marble statuette resembles a trumpeting elephant. It can become an Elephant for up to 24 hours. Once it has been used, it can’t be used again until 7 days have passed.

This polished obsidian horse can become a Nightmare for up to 24 hours. The nightmare fights only to defend itself. Once it has been used, it can’t be used again until 5 days have passed.

The figurine has a 10 percent chance each time you use it to ignore your orders, including a command to revert to figurine form. If you mount the nightmare while it is ignoring your orders, you and the nightmare are instantly transported to a random location on the plane of Hades, where the nightmare reverts to figurine form.

This onyx statuette of a dog can become a Mastiff for up to 6 hours. The mastiff has an Intelligence of 8 and can speak Common. It also has Blindsight with a range of 60 feet. Once it has been used, it can’t be used again until 7 days have passed.

This serpentine statuette of an owl can become a Giant Owl for up to 8 hours. The owl can communicate telepathically with you at any range if you and it are on the same plane of existence. Once it has been used, it can’t be used again until 2 days have passed.

This silver statuette of a raven can become a Raven for up to 12 hours. Once it has been used, it can’t be used again until 2 days have passed. While in raven form, the figurine grants you the ability to cast Animal Messenger on it.

Ability | Score | Mod | Save
STR | 14 | +2 | +2
DEX | 13 | +1 | +1
CON | 13 | +1 | +1

Ability | Score | Mod | Save
INT | 2 | -4 | -4
WIS | 10 | +0 | +0
CHA | 3 | -4 | -4', 'b0238fed-2b08-467d-8440-306a697fbeeb', false, false, 'Wondrous Item, Rarity Varies', 'Legendary', 'Ring of Evasion', true, 'moonblade', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '9229098', 'You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon.

Curse. This weapon is cursed and possessed by a vengeful spirit. Becoming attuned to it extends the curse to you. As long as you remain cursed, you are unwilling to part with the weapon, keeping it on your person at all times. While attuned to this weapon, you have Disadvantage on attack rolls made with weapons other than this one.

In addition, while the weapon is on your person, you must succeed on a DC 15 Wisdom saving throw whenever you take damage from another creature in combat. On a failed save, you must attack the creature that damaged you until you drop to 0 Hit Points or it does or until you can’t reach the creature to make a melee attack against it.

You can break the curse in the usual ways. Alternatively, casting Banishment on the weapon forces the vengeful spirit to leave it. The weapon then becomes a +1 Weapon with no other properties.', '3ecb5dbe-3af9-4484-9454-3285afadfbfc', false, false, 'Armor', 'Uncommon', 'Ring of Resistance', false, 'perfume-of-bewitching', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '9228921', 'If you take Cold damage while wearing this ring, the ring reduces the damage you take by 2d8.

In addition, while wearing this ring, you and everything you wear and carry are unharmed by temperatures of 0 degrees Fahrenheit or lower.', '121ac309-5aa3-4b8a-84b7-3f58bb5435aa', true, false, 'Wondrous Item', 'Artifact', 'Spellguard Shield', true, 'orb-of-time', '2026-05-15 05:45:35.621161+00', NULL),
	('Requires Attunement by a Bard', '2026-05-15 05:45:35.621161+00', '9228528', 'This book contains intuition and insight exercises, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book’s contents and practicing its guidelines, your Wisdom increases by 2, to a maximum of 30. The manual then loses its magic, but regains it in a century.', '282dd59c-c149-4bd9-bd1f-26a069dcf88b', false, false, 'Armor', 'Rare', 'Dust of Disappearance', false, 'gem-of-brightness', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '5370', 'This item functions as a Pole. While holding it, you can take a Magic action to collapse it into a 1-foot-long rod for ease of storage (the pole’s weight doesn’t change) or cause the 1-foot-long rod to revert to a Pole. The rod elongates only as far as the surrounding space allows.', 'ccc838c7-a904-4df2-ad3a-66878e6a6ecd', true, false, 'Staff', 'Legendary', 'Staff of the Magi', true, 'quarterstaff-of-the-acrobat', '2026-05-15 05:45:35.621161+00', NULL),
	('Any Light, Medium, or Heavy', '2026-05-15 05:45:35.621161+00', '9228966', 'This book contains guidelines for influencing and charming others, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book’s contents and practicing its guidelines, your Charisma increases by 2, to a maximum of 30. The manual then loses its magic but regains it in a century.', '3ce36902-5360-4610-9454-1145f9601e55', false, false, 'Wondrous Item', 'Artifact', 'Necklace of Fireballs', false, 'apparatus-of-kwalish', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '4654', 'While holding this fan, you can cast Gust of Wind (save DC 13) from it. Each subsequent time the fan is used before the next dawn, it has a cumulative 20 percent chance of not working; if the fan fails to work, it tears into useless, nonmagical tatters.', 'bb2550b9-efcd-4525-823e-b890150ee99f', true, false, 'Wondrous Item', 'Uncommon', 'Sword of Sharpness', true, 'walloping-ammunition', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '9229110', 'You have Resistance to Bludgeoning, Piercing, and Slashing damage while you wear this armor.

Metal Shell. You can take a Magic action to give yourself Immunity to Bludgeoning, Piercing, and Slashing damage for 10 minutes or until you are no longer wearing the armor. Once this property is used, it can’t be used again until the next dawn.', 'b1fa11ab-d58c-49dd-98b8-85d328d896a4', false, false, 'Ring', 'Rare', 'Sending Stones', true, 'potion-of-mind-reading', '2026-05-15 05:45:35.621161+00', NULL),
	(NULL, '2026-05-15 05:45:35.621161+00', '4783', 'When you take a Magic action to read this scroll, a particular titan named in the scroll appears in an unoccupied space on the ground or in water that you can see within 1 mile of yourself. The DM picks a suitable titan or determines it randomly by rolling on the table below (see the Monster Manual for the creature’s stat block).

The titan is Hostile toward all other creatures and disappears when it drops to 0 Hit Points. If the titan is summoned into a space that isn’t large enough to contain it, the summoning fails, and the scroll is wasted.

1d100 | Titan
01–15 | Animal Lord
16–30 | Blob of Annihilation
31–45 | Colossus
46–60 | Elemental Cataclysm
61–75 | Empyrean
76–90 | Kraken (a kraken requires a body of water large enough to contain it, or the summoning fails and the scroll is wasted)
91–00 | Tarrasque', 'b7ee7ebc-67c1-41b9-ae66-25d872aaedaf', false, false, 'Wand', 'Rare', 'Bag of Beans', true, 'ring-of-x-ray-vision', '2026-05-15 05:45:35.621161+00', NULL),
