	(NULL, '2026-05-15 05:45:35.621161+00', '4610', 'While holding this wand, you gain a bonus to spell attack rolls determined by the wand’s rarity. In addition, you ignore Half Cover when making a spell attack roll.', 'b1084b47-792b-4217-9fc4-9ae4e2352892', false, false, 'Wondrous Item', 'Uncommon', 'Sword of Kas', true, 'eyes-of-the-eagle', '2026-05-15 05:45:35.621161+00', NULL),
