INSERT INTO "public"."monsters" ("actions", "alignment", "armor_class", "bonus_actions", "challenge_rating", "charisma", "charisma_save", "constitution", "constitution_save", "created_at", "creature_type", "descriptive_tags", "dexterity", "dexterity_save", "experience_points", "experience_points_alt", "gear", "hit_point_dice", "hit_points", "id", "immunities", "initiative_modifier", "initiative_score", "intelligence", "intelligence_save", "languages", "legendary_actions", "name", "proficiency_bonus", "reactions", "resistances", "senses", "size", "skills", "speed", "speed_burrow", "speed_climb", "speed_fly", "speed_swim", "strength", "strength_save", "traits", "updated_at", "vulnerabilities", "wisdom", "wisdom_save") VALUES
	('{"Multiattack. The hobgoblin makes two attacks, using Greatsword or Longbow in any combination.","Greatsword. Melee Attack Roll: +4 , reach 5 ft. Hit: 9 ( 2d6 + 2 ) Slashing damage plus 3 ( 1d6 ) Poison damage.","Longbow. Ranged Attack Roll: +4 , range 150/600 ft. Hit: 6 ( 1d8 + 2 ) Piercing damage plus 5 ( 2d4 ) Poison damage."}', 'Chaotic Good', 19, '{}', '2', 14, 2, 10, 11, '2026-05-15 05:45:35.571633+00', 'Undead', '(Wizard)', 9, 3, 1800, NULL, 'Hide Armor , Light Hammers (3)', '2d8 + 4', 65, '4f7a5764-e2a3-4304-a19a-c9a65be6742d', '{Cold}', '+5', 18, 13, 2, 'Common, Primordial (Auran)', '{}', 'Flameskull', 3, '{}', '{Acid,Cold,Fire,Lightning,Thunder}', '{"Darkvision 60 ft.","Passive Perception 10"}', 'Medium', '{}', '30 ft.', NULL, NULL, NULL, NULL, 16, -5, '{}', '2026-05-15 05:45:35.571633+00', NULL, 11, 7),
	('{"Multiattack. The doppelganger makes two Slam attacks and uses Unsettling Visage if available.","Slam. Melee Attack Roll: +6 (with Advantage during the first round of each combat), reach 5 ft. Hit: 11 ( 2d6 + 4 ) Bludgeoning damage.","Read Thoughts. The doppelganger casts Detect Thoughts , requiring no spell components and using Charisma as the spellcasting ability (spell save DC 12).","Unsettling Visage (Recharge 6). Wisdom Saving Throw: DC 12, each creature in a 15-foot Emanation originating from the doppelganger that can see the doppelganger. Failure: The target has the Frightened condition and repeats the save at the end of each of its turns, ending the effect on itself on a success. After 1 minute, it succeeds automatically."}', 'Neutral', 14, '{"Quick Grapple. Dexterity Saving Throw: DC 13, one Medium or smaller creature the bugbear can see within 10 feet. Failure: The target has the Grappled condition (escape DC 13)."}', '0', 19, 0, 14, 11, '2026-05-15 05:45:35.571633+00', 'Humanoid', NULL, 15, 5, 450, NULL, 'Daggers (10)', '9d10 + 45', 7, 'da0dcac6-b23a-418a-a85d-b9681e046a80', '{Acid}', '+0', 12, 2, 0, 'Common, Gith', '{}', 'Young Red Dragon', 2, '{}', '{Cold}', '{"Darkvision 60 ft.","Passive Perception 14"}', 'Medium', '{"Perception +4"}', '40 ft.', NULL, NULL, NULL, NULL, 18, 3, '{"Pack Tactics. The wolf has Advantage on an attack roll against a creature if at least one of the wolf’s allies is within 5 feet of the creature and the ally doesn’t have the Incapacitated condition."}', '2026-05-15 05:45:35.571633+00', NULL, 17, 0),
	('{"Multiattack. The tough makes two attacks, using Warhammer or Heavy Crossbow in any combination.","Warhammer. Melee Attack Roll: +5 , reach 5 ft. Hit: 12 ( 2d8 + 3 ) Bludgeoning damage. If the target is a Large or smaller creature, the tough pushes the target up to 10 feet straight away from itself.","Heavy Crossbow. Ranged Attack Roll: +4 , range 100/400 ft. Hit: 13 ( 2d10 + 2 ) Piercing damage."}', 'Neutral Evil', 16, '{}', '6', 14, 4, 13, 3, '2026-05-15 05:45:35.571633+00', 'Celestial', NULL, 11, 0, 700, NULL, NULL, '20d20 + 160', 22, '771fb67a-bcc3-4d6c-9083-b71edbb35e7f', '{}', '+10', 11, 7, -1, 'None', '{}', 'Ancient Blue Dragon', 6, '{}', '{}', '{"Darkvision 60 ft.","Passive Perception 12"}', 'Huge', '{"Stealth +2"}', '30 ft.', NULL, NULL, NULL, NULL, 1, 8, '{"Demonic Restoration. If the glabrezu dies outside the Abyss, its body dissolves into ichor, and it gains a new body instantly, reviving with all its Hit Points somewhere in the Abyss .","Magic Resistance. The glabrezu has Advantage on saving throws against spells and other magical effects."}', '2026-05-15 05:45:35.571633+00', NULL, 5, -2),
	('{"Multiattack. The dragon makes three Rend attacks. It can replace one attack with a use of (A) Sleep Breath or (B) Spellcasting to cast Scorching Ray (level 3 version).","Rend. Melee Attack Roll: +14 , reach 15 ft. Hit: 19 ( 2d10 + 8 ) Slashing damage plus 7 ( 2d6 ) Fire damage.","Fire Breath (Recharge 5–6) . Dexterity Saving Throw: DC 21, each creature in a 90-foot-long, 5-foot-wide Line . Failure: 58 ( 13d8 ) Fire damage. Success: Half damage.","Sleep Breath. Constitution Saving Throw: DC 21, each creature in a 90-foot Cone . Failure: The target has the Incapacitated condition until the end of its next turn, at which point it repeats the save. Second Failure: The target has the Unconscious condition for 10 minutes. This effect ends for the target if it takes damage or a creature within 5 feet of it takes an action to wake it.","Spellcasting. The dragon casts one of the following spells, requiring no Material components and using Charisma as the spellcasting ability (spell save DC 20):","At Will: Detect Magic , Minor Illusion , Scorching Ray (level 3 version), Shapechange (Beast or Humanoid form only, no Temporary Hit Points gained from the spell, and no Concentration or Temporary Hit Points required to maintain the spell), Speak with Animals","1/Day Each: Control Weather , Detect Thoughts"}', 'Lawful Evil', 15, '{}', '6', 9, 0, 21, 2, '2026-05-15 05:45:35.571633+00', 'Plant', NULL, 12, 9, 25, NULL, NULL, '3d6 + 3', 110, '6005c20a-e7c8-480c-9b24-6cfa08535bc5', '{Fire,"Poison; Poisoned"}', '+1', 12, 3, 0, 'Common plus one other language', '{}', 'Lizardfolk Geomancer', 4, '{}', '{}', '{"Blindsight 60 ft., Darkvision 120 ft.","Passive Perception 24"}', 'Medium', '{}', '30 ft.', NULL, NULL, NULL, NULL, 10, 2, '{"Magic Resistance. The yuan-ti has Advantage on saving throws against spells and other magical effects."}', '2026-05-15 05:45:35.571633+00', NULL, 12, 1),
	('{"Multiattack. The yeti can use its Chilling Gaze and makes two attacks, using Claw or Ice Throw in any combination.","Claw. Melee Attack Roll: +11 , reach 5 ft. Hit: 14 ( 2d6 + 7 ) Slashing damage plus 7 ( 2d6 ) Cold damage.","Ice Throw. Ranged Attack Roll: +11 , range 60/240 ft. Hit: 12 ( 2d4 + 7 ) Bludgeoning damage plus 7 ( 2d6 ) Cold damage.","Chilling Gaze. Constitution Saving Throw: DC 18, one creature the yeti can see within 30 feet. Failure: 21 ( 6d6 ) Cold damage, and the target has the Paralyzed condition until the start of the yeti’s next turn unless the target has Immunity to Cold damage. Success: The target is immune to this yeti’s Chilling Gaze for 1 hour.","Cold Breath (Recharge 6). Constitution Saving Throw: DC 18, each creature in a 30-foot Cone . Failure: 45 ( 10d8 ) Cold damage. Success: Half damage."}', 'Chaotic Evil', 14, '{}', '23', 9, -4, 18, 0, '2026-05-15 05:45:35.571633+00', 'Dragon', '(Lycanthrope)', 20, 2, 450, NULL, NULL, '9d8 + 27', 119, '16f566ac-5ba6-4c97-98c6-fc44fdd79f61', '{}', '-1', 13, 14, 3, 'Gnoll', '{}', 'Arch-hag', 2, '{}', '{}', '{"Darkvision 120 ft.","Passive Perception 12"}', 'Large', '{}', '40 ft.', NULL, '40 ft.', NULL, NULL, 8, 1, '{}', '2026-05-15 05:45:35.571633+00', NULL, 11, 1),
	('{"Multiattack. The pirate makes three attacks, using Scimitar or Pistol in any combination.","Scimitar. Melee Attack Roll: +10 , reach 5 ft. Hit: 16 ( 3d6 + 6 ) Slashing damage plus 7 ( 2d6 ) Poison damage, and the target suffers one of the following effects of the pirate’s choice:","Awestruck. The target has the Charmed condition until the start of the pirate’s next turn.","Poison. The target has the Poisoned condition until the start of the pirate’s next turn.","Pistol. Ranged Attack Roll: +10 , range 30/90 ft. Hit: 28 ( 4d10 + 6 ) Piercing damage."}', 'Neutral Good', 17, '{}', '2', 11, 5, 12, 6, '2026-05-15 05:45:35.571633+00', 'Construct', NULL, 15, 8, 2300, NULL, NULL, '5d10', 19, '1067802f-e7bb-416b-b8a6-2622c3918d78', '{"Poison; Charmed",Exhaustion,Paralyzed,Petrified,Poisoned,Prone}', '+4', 15, 18, 1, 'Common (can’t speak in bear form)', '{}', 'Ghoul', 2, '{}', '{}', '{"Darkvision 60 ft.","Passive Perception 10"}', 'Large', '{"Perception +5"}', '40 ft.', NULL, NULL, NULL, NULL, 16, 5, '{}', '2026-05-15 05:45:35.571633+00', NULL, 12, 1),
	('{"Multiattack. The treant makes two Slam attacks.","Slam. Melee Attack Roll: +10 , reach 5 ft. Hit: 16 ( 3d6 + 6 ) Bludgeoning damage.","Hail of Bark. Ranged Attack Roll: +10 , range 180 ft. Hit: 28 ( 4d10 + 6 ) Piercing damage.","Animate Trees (1/Day). The treant magically animates up to two trees it can see within 60 feet of itself. Each tree uses the Treant stat block, except it has Intelligence and Charisma scores of 1, it can’t speak, and it lacks this action. The tree takes its turn immediately after the treant on the same Initiative count, and it obeys the treant. A tree remains animate for 1 day or until it dies, the treant dies, or it is more than 120 feet from the treant. The tree then takes root if possible."}', 'Chaotic Evil', 10, '{}', '2', 3, 2, 21, 1, '2026-05-15 05:45:35.571633+00', 'Fiend', NULL, 14, 4, 50, NULL, 'Club', '4d6 + 4', 123, 'af32df9f-981a-49f4-80fb-350e474685c6', '{Fire,Necrotic,"Poison; Charmed",Exhaustion,Frightened,Paralyzed,Poisoned,Prone}', '+3', 10, 6, -1, 'Abyssal, Infernal; telepathy 60 ft.', '{}', 'Sphinx of Secrets', 2, '{"Shield (2/Day). The noble casts Shield in response to that spell’s trigger, using the same spellcasting ability as Spellcasting."}', '{}', '{"Darkvision 60 ft.","Passive Perception 12"}', 'Gargantuan', '{"Deception +14","Perception +11","Persuasion +21"}', '40 ft.', NULL, '30 ft.', NULL, NULL, 12, -1, '{"Aura of Authority. While in a 10-foot Emanation originating from the hobgoblin, the hobgoblin and its allies have Advantage on attack rolls and saving throws, provided the hobgoblin doesn’t have the Incapacitated condition."}', '2026-05-15 05:45:35.571633+00', NULL, 14, 7),
	('{"Multiattack. The dragon makes two Rend attacks.","Rend. Melee Attack Roll: +6 , reach 5 ft. Hit: 9 ( 1d10 + 4 ) Piercing damage.","Cold Breath (Recharge 5–6) . Constitution Saving Throw: DC 13, each creature in a 15-foot Cone . Failure: 18 ( 4d8 ) Cold damage. Success: Half damage.","Paralyzing Breath. Constitution Saving Throw: DC 13, each creature in a 15-foot Cone . First Failure: The target has the Incapacitated condition until the end of its next turn, when it repeats the save. Second Failure: The target has the Paralyzed condition, and it repeats the save at the end of each of its turns, ending the effect on itself on a success. After 1 minute, it succeeds automatically."}', 'Neutral', 14, '{}', '1', 11, -3, 12, 0, '2026-05-15 05:45:35.571633+00', 'Fiend', NULL, 8, 1, 13000, NULL, NULL, '7d8 + 7', 468, 'f32afabf-bf3a-4519-ad63-a372362bbb10', '{Cold}', '+3', 14, 10, 2, 'Abyssal; telepathy 60 ft. (works only with creatures that understand Abyssal)', '{}', 'Rust Monster', 2, '{}', '{}', '{"Truesight 120 ft.","Passive Perception 22"}', 'Medium', '{}', '5 ft.', NULL, NULL, NULL, NULL, 9, 4, '{"Pack Tactics. The hobgoblin has Advantage on an attack roll against a creature if at least one of the hobgoblin’s allies is within 5 feet of the creature and the ally doesn’t have the Incapacitated condition."}', '2026-05-15 05:45:35.571633+00', NULL, 16, 2),
	('{"Multiattack. The dragon makes three Rend attacks. It can replace two attacks with a use of Sleep Breath.","Rend. Melee Attack Roll: +7 , reach 10 ft. Hit: 15 ( 2d10 + 4 ) Slashing damage.","Fire Breath (Recharge 5–6) . Dexterity Saving Throw: DC 14, each creature in a 40-foot-long, 5-foot-wide Line . Failure: 38 ( 11d6 ) Fire damage. Success: Half damage.","Sleep Breath. Constitution Saving Throw: DC 14, each creature in a 30-foot Cone . Failure: The target has the Incapacitated condition until the end of its next turn, at which point it repeats the save. Second Failure: The target has the Unconscious condition for 1 minute. This effect ends for the target if it takes damage or a creature within 5 feet of it takes an action to wake it."}', 'Neutral', 20, '{"Weird Insight (Recharge 6). Wisdom Saving Throw: DC 14, one creature the nothic can see within 120 feet. Failure: The nothic magically learns one fact or secret about the target."}', '4', 8, 0, 14, 1, '2026-05-15 05:45:35.571633+00', 'Dragon', '(Lycanthrope)', 17, 2, 100, NULL, NULL, '5d8', 94, '177df7f9-7538-40ff-b3be-36a2ce0555e1', '{}', '+2', 12, 18, 0, 'Common, Goblin', '{}', 'Lizardfolk Sovereign', 4, '{}', '{}', '{"Darkvision 60 ft.","Passive Perception 14"}', 'Medium', '{"Perception +5","Stealth +5"}', '40 ft.', NULL, NULL, '20 ft. (hover)', NULL, 18, 1, '{"Astral Implosion. If the blob is reduced to 0 Hit Points, it implodes and ejects any creatures and objects engulfed by it into the Astral Sea. The blob itself vanishes, leaving behind a layer of slime on everything that was within 600 feet of it. In 1d20 years, the blob reconstitutes on a random world in the Material Plane.","Legendary Resistance (4/Day). If the blob fails a saving throw, it can choose to succeed instead.","Magic Resistance. The blob has Advantage on saving throws against spells and other magical effects."}', '2026-05-15 05:45:35.571633+00', NULL, 16, 0),
	('{"Multiattack. The jackalwere makes two Rend or Slam attacks.","Rend (Jackal or Hybrid Form Only). Melee Attack Roll: +4 , reach 5 ft. Hit: 5 ( 1d6 + 2 ) Piercing damage.","Slam (Human or Hybrid Form Only). Melee Attack Roll: +4 , reach 5 ft. Hit: 4 ( 1d4 + 2 ) Bludgeoning damage.","Sleep Gaze (Recharge 5–6). Wisdom Saving Throw: DC 10, one creature the jackalwere can see within 30 feet (Constructs and Undead succeed automatically). Failure: The target has the Unconscious condition for 10 minutes or until it takes damage or a creature within 5 feet of it takes an action to wake it. Success: The target is immune to this jackalwere’s Sleep Gaze for 24 hours."}', 'Neutral', 12, '{}', '11', 10, 3, 20, 5, '2026-05-15 05:45:35.571633+00', 'Aberration', '(Metallic)', 12, -1, 5900, NULL, 'Chain Mail', '1d8', 76, 'af60b7a6-7ca2-455c-9c74-5bda84eaf91d', '{Deafened}', '+2', 29, 12, 3, 'Abyssal', '{}', 'Roper', 3, '{}', '{Cold,Fire,Lightning}', '{"Passive Perception 15"}', 'Tiny', '{"Perception +10","Persuasion +19"}', '60 ft.', NULL, NULL, '30 ft. (hover)', NULL, 10, 4, '{}', '2026-05-15 05:45:35.571633+00', NULL, 14, 1),
	('{"Multiattack. The half-dragon makes two Claw attacks.","Claw. Melee Attack Roll: +7 , reach 10 ft. Hit: 6 ( 1d4 + 4 ) Slashing damage plus 7 ( 2d6 ) damage of the type chosen for the Draconic Origin trait.","Dragon’s Breath (Recharge 5–6). Dexterity Saving Throw: DC 14, each creature in a 30-foot Cone . Failure: 28 ( 8d6 ) damage of the type chosen for the Draconic Origin trait. Success: Half damage."}', 'Neutral', 15, '{}', '13', 12, -2, 18, 1, '2026-05-15 05:45:35.571633+00', 'Monstrosity', NULL, 18, 2, 1800, NULL, NULL, '9d8 + 9', 33, 'd7268e95-112c-4b2a-accb-28e866333620', '{Acid,"Poison; Poisoned"}', '+4', 13, 6, -2, 'Common', '{}', 'Death Dog', 2, '{}', '{}', '{"Blindsight 60 ft.","Passive Perception 8"}', 'Gargantuan', '{}', '5 ft.', NULL, '40 ft.', '40 ft. (hover)', NULL, 20, 6, '{"Shielded Mind. The couatl’s thoughts can’t be read by any means, and other creatures can communicate with it telepathically only if it allows them."}', '2026-05-15 05:45:35.571633+00', NULL, 14, 0),
	('{"Multiattack. The golem makes two Slam attacks.","Slam. Melee Attack Roll: +7 , reach 5 ft. Hit: 13 ( 2d8 + 4 ) Bludgeoning damage plus 4 ( 1d8 ) Lightning damage."}', 'Chaotic Evil', 18, '{}', '1/4', 16, -3, 12, 1, '2026-05-15 05:45:35.571633+00', 'Construct', NULL, 12, 3, 1800, NULL, NULL, '16d8 + 64', 310, '9c41fdc2-5ca9-4369-b700-379f0fbc8a8b', '{}', '+3', 14, 11, -2, 'Common, Goblin', '{"Legendary Action Uses: 3 (4 in Lair). Immediately after another creature’s turn, the dragon can expend a use to take one of the following actions. The dragon regains all expended uses at the start of each of its turns.","Pounce. The dragon moves up to half its Speed, and it makes one Rend attack.","Veil of Shadow. The dragon uses Shadow Stealth, and one creature of its choice that it can see within 10 feet of it takes 10 ( 3d6 ) Necrotic damage. The dragon can’t take this action again until the start of its next turn."}', 'Shadow Dragon', 3, '{}', '{}', '{"Darkvision 60 ft.","Passive Perception 12"}', 'Large', '{"Perception +11","Stealth +7"}', '40 ft.', NULL, '40 ft.', '50 ft. (hover)', NULL, 17, 4, '{"Detect Intelligence. The intellect devourer magically senses the location of any creature within 300 feet of itself that has an Intelligence score of 3 or higher, regardless of interposing barriers."}', '2026-05-15 05:45:35.571633+00', 'Fire', 10, 0),
	('{"Rend. Melee Attack Roll: +3 , reach 5 ft. Hit: 4 ( 1d6 + 1 ) Slashing damage.","Fetid Cloud (1/Day). Constitution Saving Throw: DC 11, each creature in a 10-foot Emanation originating from the dretch. Failure: The target has the Poisoned condition until the end of its next turn. While Poisoned, the creature can take either an action or a Bonus Action on its turn, not both, and it can’t take Reactions."}', 'Lawful Evil', 16, '{}', '9', 15, 0, 16, 3, '2026-05-15 05:45:35.571633+00', 'Elemental', '(Genie)', 10, 4, 1100, NULL, NULL, '9d8 + 18', 11, '4ad2d41b-1789-43e1-a1a8-4b82c1aa9211', '{Cold}', '+12', 10, 14, -1, 'None', '{}', 'Frost Giant', 2, '{}', '{}', '{"Darkvision 60 ft.","Passive Perception 17"}', 'Large', '{"Arcana +13","Insight +7","Perception +7","Stealth +6"}', '30 ft.', NULL, NULL, NULL, NULL, 12, 4, '{"Demonic Restoration. If the marilith dies outside the Abyss, its body dissolves into ichor, and it gains a new body instantly, reviving with all its Hit Points somewhere in the Abyss .","Magic Resistance. The marilith has Advantage on saving throws against spells and other magical effects.","Reactive. The marilith can take one Reaction on every turn of combat."}', '2026-05-15 05:45:35.571633+00', NULL, 13, 0),
	('{"Multiattack. The vampire makes two Claw attacks and uses Bite.","Claw. Melee Attack Roll: +6 , reach 5 ft. Hit: 8 ( 2d4 + 3 ) Slashing damage. If the target is a Medium or smaller creature, it has the Grappled condition (escape DC 13) from one of two claws.","Bite. Constitution Saving Throw: DC 14, one creature within 5 feet that is willing or that has the Grappled , Incapacitated , or Restrained condition. Failure: 5 ( 1d4 + 3 ) Piercing damage plus 10 ( 3d6 ) Necrotic damage. The target’s Hit Point maximum decreases by an amount equal to the Necrotic damage taken, and the vampire regains Hit Points equal to that amount."}', 'Unaligned', 18, '{}', '8', 10, 1, 16, 3, '2026-05-15 05:45:35.571633+00', 'Undead', NULL, 10, 3, 5900, NULL, NULL, '6d10 + 12', 22, '7d6c9981-2038-4a8d-9b7d-474232d1ac7e', '{Lightning}', '+12', 15, 10, 1, 'Common, Primordial', '{"Legendary Action Uses: 3. Immediately after another creature’s turn, the cataclysm can expend a use to take one of the following actions. The cataclysm regains all expended uses at the start of each of its turns.","Eruption. The cataclysm makes one Elemental Burst attack.","Rumbling Movement. The cataclysm moves up to its Speed, Fly Speed, or Swim Speed without provoking Opportunity Attacks . Each creature within 5 feet of the cataclysm as it moves is targeted once by the following effect. Constitution Saving Throw: DC 23. Failure: The target has the Prone condition. Failure or Success: The cataclysm can’t take this action again until the start of its next turn."}', 'Solar', 2, '{"Spell Reflection. Trigger: The spectator succeeds on a saving throw against a spell, or a spell’s attack roll misses it. Response—Dexterity Saving Throw: DC 12, one creature the spectator can see within 120 feet. Failure: 10 ( 3d6 ) Force damage."}', '{}', '{"Darkvision 60 ft.","Passive Perception 17"}', 'Tiny', '{"Medicine +4","Religion +2"}', '50 ft.', NULL, NULL, NULL, '30 ft.', 12, -1, '{"Magic Resistance. The slaad has Advantage on saving throws against spells and other magical effects.","Regeneration. The slaad regains 10 Hit Points at the start of each of its turns if it has at least 1 Hit Point."}', '2026-05-15 05:45:35.571633+00', NULL, 7, 0),
	('{"Multiattack. The gnoll makes two Abyssal Strike attacks.","Abyssal Strike. Melee or Ranged Attack Roll: +6 , reach 5 ft. or range 60 ft. Hit: 20 ( 5d6 + 3 ) Poison damage.","Hunger of Yeenoghu (Recharge 5–6). The gnoll conjures a 30-foot Cube of magical Darkness originating from a point it can see within 60 feet, which lasts for 1 minute or until the gnoll’s Concentration ends on it. This area is Difficult Terrain . Dexterity Saving Throw: DC 14, any creature that starts its turn in this area or enters it for the first time on a turn. Failure: 28 ( 8d6 ) Necrotic damage, and the gnoll or a creature of its choice it can see gains 10 Temporary Hit Points . Success: Half damage only."}', 'Neutral Evil', 17, '{}', '5', 11, 4, 16, 0, '2026-05-15 05:45:35.571633+00', 'Elemental', '(Demon)', 12, 1, 1800, NULL, NULL, '11d10 + 33', 45, '4fd11ecb-1628-44da-80e8-b36dbbec1eb4', '{Necrotic,"Poison; Charmed",Exhaustion,Frightened,Grappled,Paralyzed,Petrified,Poisoned,Prone,Restrained}', '+4', 10, 6, 0, 'Common', '{"Legendary Action Uses: 3 (4 in Lair). Immediately after another creature’s turn, the dragon can expend a use to take one of the following actions. The dragon regains all expended uses at the start of each of its turns.","Freezing Burst. Constitution Saving Throw: DC 14, each creature in a 30-foot-radius Sphere centered on a point the dragon can see within 120 feet. Failure: 7 ( 2d6 ) Cold damage, and the target’s Speed is 0 until the end of the target’s next turn. Failure or Success: The dragon can’t take this action again until the start of its next turn.","Frightful Presence. The dragon casts Fear , requiring no Material components and using Charisma as the spellcasting ability (spell save DC 14). The dragon can’t take this action again until the start of its next turn.","Pounce. The dragon moves up to half its Speed, and it makes one Rend attack."}', 'Death Slaad', 5, '{}', '{Bludgeoning,Piercing}', '{"Passive Perception 10"}', 'Medium', '{}', '40 ft.', NULL, NULL, NULL, NULL, 18, 4, '{"Fiendish Restoration. If the arcanaloth dies outside Gehenna, its body dissolves into ichor, and it gains a new body instantly and revives with all its Hit Points in Gehenna .","Magic Resistance. The arcanaloth has Advantage on saving throws against spells and other magical effects.","Soul Tome. The arcanaloth has a magic tome. While holding or carrying the tome, the arcanaloth can use its Banishing Claw action.","The tome has AC 17; HP 35; and Immunity to Necrotic, Poison, and Psychic damage. The tome regains all its Hit Points at the end of every turn, but it turns to dust if reduced to 0 Hit Points or when the arcanaloth dies. If the tome is destroyed, the arcanaloth can create a new one when it finishes a Short or Long Rest."}', '2026-05-15 05:45:35.571633+00', NULL, 11, 2),
	('{"Multiattack. The beholder uses Eye Rays three times.","Bite. Melee Attack Roll: +8 , reach 5 ft. Hit: 13 ( 3d6 + 3 ) Piercing damage.","Eye Rays. The beholder randomly shoots one of the following magical rays at a target it can see within 120 feet of itself (roll 1d10 ; reroll if the beholder has already used that ray during this turn):"}', 'Chaotic Neutral', 17, '{"Rally (1/Day). The pirate chooses up to three other creatures it can see within 30 feet. Until the start of the pirate’s next turn, the targets have Advantage on attack rolls and saving throws."}', '1/2', 14, -1, 17, 1, '2026-05-15 05:45:35.571633+00', 'Fiend', NULL, 10, 8, 1100, NULL, NULL, '6d4 + 6', 18, 'cbb01ab1-5e95-4ab0-a6bf-e3cff8f31aaf', '{Fire}', '+4', 18, 13, 1, 'Common, Gith', '{"Legendary Action Uses: 3 (4 in Lair). Immediately after another creature’s turn, the dragon can expend a use to take one of the following actions. The dragon regains all expended uses at the start of each of its turns.","Commanding Presence. The dragon uses Spellcasting to cast Command (level 2 version). The dragon can’t take this action again until the start of its next turn.","Fiery Rays. The dragon uses Spellcasting to cast Scorching Ray . The dragon can’t take this action again until the start of its next turn.","Pounce. The dragon moves up to half its Speed, and it makes one Rend attack."}', 'Displacer Beast', 3, '{}', '{}', '{"Blindsight 60 ft., Darkvision 120 ft.","Passive Perception 26"}', 'Large', '{"Perception +6","Religion +3"}', '30 ft.', NULL, '30 ft.', NULL, NULL, 12, -2, '{}', '2026-05-15 05:45:35.571633+00', NULL, 15, 1),
	('{"Multiattack. The hag makes two Claw attacks.","Claw. Melee Attack Roll: +7 , reach 5 ft. Hit: 13 ( 2d8 + 4 ) Slashing damage.","Nightmare Haunting (1/Day; Requires Soul Bag). While on the Ethereal Plane, the hag casts Dream , using the same spellcasting ability as Spellcasting. Only the hag can serve as the spell’s messenger, and the target must be a creature the hag can see on the Material Plane. The spell fails and is wasted if the target is under the effect of the Protection from Evil and Good spell or within a Magic Circle spell.","If the target takes damage from the Dream spell, the target’s Hit Point maximum decreases by an amount equal to that damage. If the spell kills the target, its soul is trapped in the hag’s soul bag, and the target can’t be raised from the dead until its soul is released.","Spellcasting. The hag casts one of the following spells, requiring no Material components and using Intelligence as the spellcasting ability (spell save DC 14):","At Will: Detect Magic , Etherealness , Magic Missile (level 4 version)","2/Day Each: Phantasmal Killer , Plane Shift (self only)"}', 'Neutral', 20, '{"War Cry (Recharge 5–6). The giant or one creature of its choice that can see or hear it gains 16 ( 2d10 + 5 ) Temporary Hit Points and has Advantage on attack rolls until the start of the giant’s next turn."}', '2', 10, 0, 12, 1, '2026-05-15 05:45:35.571633+00', 'Ooze', NULL, 14, 0, 1800, NULL, NULL, '10d12 + 40', 184, 'b254e138-d508-48e0-a9bb-4a7346953ab7', '{}', '+9', 13, 7, -4, 'Common, Draconic', '{}', 'Piercer', 4, '{}', '{}', '{"Blindsight 30 ft., Darkvision 120 ft.","Passive Perception 18"}', 'Medium', '{"Perception +14"}', '40 ft.', '20 ft.', NULL, '80 ft.', NULL, 16, -2, '{"Amphibious. The dragon can breathe air and water.","Legendary Resistance (3/Day, or 4/Day in Lair). If the dragon fails a saving throw, it can choose to succeed instead."}', '2026-05-15 05:45:35.571633+00', NULL, 12, 3),
	('{"Multiattack. The sphinx makes three Claw attacks.","Claw. Melee Attack Roll: +8 , reach 5 ft. Hit: 14 ( 3d6 + 4 ) Slashing damage.","Mind-Rending Roar (Recharge 5–6). Wisdom Saving Throw: DC 16, each enemy in a 300-foot Emanation originating from the sphinx. Failure: 35 ( 10d6 ) Psychic damage, and the target has the Incapacitated condition until the start of the sphinx’s next turn.","Spellcasting. The sphinx casts one of the following spells, requiring no Material components and using Intelligence as the spellcasting ability (spell save DC 16):","At Will: Detect Magic , Identify , Mage Hand , Minor Illusion , Prestidigitation","1/Day Each: Dispel Magic , Legend Lore , Locate Object , Plane Shift , Remove Curse , Tongues"}', 'Unaligned', 19, '{}', '17', 11, -1, 11, 1, '2026-05-15 05:45:35.571633+00', 'Fey', NULL, 15, -1, 450, NULL, NULL, '12d8 + 12', 9, '7737dc9d-87c1-47c3-bc9b-4abf73806b16', '{"Poison; Exhaustion",Grappled,Paralyzed,Petrified,Poisoned,Prone,Restrained,Unconscious}', '+0', 12, 13, -2, 'Giant', '{}', 'Scout', 3, '{}', '{}', '{"Darkvision 120 ft.","Passive Perception 10"}', 'Large', '{"Stealth +3"}', '40 ft.', NULL, NULL, '20 ft.', NULL, 17, 4, '{"Death Burst. The mephit explodes when it dies. Dexterity Saving Throw: DC 11, each creature in a 5-foot Emanation originating from the mephit. Failure: The target has the Restrained condition until the end of its next turn."}', '2026-05-15 05:45:35.571633+00', NULL, 19, 6),
	('{"Ritual Sickle. Melee Attack Roll: +3 , reach 5 ft. Hit: 3 ( 1d4 + 1 ) Slashing damage plus 1 Necrotic damage."}', 'Neutral', 16, '{}', '13', 9, 0, 25, 0, '2026-05-15 05:45:35.571633+00', 'Dragon', NULL, 10, 1, 2300, '13,000', NULL, '16d12 + 80', 33, '5763ba66-4ed2-451a-ae27-5f263b3b0b25', '{}', '+5', 14, 14, -1, 'Common, Draconic', '{"Legendary Action Uses: 3 (4 in Lair). Immediately after another creature’s turn, the dragon can expend a use to take one of the following actions. The dragon regains all expended uses at the start of each of its turns.","Banish. Charisma Saving Throw: DC 24, one creature the dragon can see within 120 feet. Failure: 24 ( 7d6 ) Force damage, and the target has the Incapacitated condition and is transported to a harmless demiplane until the start of the dragon’s next turn, at which point it reappears in an unoccupied space of the dragon’s choice within 120 feet of the dragon. Failure or Success: The dragon can’t take this action again until the start of its next turn.","Guiding Light. The dragon uses Spellcasting to cast Guiding Bolt (level 4 version).","Pounce. The dragon moves up to half its Speed, and it makes one Rend attack."}', 'Priest', 4, '{}', '{Bludgeoning,Piercing}', '{"Darkvision 60 ft.","Passive Perception 11"}', 'Small', '{}', '30 ft.', NULL, NULL, NULL, NULL, 10, 3, '{"Spider Climb. The ettercap can climb difficult surfaces, including along ceilings, without needing to make an ability check.","Web Walker. The ettercap ignores movement restrictions caused by webs, and the ettercap knows the location of any other creature in contact with the same web."}', '2026-05-15 05:45:35.571633+00', NULL, 11, 0),
	('{"Smother. Melee Attack Roll: +5 , reach 5 ft. Hit: 10 ( 2d6 + 3 ) Bludgeoning damage. If the target is a Medium or smaller creature, the rug can give it the Grappled condition (escape DC 13) instead of dealing damage. Until the grapple ends, the target has the Blinded and Restrained conditions, is suffocating , and takes 10 ( 2d6 + 3 ) Bludgeoning damage at the start of each of its turns. The rug can smother only one creature at a time.","While grappling the target, the rug can’t take this action, the rug halves the damage it takes (round down), and the target takes the same amount of damage."}', 'Chaotic Evil', 15, '{}', '2', 10, 2, 30, 3, '2026-05-15 05:45:35.571633+00', 'Fiend', NULL, 15, 0, 100, NULL, 'Daggers (6), Leather Armor', '7d8 + 7', 178, 'af0f5ec7-9af5-4b05-b446-3605e047a278', '{Necrotic,"Poison; Charmed",Exhaustion,Frightened,Grappled,Incapacitated,Paralyzed,Petrified,Poisoned,Prone,Restrained,Stunned}', '+2', 10, 10, -2, 'Common', '{}', 'Arch-hag', 2, '{}', '{}', '{"Blindsight 30 ft., Darkvision 120 ft.","Passive Perception 21"}', 'Large', '{}', '30 ft.', NULL, NULL, NULL, NULL, 19, -5, '{}', '2026-05-15 05:45:35.571633+00', NULL, 12, 11),
	('{}', 'Unaligned', 12, '{}', '11', 15, 0, 17, 2, '2026-05-15 05:45:35.571633+00', 'Dragon', NULL, 12, 11, 2900, NULL, NULL, '5d6 + 5', 135, 'd08d497b-334d-4e49-9ca6-dc4725508374', '{}', '+3', 13, 10, -2, 'Common, Deep Speech; telepathy 30 ft.', '{}', 'Pirate', 2, '{}', '{Cold}', '{"Truesight 120 ft.","Passive Perception 19"}', 'Gargantuan', '{"Perception +17","Stealth +7"}', '30 ft.', NULL, '30 ft. (snake form only)', '90 ft. (hover)', '90 ft.', 27, 1, '{"Death Burst. The mephit explodes when it dies. Constitution Saving Throw: DC 10, each creature in a 5-foot Emanation originating from the mephit. Failure: 5 ( 2d4 ) Cold damage. Success: Half damage."}', '2026-05-15 05:45:35.571633+00', NULL, 10, -4),
	('{"Multiattack. The devil makes one Beard attack and one Infernal Glaive attack.","Beard. Melee Attack Roll: +5 , reach 5 ft. Hit: 7 ( 1d8 + 3 ) Piercing damage, and the target has the Poisoned condition until the start of the devil’s next turn. Until this poison ends, the target can’t regain Hit Points.","Infernal Glaive. Melee Attack Roll: +5 , reach 10 ft. Hit: 8 ( 1d10 + 3 ) Slashing damage. If the target is a creature and doesn’t already have an infernal wound, it is subjected to the following effect. Constitution Saving Throw: DC 12. Failure: The target receives an infernal wound. While wounded, the target loses 5 ( 1d10 ) Hit Points at the start of each of its turns. The wound closes after 1 minute, after a spell restores Hit Points to the target, or after the target or a creature within 5 feet of it takes an action to stanch the wound, doing so by succeeding on a DC 12 Wisdom ( Medicine ) check."}', 'Unaligned', 12, '{}', '5', 2, 5, 14, 0, '2026-05-15 05:45:35.571633+00', 'Celestial or Fiend', NULL, 14, 0, 450, NULL, 'Pistol , Rapier', '6d4 + 6', 7, '9b1e7ce7-605c-4290-ae60-e93c5360bb3c', '{}', '+3', 22, 3, -2, 'Understands Common plus two other languages but can’t speak', '{"Legendary Action Uses: 3. Immediately after another creature’s turn, the unicorn can expend a use to take one of the following actions. The unicorn regains all expended uses at the start of each of its turns.","Charging Horn. The unicorn moves up to half its Speed without provoking Opportunity Attacks , and it makes one Radiant Horn attack.","Shimmering Shield. The unicorn targets itself or one creature it can see within 60 feet of itself. The target gains 10 ( 3d6 ) Temporary Hit Points , and its AC increases by 2 until the end of the unicorn’s next turn. The unicorn can’t take this action again until the start of its next turn."}', 'Goblin Hexer', 4, '{}', '{}', '{"Blindsight 60 ft.","Passive Perception 14"}', 'Medium', '{"History +8","Perception +11","Stealth +5"}', '30 ft.', NULL, NULL, '30 ft. (hover)', NULL, 14, -1, '{"Aversion to Fire. If the golem takes Fire damage, it has Disadvantage on attack rolls and ability checks until the end of its next turn.","Berserk. Whenever the golem starts its turn Bloodied , roll 1d6 . On a 6, the golem goes berserk. On each of its turns while berserk, the golem attacks the nearest creature it can see. If no creature is near enough to move to and attack, the golem attacks an object. Once the golem goes berserk, it remains so until it is destroyed or it is no longer Bloodied.","The golem’s creator, if within 60 feet of the berserk golem, can try to calm it by taking an action to make a DC 15 Charisma ( Persuasion ) check; the golem must be able to hear its creator. If this check succeeds, the golem ceases being berserk until the start of its next turn, at which point it resumes rolling for the Berserk trait again if it is still Bloodied.","Immutable Form. The golem can’t shape-shift .","Lightning Absorption . Whenever the golem is subjected to Lightning damage, it regains a number of Hit Points equal to the Lightning damage dealt.","Magic Resistance. The golem has Advantage on saving throws against spells and other magical effects."}', '2026-05-15 05:45:35.571633+00', NULL, 8, 6),
	('{"Multiattack. The familiar makes two Umbral Dagger attacks.","Umbral Dagger. Melee or Ranged Attack Roll: +5 , reach 5 ft. or range 20/60 ft. Hit: 5 ( 1d4 + 3 ) Piercing damage plus 7 ( 3d4 ) Necrotic damage. If the target is reduced to 0 Hit Points by this attack, the target becomes Stable but has the Poisoned condition for 1 hour. While it has the Poisoned condition, the target has the Paralyzed condition."}', 'Neutral Evil', 15, '{}', '3', 19, 1, 11, 6, '2026-05-15 05:45:35.571633+00', 'Dragon', NULL, 15, 2, 25, '15,000', 'Pistol , Rapier', '17d12 + 85', 65, '03ec8449-d27f-4e57-a7d9-31eba6ce09e9', '{Charmed}', '+16', 8, 5, -1, 'Abyssal, Common, Draconic', '{}', 'Carrion Crawler', 2, '{}', '{}', '{"Darkvision 60 ft.","Passive Perception 11"}', 'Medium', '{}', '30 ft.', NULL, NULL, '60 ft.', NULL, 18, -4, '{"Amphibious. The merrow can breathe air and water."}', '2026-05-15 05:45:35.571633+00', NULL, 14, 1),
	('{"Multiattack. The aboleth makes two Tentacle attacks and uses either Consume Memories or Dominate Mind if available.","Tentacle. Melee Attack Roll: +9 , reach 15 ft. Hit: 12 ( 2d6 + 5 ) Bludgeoning damage. If the target is a Large or smaller creature, it has the Grappled condition (escape DC 14) from one of four tentacles.","Consume Memories. Intelligence Saving Throw: DC 16, one creature within 30 feet that is Charmed or Grappled by the aboleth. Failure: 10 ( 3d6 ) Psychic damage. Success: Half damage. Failure or Success: The aboleth gains the target’s memories if the target is a Humanoid and is reduced to 0 Hit Points by this action.","Dominate Mind (2/Day). Wisdom Saving Throw: DC 16, one creature the aboleth can see within 30 feet. Failure: The target has the Charmed condition until the aboleth dies or is on a different plane of existence from the target. While Charmed, the target acts as an ally to the aboleth and is under its control while within 60 feet of it. In addition, the aboleth and the target can communicate telepathically with each other over any distance.","The target repeats the save whenever it takes damage as well as after every 24 hours it spends at least 1 mile away from the aboleth, ending the effect on itself on a success."}', 'Lawful Neutral', 13, '{}', '1/2', 13, 8, 12, 3, '2026-05-15 05:45:35.571633+00', 'Fiend', NULL, 12, 3, 25, NULL, NULL, '11d10 + 33', 49, '71b287eb-7612-4b5b-9a6f-1dbc9ab60225', '{}', '+5', 11, 16, -5, 'Undercommon', '{}', 'Stirge', 3, '{"Parry. Trigger: The noble is hit by a melee attack roll while holding a weapon. Response: The noble adds 2 to its AC against that attack, possibly causing it to miss."}', '{Cold,Lightning}', '{"Darkvision 60 ft.","Passive Perception 9"}', 'Medium', '{"Perception +7"}', '5 ft.', NULL, NULL, '60 ft.', NULL, 15, 5, '{"Living Shadow. While in Dim Light or Darkness , the dragon has Resistance to damage that isn’t Force, Psychic, or Radiant.","Sunlight Sensitivity. While in sunlight, the dragon has Disadvantage on ability checks and attack rolls."}', '2026-05-15 05:45:35.571633+00', NULL, 10, 0),
	('{"Multiattack. The hobgoblin makes two attacks, using Greatsword or Longbow in any combination.","Greatsword. Melee Attack Roll: +4 , reach 5 ft. Hit: 9 ( 2d6 + 2 ) Slashing damage plus 3 ( 1d6 ) Poison damage.","Longbow. Ranged Attack Roll: +4 , range 150/600 ft. Hit: 6 ( 1d8 + 2 ) Piercing damage plus 5 ( 2d4 ) Poison damage."}', 'Neutral', 19, '{"Leap. The bulette jumps up to 30 feet by spending 10 feet of movement."}', '2', 16, 8, 20, 7, '2026-05-15 05:45:35.571633+00', 'Monstrosity', NULL, 12, 3, 450, NULL, NULL, '18d8 + 72', 52, 'c5043688-4508-4d71-911f-66ff2f904bba', '{Charmed}', '+4', 13, 13, 0, 'None', '{}', 'Ghast Gravecaller', 2, '{"Parry. Trigger: The noble is hit by a melee attack roll while holding a weapon. Response: The noble adds 2 to its AC against that attack, possibly causing it to miss."}', '{Cold,Lightning}', '{"Passive Perception 12"}', 'Large', '{"Perception +1"}', '50 ft.', NULL, NULL, NULL, NULL, 19, 2, '{"Amphibious. The dragon can breathe air and water."}', '2026-05-15 05:45:35.571633+00', 'Fire', 10, 2),
	('{"Multiattack. The deva makes two Holy Mace attacks.","Holy Mace. Melee Attack Roll: +8 , reach 5 ft. Hit: 7 ( 1d6 + 4 ) Bludgeoning damage plus 18 ( 4d8 ) Radiant damage.","Spellcasting. The deva casts one of the following spells, requiring no Material components and using Charisma as the spellcasting ability (spell save DC 17):","At Will: Detect Evil and Good , Shapechange (Beast or Humanoid form only, no Temporary Hit Points gained from the spell, and no Concentration or Temporary Hit Points required to maintain the spell)","1/Day Each: Commune , Raise Dead"}', 'Chaotic Evil', 13, '{}', '1', 13, 2, 20, 3, '2026-05-15 05:45:35.571633+00', 'Elemental', '(Chromatic)', 8, -1, 2300, NULL, 'Daggers (3)', '18d12 + 90', 105, '12c3e946-4625-483e-b1aa-281d5ae9c4c2', '{Fire}', '+3', 22, 7, 1, 'Common, Goblin', '{}', 'Barbed Devil', 5, '{}', '{Bludgeoning,Piercing,Slashing}', '{"Blindsight 60 ft.","Passive Perception 7"}', 'Medium', '{"Stealth +4"}', '30 ft.', NULL, NULL, NULL, NULL, 16, -1, '{}', '2026-05-15 05:45:35.571633+00', NULL, 10, 6),
	('{"Pseudopod. Melee Attack Roll: +3 , reach 5 ft. Hit: 10 ( 2d8 + 1 ) Acid damage. Nonmagical armor worn by the target takes a -1 penalty to the AC it offers. The armor is destroyed if the penalty reduces its AC to 10. The penalty can be removed by casting the Mending spell on the armor."}', 'Unaligned', 13, '{}', '5', 10, -2, 20, 4, '2026-05-15 05:45:35.571633+00', 'Giant', NULL, 11, 2, 1800, NULL, NULL, '2d8 + 6', 11, 'd11cb898-cd6d-4c5c-8632-0a0febcc18bf', '{Fire,"Poison; Poisoned"}', '+9', 12, 12, 0, 'Common plus three other languages', '{}', 'Manes', 2, '{}', '{}', '{"Passive Perception 16"}', 'Medium or Small', '{}', '10 ft.', NULL, NULL, NULL, NULL, 17, 5, '{"Inscrutable. No magic can observe the sphinx remotely or detect its thoughts without its permission. Wisdom ( Insight ) checks made to ascertain its intentions or sincerity are made with Disadvantage.","Legendary Resistance (3/Day, or 4/Day in Lair). If the sphinx fails a saving throw, it can choose to succeed instead."}', '2026-05-15 05:45:35.571633+00', NULL, 22, 2),
	('{"Multiattack. The devil makes two Claw attacks and one Infernal Sting attack.","Claw. Melee Attack Roll: +8 , reach 10 ft. Hit: 13 ( 2d8 + 4 ) Slashing damage.","Infernal Sting. Melee Attack Roll: +8 , reach 10 ft. Hit: 15 ( 2d10 + 4 ) Piercing damage plus 18 ( 4d8 ) Poison damage, and the target has the Poisoned condition until the start of the devil’s next turn. While Poisoned, the target can’t regain Hit Points."}', 'Unaligned', 18, '{}', '0', 16, 0, 18, 1, '2026-05-15 05:45:35.571633+00', 'Monstrosity', '(Metallic)', 8, 1, 700, NULL, NULL, '3d8 + 3', 39, '2a1e3ae7-63a8-4cdf-ac67-c1c1d1326b60', '{}', '+7', 12, 7, 3, 'Common', '{"Legendary Action Uses: 3 (4 in Lair). Immediately after another creature’s turn, the kraken can expend a use to take one of the following actions. The kraken regains all expended uses at the start of each of its turns.","Storm Bolt. The kraken uses Lightning Strike.","Toxic Ink. Constitution Saving Throw: DC 23, each creature in a 15-foot Emanation originating from the kraken while it is underwater. Failure: The target has the Blinded and Poisoned conditions until the end of the kraken’s next turn. The kraken then moves up to its Speed. Failure or Success: The kraken can’t take this action again until the start of its next turn."}', 'Salamander', 2, '{"Shield (2/Day). The noble casts Shield in response to that spell’s trigger, using the same spellcasting ability as Spellcasting."}', '{"See Living Shadow"}', '{"Blindsight 30 ft., Darkvision 120 ft.","Passive Perception 13"}', 'Medium or Small', '{}', '30 ft.', NULL, '40 ft.', NULL, NULL, 19, 2, '{}', '2026-05-15 05:45:35.571633+00', NULL, 10, 7),
	('{"Multiattack. The death tyrant uses Eye Rays three times.","Bite. Melee Attack Roll: +9 , reach 5 feet. Hit: 13 ( 2d8 + 4 ) Piercing damage.","Eye Rays. The death tyrant randomly shoots one of the following magical rays at a target it can see within 120 feet of itself (roll 1d10 ; reroll if the death tyrant has already used that ray during this turn):"}', 'Neutral Evil', 17, '{"Moan. Wisdom Saving Throw: DC 13, each creature in a 60-foot Emanation originating from the cloaker. Failure: The target has the Frightened condition until the end of the cloaker’s next turn. Success: The target is immune to this cloaker’s Moan for the next 24 hours.","Phantasms (Recharge after a Short or Long Rest). The cloaker casts the Mirror Image spell, requiring no spell components and using Wisdom as the spellcasting ability. The spell ends early if the cloaker starts or ends its turn in Bright Light ."}', '13', 11, 9, 26, 2, '2026-05-15 05:45:35.571633+00', 'Humanoid', NULL, 8, 5, 50000, NULL, NULL, '16d10 + 64', 136, '28f0b021-8f24-4a9f-aaa0-7c658b928e4e', '{"Poison; Frightened",Poisoned}', '+2', 11, 6, 0, 'All; telepathy 120 ft.', '{}', 'Piercer', 2, '{"Feather Fall (1/Day). The aarakocra casts Feather Fall in response to that spell’s trigger, using the same spellcasting ability as Spellcasting."}', '{}', '{"Passive Perception 10"}', 'Medium', '{"Insight +7","Perception +12","Stealth +5"}', '5 ft.', NULL, NULL, '25 ft. (hover)', NULL, 14, -5, '{"Demonic Restoration. If the marilith dies outside the Abyss, its body dissolves into ichor, and it gains a new body instantly, reviving with all its Hit Points somewhere in the Abyss .","Magic Resistance. The marilith has Advantage on saving throws against spells and other magical effects.","Reactive. The marilith can take one Reaction on every turn of combat."}', '2026-05-15 05:45:35.571633+00', NULL, 15, 7),
	('{"Multiattack. The chimera makes one Ram attack, one Bite attack, and one Claw attack. It can replace the Claw attack with a use of Fire Breath if available.","Bite. Melee Attack Roll: +7 , reach 5 ft. Hit: 11 ( 2d6 + 4 ) Piercing damage, or 18 ( 4d6 + 4 ) Piercing damage if the chimera had Advantage on the attack roll.","Claw. Melee Attack Roll: +7 , reach 5 ft. Hit: 7 ( 1d6 + 4 ) Slashing damage.","Ram. Melee Attack Roll: +7 , reach 5 ft. Hit: 10 ( 1d12 + 4 ) Bludgeoning damage. If the target is a Medium or smaller creature, it has the Prone condition.","Fire Breath (Recharge 5–6). Dexterity Saving Throw: DC 15, each creature in a 15-foot Cone . Failure: 31 ( 7d8 ) Fire damage. Success: Half damage."}', 'Chaotic Evil', 12, '{}', '5', 15, 4, 15, 0, '2026-05-15 05:45:35.571633+00', 'Monstrosity', '(Yugoloth)', 14, 5, 450, NULL, 'Shortsword', '4d6', 84, 'd0830136-e068-4f22-82c0-70d410849933', '{Fire,"Poison; Charmed",Frightened,Poisoned}', '+6', 13, 12, -1, 'None', '{}', 'Blue Slaad', 6, '{}', '{}', '{"Blindsight 30 ft., Darkvision 120 ft.","Passive Perception 15"}', 'Small', '{}', '30 ft.', NULL, NULL, NULL, NULL, 23, 0, '{"Blight Seeds. When it finishes a Long Rest, the blight expels 1d6 seeds into unoccupied spaces on the ground within 30 feet of itself. After 24 hours, the seeds become creatures under the blight’s control. Roll 1d8 for each seed to determine the creature it becomes: on 1–4, Twig Blight ; on 5–6, Needle Blight ; on 7–8, Vine Blight ."}', '2026-05-15 05:45:35.571633+00', NULL, 6, 1),
	('{"Multiattack. The treant makes two Slam attacks.","Slam. Melee Attack Roll: +10 , reach 5 ft. Hit: 16 ( 3d6 + 6 ) Bludgeoning damage.","Hail of Bark. Ranged Attack Roll: +10 , range 180 ft. Hit: 28 ( 4d10 + 6 ) Piercing damage.","Animate Trees (1/Day). The treant magically animates up to two trees it can see within 60 feet of itself. Each tree uses the Treant stat block, except it has Intelligence and Charisma scores of 1, it can’t speak, and it lacks this action. The tree takes its turn immediately after the treant on the same Initiative count, and it obeys the treant. A tree remains animate for 1 day or until it dies, the treant dies, or it is more than 120 feet from the treant. The tree then takes root if possible."}', 'Unaligned', 17, '{}', '2', 9, 0, 20, 6, '2026-05-15 05:45:35.571633+00', 'Plant', NULL, 10, 1, 2300, NULL, NULL, '5d8', 133, 'a012dcab-3ef8-4b91-b135-62920bde1529', '{Lightning}', '+0', 16, 2, 1, 'None', '{}', 'Guardian Naga', 5, '{}', '{}', '{"Darkvision 60 ft.","Passive Perception 14"}', 'Huge', '{"Arcana +4","Perception +7"}', '30 ft.', NULL, NULL, '15 ft. (hover)', NULL, 21, 2, '{}', '2026-05-15 05:45:35.571633+00', NULL, 18, 0),
	('{"Multiattack. The scout makes two attacks, using Shortsword or Longbow in any combination.","Shortsword. Melee Attack Roll: +5 , reach 5 ft. Hit: 6 ( 1d6 + 3 ) Piercing damage, plus 10 ( 3d6 ) Piercing damage if the attack was made with Advantage.","Longbow. Ranged Attack Roll: +5 , range 150/600 ft. Hit: 7 ( 1d8 + 3 ) Piercing damage, plus 10 ( 3d6 ) Piercing damage if the attack was made with Advantage."}', 'Neutral', 7, '{"Nimble Escape. The goblin takes the Disengage or Hide action."}', '1/2', 6, 0, 16, 1, '2026-05-15 05:45:35.571633+00', 'Swarm of Medium Fiends', NULL, 18, 2, 450, NULL, NULL, '3d8 + 9', 148, '05a98470-05a3-40f1-bf4b-ed2eb91d6d42', '{}', '+2', 12, 12, 5, 'None', '{}', 'Colossus', 4, '{}', '{Necrotic}', '{"Blindsight 10 ft., Darkvision 60 ft.","Passive Perception 14"}', 'Small', '{"Perception +6","Persuasion +8"}', '30 ft.', NULL, NULL, NULL, NULL, 10, 1, '{}', '2026-05-15 05:45:35.571633+00', NULL, 15, 7),
	('{"Multiattack. The zombie uses Eye Rays twice.","Bite. Melee Attack Roll: +5 , reach 5 ft. Hit: 16 ( 4d6 + 2 ) Piercing damage.","Eye Rays. The zombie randomly shoots one of the following magical rays at a target it can see within 120 feet of itself (roll 1d4 ; reroll if the zombie has already used that ray during this turn):"}', 'Neutral Evil', 13, '{}', '3', 16, -2, 25, 2, '2026-05-15 05:45:35.571633+00', 'Giant', '(Demon)', 11, 2, 100, NULL, NULL, '5d8 + 15', 99, 'd6bd7366-01c6-41b7-82e7-67e81a324124', '{Charmed}', '+3', 14, 14, -2, 'Infernal; telepathy 120 ft.', '{}', 'Umber Hulk', 2, '{}', '{Cold,Fire,Necrotic,Psychic,Radiant}', '{"Blindsight 60 ft.","Passive Perception 6"}', 'Medium', '{"Arcana +13","Insight +7","Perception +7","Stealth +6"}', '50 ft.', NULL, NULL, '80 ft.', '40 ft.', 19, 1, '{"Acid Absorption. Whenever the golem is subjected to Acid damage, it takes no damage and instead regains a number of Hit Points equal to the Acid damage dealt.","Berserk. Whenever the golem starts its turn Bloodied , roll 1d6 . On a 6, the golem goes berserk. On each of its turns while berserk, the golem attacks the nearest creature it can see. If no creature is near enough to move to and attack, the golem attacks an object. Once the golem goes berserk, it continues to be berserk until it is destroyed or it is no longer Bloodied.","Immutable Form. The golem can’t shape-shift .","Magic Resistance. The golem has Advantage on saving throws against spells and other magical effects."}', '2026-05-15 05:45:35.571633+00', NULL, 12, 6),
	('{"Multiattack. The flameskull makes two Fire Ray attacks.","Fire Ray. Melee or Ranged Attack Roll: +5 , reach 5 ft. or range 60 ft. Hit: 13 ( 3d6 + 3 ) Fire damage.","Spellcasting. The flameskull casts one of the following spells, requiring no Somatic or Material components and using Intelligence as the spellcasting ability (spell save DC 13):","At Will: Mage Hand","2/Day: Magic Missile (level 2 version)","1/Day: Fireball"}', 'Chaotic Evil', 18, '{"Charm (Recharge 5–6). The vampire casts Charm Person , requiring no spell components and using Charisma as the spellcasting ability (spell save DC 17), and the duration is 24 hours. The Charmed target is a willing recipient of the vampire’s Bite, the damage of which doesn’t end the spell. When the spell ends, the target is unaware it was Charmed by the vampire.","Shape-Shift. If the vampire isn’t in sunlight or running water, it shape-shifts into a Tiny bat (Speed 5 ft., Fly Speed 30 ft.) or a Medium cloud of mist (Speed 5 ft., Fly Speed 20 ft. [hover]), or it returns to its vampire form. Anything it is wearing transforms with it.","While in bat form, the vampire can’t speak. Its game statistics, other than its size and Speed, are unchanged.","While in mist form, the vampire can’t take any actions, speak, or manipulate objects. It is weightless and can enter an enemy’s space and stop there. If air can pass through a space, the mist can do so, but it can’t pass through liquid. It has Resistance to all damage, except the damage it takes from sunlight."}', '1', 15, -1, 16, 1, '2026-05-15 05:45:35.571633+00', 'Dragon', NULL, 16, 1, 1100, '50,000', NULL, '6d8 + 6', 7, 'ea7e7050-8ad9-45cb-ab53-a389e134dbd5', '{"Poison; Charmed",Exhaustion,Frightened,Paralyzed,Petrified,Poisoned}', '+1', 12, 10, -1, 'Abyssal, Common, Infernal', '{}', 'Modron Pentadrone', 2, '{}', '{Bludgeoning,Piercing,Slashing}', '{"Truesight 120 ft.","Passive Perception 14"}', 'Medium', '{"Deception +5","Perception +7","Stealth +4"}', '40 ft.', NULL, '30 ft.', NULL, NULL, 30, 3, '{}', '2026-05-15 05:45:35.571633+00', NULL, 13, 3),
	('{"Ocean Spear. Melee or Ranged Attack Roll: +2 , reach 5 ft. or range 20/60 ft. Hit: 3 ( 1d6 ) Piercing damage plus 2 ( 1d4 ) Cold damage. If the target is a creature, its Speed decreases by 10 feet until the end of its next turn. Hit or Miss: The spear magically returns to the merfolk’s hand immediately after a ranged attack."}', 'Neutral Evil', 16, '{}', '1/4', 10, -1, 16, 5, '2026-05-15 05:45:35.571633+00', 'Plant', NULL, 10, -1, NULL, NULL, NULL, '20d8 + 40', 168, 'fbf9f753-092d-4da8-86ab-937675f4fbe9', '{}', '+8', 13, 6, 3, 'Primordial (Aquan, Auran)', '{}', 'Vrock', 4, '{}', '{}', '{"Darkvision 60 ft.","Passive Perception 10"}', 'Medium', '{"Insight +4","Perception +7","Stealth +3"}', '40 ft.', '30 ft.', NULL, NULL, NULL, 21, 0, '{}', '2026-05-15 05:45:35.571633+00', NULL, 11, 0),
	('{"Insectile Rapier. Melee Attack Roll: +4 , reach 5 ft. Hit: 6 ( 1d8 + 2 ) Piercing damage plus 2 ( 1d4 ) Poison damage."}', 'Lawful Evil', 22, '{}', '8', 11, 2, 10, 5, '2026-05-15 05:45:35.571633+00', 'Undead', '(Devil)', 11, 0, 1800, NULL, NULL, '10d8 + 10', 16, '9aa35ddd-08b6-426c-a900-22f2a58e15db', '{"Poison; Exhaustion",Poisoned}', '+7', 15, 1, -4, 'Common, Goblin', '{}', 'Gorgon', 2, '{}', '{}', '{"Darkvision 60 ft.","Passive Perception 15"}', 'Large', '{"Deception +5","Perception +4","Stealth +6"}', '30 ft.', NULL, '40 ft.', '60 ft.', NULL, 1, 3, '{"Magic Resistance. The pseudodragon has Advantage on saving throws against spells and other magical effects."}', '2026-05-15 05:45:35.571633+00', NULL, 10, 1),
	('{"Multiattack. The jackalwere makes two Rend or Slam attacks.","Rend (Jackal or Hybrid Form Only). Melee Attack Roll: +4 , reach 5 ft. Hit: 5 ( 1d6 + 2 ) Piercing damage.","Slam (Human or Hybrid Form Only). Melee Attack Roll: +4 , reach 5 ft. Hit: 4 ( 1d4 + 2 ) Bludgeoning damage.","Sleep Gaze (Recharge 5–6). Wisdom Saving Throw: DC 10, one creature the jackalwere can see within 30 feet (Constructs and Undead succeed automatically). Failure: The target has the Unconscious condition for 10 minutes or until it takes damage or a creature within 5 feet of it takes an action to wake it. Success: The target is immune to this jackalwere’s Sleep Gaze for 24 hours."}', 'Lawful Evil', 14, '{}', '3', 6, 3, 18, 5, '2026-05-15 05:45:35.571633+00', 'Dragon', NULL, 15, 7, 7200, NULL, NULL, '24d20 + 216', 170, '7cba1ea5-b716-4a6c-9e25-6318ec08a1b9', '{Cold,Fire}', '+0', 14, 5, -3, 'Otyugh; telepathy 120 ft. (doesn’t allow the receiving creature to respond telepathically)', '{}', 'Pixie', 3, '{}', '{}', '{"Passive Perception 10"}', 'Large', '{"Insight +6","Perception +6","Religion +4"}', '60 ft.', NULL, NULL, '80 ft.', NULL, 18, 4, '{}', '2026-05-15 05:45:35.571633+00', 'Fire', 14, 4),
	('{"Proboscis. Melee Attack Roll: +5 , reach 5 ft. Hit: 6 ( 1d6 + 3 ) Piercing damage, and the stirge attaches to the target. While attached, the stirge can’t make Proboscis attacks, and the target takes 5 ( 2d4 ) Necrotic damage at the start of each of the stirge’s turns.","The stirge can detach itself by spending 5 feet of its movement. The target or a creature within 5 feet of it can detach the stirge as an action."}', 'Chaotic Good', 14, '{}', '6', 17, 7, 10, 0, '2026-05-15 05:45:35.571633+00', 'Humanoid', NULL, 20, 4, 11500, NULL, NULL, '16d12 + 80', 11, '4360cdb2-e715-4756-ba4c-9f1cf2b8ae64', '{}', '+2', 12, 6, 0, 'Common plus one other language', '{"Legendary Action Uses: 3 (4 in Lair). Immediately after another creature’s turn, the dragon can expend a use to take one of the following actions. The dragon regains all expended uses at the start of each of its turns.","Mind Invasion. The dragon uses Spellcasting to cast Mind Spike (level 5 version).","Noxious Miasma. Constitution Saving Throw: DC 21, each creature in a 30-foot-radius Sphere centered on a point the dragon can see within 90 feet. Failure: 17 ( 5d6 ) Poison damage, and the target takes a -2 penalty to AC until the end of its next turn. Failure or Success: The dragon can’t take this action again until the start of its next turn.","Pounce. The dragon moves up to half its Speed, and it makes one Rend attack."}', 'Gray Slaad', 3, '{}', '{}', '{"Darkvision 60 ft.","Passive Perception 13"}', 'Medium', '{"Perception +4","Stealth +5"}', '30 ft.', NULL, NULL, '80 ft.', NULL, 11, 4, '{"Confer Fire Resistance. The nightmare can grant Resistance to Fire damage to a rider while it is on the nightmare.","Illumination. The nightmare sheds Bright Light in a 10-foot radius and Dim Light for an additional 10 feet."}', '2026-05-15 05:45:35.571633+00', NULL, 12, 1),
	('{"Multiattack. The cultist makes three attacks, using Dread Scythe or Deathly Ray in any combination.","Dread Scythe. Melee Attack Roll: +7 , reach 10 ft. Hit: 9 ( 1d10 + 4 ) Slashing damage plus 11 ( 2d10 ) Necrotic damage, and the target can’t regain Hit Points until the end of its next turn.","Deathly Ray. Ranged Attack Roll: +6 , range 120 ft. Hit: 22 ( 4d10 ) Necrotic damage.","Spellcasting. The cultist casts one of the following spells, using Wisdom as the spellcasting ability (spell save DC 14):","At Will: Speak with Dead , Thaumaturgy"}', 'Neutral Evil', 16, '{}', '6', 5, 1, 14, 5, '2026-05-15 05:45:35.571633+00', 'Swarm of Tiny Monstrosities', NULL, 10, 6, 25, NULL, NULL, '27d10 + 189', 65, 'd7f59591-fef0-493f-bbd0-a61a79af7848', '{Lightning}', '+8', 27, 16, 7, 'Common plus one other language', '{}', 'Dretch', 2, '{}', '{}', '{"Blindsight 30 ft., Darkvision 120 ft.","Passive Perception 17"}', 'Large', '{"Perception +9"}', '40 ft.', NULL, NULL, NULL, NULL, 17, -5, '{"Pack Tactics. The kobold has Advantage on an attack roll against a creature if at least one of the kobold’s allies is within 5 feet of the creature and the ally doesn’t have the Incapacitated condition.","Sunlight Sensitivity. While in sunlight, the kobold has Disadvantage on ability checks and attack rolls."}', '2026-05-15 05:45:35.571633+00', NULL, 10, 8),
	('{"Scimitar. Melee Attack Roll: +3 , reach 5 ft. Hit: 4 ( 1d6 + 1 ) Slashing damage.","Light Crossbow. Ranged Attack Roll: +3 , range 80/320 ft. Hit: 5 ( 1d8 + 1 ) Piercing damage."}', 'Lawful Neutral', 12, '{}', '2', 11, 5, 12, -1, '2026-05-15 05:45:35.571633+00', 'Plant', NULL, 15, 3, 50, NULL, NULL, '12d8', 66, '4e088444-9053-46a0-950f-fd03e5337b6e', '{}', '+3', 18, 6, 6, 'Common, Draconic', '{}', 'Myconid Sprout', 2, '{}', '{}', '{"Blindsight 30 ft., Darkvision 120 ft.","Passive Perception 18"}', 'Large', '{"Arcana +5","Perception +3"}', '30 ft.', '20 ft.', NULL, NULL, NULL, 16, 4, '{"Spider Climb. The drider can climb difficult surfaces, including along ceilings, without needing to make an ability check.","Sunlight Sensitivity. While in sunlight, the drider has Disadvantage on ability checks and attack rolls.","Web Walker. The drider ignores movement restrictions caused by webs, and the drider knows the location of any other creature in contact with the same web."}', '2026-05-15 05:45:35.571633+00', NULL, 10, 2),
	('{"Multiattack. The devil makes three attacks, using Searing Fork or Hurl Flame in any combination. It can replace one attack with a use of Infernal Tail.","Searing Fork. Melee Attack Roll: +10 , reach 10 ft. Hit: 15 ( 2d8 + 6 ) Piercing damage plus 9 ( 2d8 ) Fire damage.","Hurl Flame. Ranged Attack Roll: +8 , range 150 ft. Hit: 26 ( 5d8 + 4 ) Fire damage. If the target is a flammable object that isn’t being worn or carried, it starts burning .","Infernal Tail. Dexterity Saving Throw: DC 17, one creature the devil can see within 10 feet. Failure: 10 ( 1d8 + 6 ) Necrotic damage, and the target receives an infernal wound if it doesn’t have one. While wounded, the target loses 10 ( 3d6 ) Hit Points at the start of each of its turns. The wound closes after 1 minute, after a spell restores Hit Points to the target, or after the target or a creature within 5 feet of it takes an action to stanch the wound, doing so by succeeding on a DC 17 Wisdom ( Medicine ) check."}', 'Neutral', 19, '{"Shape-Shift. The doppelganger shape-shifts into a Medium or Small Humanoid, or it returns to its true form. Its game statistics, other than its size, are the same in each form. Any equipment it is wearing or carrying isn’t transformed."}', '17', 1, -5, 19, 2, '2026-05-15 05:45:35.571633+00', 'Elemental', NULL, 14, 6, 100, NULL, NULL, '14d10 + 14', 170, '064d537e-b8e7-41d9-80dd-404757f3cc65', '{Petrified}', '+1', 28, 13, -4, 'Common plus one other language', '{}', 'Yeti', 7, '{}', '{}', '{"Darkvision 120 ft.","Passive Perception 11"}', 'Large', '{}', '40 ft.', NULL, NULL, '30 ft. (hover)', NULL, 17, 8, '{"Elemental Restoration. If the efreeti dies outside the Elemental Plane of Fire, its body dissolves into ash, and it gains a new body in 1d4 days, reviving with all its Hit Points somewhere on the Plane of Fire.","Magic Resistance. The efreeti has Advantage on saving throws against spells and other magical effects.","Wishes. The efreeti has a 30 percent chance of knowing the Wish spell. If the efreeti knows it, the efreeti can cast it only on behalf of a non-genie creature who communicates a wish in a way the efreeti can understand. If the efreeti casts the spell for the creature, the efreeti suffers none of the spell’s stress. Once the efreeti has cast it three times, the efreeti can’t do so again for 365 days."}', '2026-05-15 05:45:35.571633+00', NULL, 14, 0),
	('{"Life Drain. Melee Attack Roll: +6 , reach 5 ft. Hit: 21 ( 4d8 + 3 ) Necrotic damage. If the target is a creature, its Hit Point maximum decreases by an amount equal to the damage taken.","Create Specter. The wraith targets a Humanoid corpse within 10 feet of itself that has been dead for no longer than 1 minute. The target’s spirit rises as a Specter in the space of its corpse or in the nearest unoccupied space. The specter is under the wraith’s control. The wraith can have no more than seven specters under its control at a time."}', 'Neutral Evil', 14, '{"Cunning Action. The spy takes the Dash , Disengage , or Hide action."}', '1', 25, -2, 16, 5, '2026-05-15 05:45:35.571633+00', 'Swarm of Medium Fiends', '(Chromatic)', 15, 1, 50, NULL, 'Flinger. Ranged Attack Roll: +4 , range 120 ft. Hit: 6 ( 1d8 + 2 ) Force damage.', '9d10 + 36', 11, '257b3e58-427f-4979-9cd2-b31ec28b7e42', '{}', '+5', 14, 6, -1, 'Infernal; telepathy 120 ft.', '{}', 'Darkmantle', 2, '{"Hellish Rebuke. The cultist casts Hellish Rebuke in response to that spell’s trigger, using the same spellcasting ability as Spellcasting."}', '{Cold,Fire,Lightning}', '{"Darkvision 60 ft.","Passive Perception 14"}', 'Medium', '{}', '20 ft.', NULL, NULL, NULL, '40 ft.', 10, 1, '{"Incorporeal Movement. The empyrean can move through other creatures and objects as if they were Difficult Terrain . It takes 5 ( 1d10 ) Force damage if it ends its turn inside an object.","Magic Resistance. The empyrean has Advantage on saving throws against spells and other magical effects."}', '2026-05-15 05:45:35.571633+00', NULL, 11, 0),
	('{"Claw. Melee Attack Roll: +2 , reach 5 ft. Hit: 2 ( 1d4 ) Slashing damage plus 2 ( 1d4 ) Fire damage.","Steam Breath (Recharge 6). Constitution Saving Throw: DC 10, each creature in a 15-foot Cone . Failure: 5 ( 2d4 ) Fire damage, and the target’s Speed decreases by 10 feet until the end of the mephit’s next turn. Success: Half damage only. Failure or Success: Being underwater doesn’t grant Resistance to this Fire damage."}', 'Neutral Evil', 17, '{"Hasten (Recharge 5–6). The golem takes the Dash and Disengage actions."}', '4', 5, 0, 16, -1, '2026-05-15 05:45:35.571633+00', 'Aberration', '(Demon)', 13, 2, 13000, NULL, 'Pistol , Scimitar , Studded Leather Armor', '8d8 + 16', 45, '63f1a955-a213-4b5b-ab1b-15491e65e9c9', '{Cold}', '+4', 13, 10, 0, 'Abyssal, Common, Gnoll', '{}', 'Larva', 3, '{}', '{}', '{"Darkvision 120 ft.","Passive Perception 11"}', 'Large', '{"Stealth +4"}', '30 ft.', NULL, NULL, '60 ft.', NULL, 17, 4, '{"Detect Life. The banshee magically senses the direction of creatures up to 1 mile away that aren’t Constructs or Undead.","Incorporeal Movement. The banshee can move through other creatures and objects as if they were Difficult Terrain . It takes 5 ( 1d10 ) Force damage if it ends its turn inside an object."}', '2026-05-15 05:45:35.571633+00', NULL, 11, -1),
	('{"Slam. Melee Attack Roll: +2 , reach 5 ft. Hit: 4 ( 1d8 ) Bludgeoning damage plus 3 ( 1d6 ) Poison damage.","Pacifying Spores (1/Day). Constitution Saving Throw: DC 11, one creature the myconid can see within 10 feet. Failure: The target has the Stunned condition and repeats the save at the end of each of its turns, ending the effect on itself on a success. After 1 minute, it succeeds automatically.","Rapport Spores. The myconid expels spores in a 30-foot Emanation originating from itself. Creatures in that area with an Intelligence score of 2 or higher that aren’t Constructs, Elementals, or Undead gain telepathy with a range of 30 feet for 1 hour."}', 'Lawful Evil', 19, '{}', '4', 11, 5, 18, 1, '2026-05-15 05:45:35.571633+00', 'Aberration', NULL, 9, 2, 1100, NULL, NULL, '6d8 + 6', 84, 'd7178941-7d30-4b6f-8f02-c09605b427b4', '{Fire,"Poison; Poisoned"}', '+5', 10, 2, 0, 'None', '{}', 'Copper Dragon Wyrmling', 3, '{}', '{}', '{"Darkvision 60 ft.","Passive Perception 11"}', 'Small', '{"Deception +5","Perception +4","Stealth +3"}', '30 ft.', NULL, NULL, NULL, NULL, 11, 7, '{}', '2026-05-15 05:45:35.571633+00', NULL, 14, 8),
	('{"Multiattack. The devil makes two Chain attacks and uses Conjure Infernal Chain.","Chain. Melee Attack Roll: +7 , reach 10 ft. Hit: 11 ( 2d6 + 4 ) Slashing damage. If the target is a Large or smaller creature, it has the Grappled condition (escape DC 14) from one of two chains, and it has the Restrained condition until the grapple ends.","Conjure Infernal Chain. The devil conjures a fiery chain to bind a creature. Dexterity Saving Throw: DC 15, one creature the devil can see within 60 feet. Failure: 9 ( 2d4 + 4 ) Fire damage, and the target has the Restrained condition until the end of the devil’s next turn, at which point the chain disappears. If the target is Large or smaller, the devil moves the target up to 30 feet straight toward itself. Success: The chain disappears."}', 'Neutral', 12, '{}', '4', 10, -3, 16, 1, '2026-05-15 05:45:35.571633+00', 'Undead', NULL, 14, 6, 15000, NULL, NULL, '10d8 + 20', 481, 'bbc2d68f-6987-41f0-ada1-577e02cca151', '{Necrotic,"Poison; Blinded",Charmed,Deafened,Frightened,Poisoned}', '+2', 12, 16, -4, 'Abyssal; telepathy 120 ft.', '{}', 'Lemure', 3, '{}', '{}', '{"Darkvision 120 ft. (unimpeded by magical Darkness )","Passive Perception 12"}', 'Medium or Small', '{"Arcana +4","History +4","Religion +4"}', '40 ft.', NULL, '40 ft.', NULL, NULL, 10, -2, '{}', '2026-05-15 05:45:35.571633+00', NULL, 22, -1),
	('{"Dagger. Melee or Ranged Attack Roll: +4 , reach 5 ft. or range 20/60 ft. Hit: 4 ( 1d4 + 2 ) Piercing damage."}', 'Unaligned', 18, '{}', '21', 10, 2, 12, 2, '2026-05-15 05:45:35.571633+00', 'Aberration', NULL, 20, 0, 2300, NULL, NULL, '10d12 + 50', 136, 'a3c4870b-ecb7-4843-8d44-9ab19663ce1c', '{Necrotic}', '+1', 10, 8, -4, 'None', '{}', 'Death Slaad', 3, '{}', '{Necrotic}', '{"Darkvision 120 ft.","Passive Perception 13"}', 'Large', '{}', '10 ft.', NULL, NULL, '40 ft.', NULL, 6, 0, '{"Divine Awareness. The planetar knows if it hears a lie.","Exalted Restoration. If the planetar dies outside Mount Celestia, its body disappears, and it gains a new body instantly, reviving with all its Hit Points somewhere in Mount Celestia .","Magic Resistance. The planetar has Advantage on saving throws against spells and other magical effects."}', '2026-05-15 05:45:35.571633+00', NULL, 14, 5),
	('{"Bite. Melee Attack Roll: +5 , reach 5 ft. Hit: 10 ( 2d6 + 3 ) Piercing damage plus 7 ( 2d6 ) Poison damage."}', 'Lawful Good', 12, '{}', '0', 8, -4, 25, 2, '2026-05-15 05:45:35.571633+00', 'Fiend', NULL, 17, 2, 1800, NULL, NULL, '13d10 + 52', 27, '0ecc3c99-8f56-48ef-8f5c-35b2e010d563', '{}', '+0', 20, 14, 1, 'Draconic, Primordial (Terran)', '{}', 'Sphinx of Valor', 2, '{}', '{}', '{"Passive Perception 14"}', 'Large', '{"Arcana +6","Perception +8"}', '10 ft.', NULL, NULL, NULL, NULL, 1, 3, '{"Disintegration. If the modron dies, it disintegrates into dust, leaving behind anything it was wearing or carrying."}', '2026-05-15 05:45:35.571633+00', NULL, 17, 7),
	('{"Petrifying Bite. Melee Attack Roll: +3 , reach 5 ft. Hit: 3 ( 1d4 + 1 ) Piercing damage. If the target is a creature, it is subjected to the following effect. Constitution Saving Throw: DC 11. First Failure: The target has the Restrained condition. The target repeats the save at the end of its next turn if it is still Restrained, ending the effect on itself on a success. Second Failure: The target has the Petrified condition, instead of the Restrained condition, for 24 hours."}', 'Neutral Evil', 13, '{}', '22', 8, 4, 15, 1, '2026-05-15 05:45:35.571633+00', 'Humanoid', NULL, 11, 2, 100, NULL, NULL, '6d4 + 6', 175, '45966eec-736f-4a13-9ad7-e1700a526f8c', '{}', '+6', 28, 17, 0, 'Abyssal, Common, Draconic', '{}', 'Unicorn', 2, '{}', '{}', '{"Darkvision 90 ft. (unimpeded by magical Darkness )","Passive Perception 17"}', 'Large', '{"Perception +2","Stealth +3"}', '60 ft.', NULL, NULL, NULL, '40 ft.', 6, 3, '{"Astral Implosion. If the blob is reduced to 0 Hit Points, it implodes and ejects any creatures and objects engulfed by it into the Astral Sea. The blob itself vanishes, leaving behind a layer of slime on everything that was within 600 feet of it. In 1d20 years, the blob reconstitutes on a random world in the Material Plane.","Legendary Resistance (4/Day). If the blob fails a saving throw, it can choose to succeed instead.","Magic Resistance. The blob has Advantage on saving throws against spells and other magical effects."}', '2026-05-15 05:45:35.571633+00', NULL, 13, 0),
	('{"Multiattack. The devil makes one Claws attack and one Tail attack, or it makes two Hurl Flame attacks.","Claws. Melee Attack Roll: +6 , reach 5 ft. Hit: 10 ( 2d6 + 3 ) Piercing damage. If the target is a Large or smaller creature, it has the Grappled condition (escape DC 13) from both claws.","Tail. Melee Attack Roll: +6 , reach 10 ft. Hit: 14 ( 2d10 + 3 ) Slashing damage.","Hurl Flame. Ranged Attack Roll: +5 , range 150 ft. Hit: 17 ( 5d6 ) Fire damage. If the target is a flammable object that isn’t being worn or carried, it starts burning ."}', 'Neutral', 13, '{}', '1/2', 14, 7, 10, 0, '2026-05-15 05:45:35.571633+00', 'Construct', '(Goblinoid)', 12, -1, 200, NULL, NULL, '7d8 + 21', 178, 'c80b47ab-befc-4e96-b2d6-bdb88e4a63c0', '{}', '+2', 20, 3, 2, 'Deep Speech, Undercommon; telepathy 120 ft.', '{}', 'Mezzoloth', 3, '{}', '{Psychic}', '{"Blindsight 30 ft., Darkvision 120 ft.","Passive Perception 13"}', 'Large', '{"Perception +14","Stealth +6"}', '40 ft.', NULL, NULL, NULL, NULL, 16, 10, '{"Hellish Restoration. If the swarm dies in the Nine Hells , it revives with all its Hit Points in 1d10 days unless it is killed by a creature under the effects of a Bless spell or its remains are sprinkled with Holy Water .","Swarm. The swarm can occupy another creature’s space and vice versa, and the swarm can move through an opening large enough for a Medium creature. The swarm can’t regain Hit Points or gain Temporary Hit Points ."}', '2026-05-15 05:45:35.571633+00', NULL, 10, 0),
	('{"Multiattack. The familiar makes two Umbral Dagger attacks.","Umbral Dagger. Melee or Ranged Attack Roll: +5 , reach 5 ft. or range 20/60 ft. Hit: 5 ( 1d4 + 3 ) Piercing damage plus 7 ( 3d4 ) Necrotic damage. If the target is reduced to 0 Hit Points by this attack, the target becomes Stable but has the Poisoned condition for 1 hour. While it has the Poisoned condition, the target has the Paralyzed condition."}', 'Lawful Evil', 20, '{}', '2', 18, 4, 18, 3, '2026-05-15 05:45:35.571633+00', 'Dragon', NULL, 12, 2, 200, '41,000', NULL, '13d10 + 39', 76, '1b29b39b-7f8d-4e00-90cc-5d1b4b3538ca', '{"Acid; Prone"}', '+3', 5, 13, -4, 'Common', '{}', 'Vampire', 7, '{}', '{}', '{"Darkvision 60 ft.","Passive Perception 15"}', 'Large', '{"Stealth +3"}', '40 ft.', NULL, NULL, NULL, NULL, 12, 3, '{"Magic Resistance. The mind flayer has Advantage on saving throws against spells and other magical effects."}', '2026-05-15 05:45:35.571633+00', NULL, 10, -1),
	('{"Multiattack. The dragon makes two Rend attacks.","Rend. Melee Attack Roll: +4 , reach 5 ft. Hit: 7 ( 1d10 + 2 ) Slashing damage plus 3 ( 1d6 ) Poison damage.","Poison Breath (Recharge 5–6). Constitution Saving Throw: DC 11, each creature in a 15-foot Cone . Failure: 21 ( 6d6 ) Poison damage. Success: Half damage."}', 'Chaotic Evil', 16, '{}', '1/2', 18, -1, 10, 3, '2026-05-15 05:45:35.571633+00', 'Plant', '(Beholder)', 1, 8, 450, NULL, NULL, '10d10 + 30', 45, 'c780c5a4-c68d-44e8-84f9-4a4d1f3846cd', '{}', '+10', 11, 3, 4, 'Common', '{}', 'Blob of Annihilation', 3, '{}', '{}', '{"Passive Perception 13"}', 'Gargantuan', '{}', '10 ft.', NULL, NULL, NULL, NULL, 21, 2, '{"Death Burst. The magmin explodes when it dies. Dexterity Saving Throw: DC 11, each creature in a 10-foot Emanation originating from the magmin. Failure : 7 ( 2d6 ) Fire damage. Success: Half damage."}', '2026-05-15 05:45:35.571633+00', NULL, 13, 1),
	('{"Shortsword. Melee Attack Roll: +4 , reach 5 ft. Hit: 5 ( 1d6 + 2 ) Piercing damage plus 7 ( 2d6 ) Poison damage.","Hand Crossbow. Ranged Attack Roll: +4 , range 30/120 ft. Hit: 5 ( 1d6 + 2 ) Piercing damage plus 7 ( 2d6 ) Poison damage."}', 'Lawful Evil', 14, '{}', '10', 10, 8, 16, 0, '2026-05-15 05:45:35.571633+00', 'Fiend', NULL, 14, 1, 200, NULL, NULL, '24d20 + 216', 7, '6be79019-02bf-49d7-80f8-e268846b8a02', '{Poison,"Radiant; Charmed",Exhaustion,Frightened,Poisoned}', '+18', 28, 18, 0, 'Understands Common but can’t speak', '{}', 'Manes Vaporspawn', 3, '{"Psionic Defense (3/Day). The quaggoth casts Feather Fall or Shield in response to the spell’s trigger, requiring no spell components and using the same spellcasting ability as Spellcasting."}', '{Acid,Cold,Fire,Lightning,Thunder}', '{"Passive Perception 16"}', 'Large', '{"Perception +5","Stealth +7"}', '40 ft.', NULL, NULL, '60 ft.', NULL, 16, -5, '{"Flame Aura. At the end of each of the gorgon’s turns, each creature in a 5-foot Emanation originating from the gorgon takes 13 ( 3d8 ) Fire damage.","Illumination. The gorgon sheds Bright Light in a 10-foot radius and Dim Light for an additional 10 feet."}', '2026-05-15 05:45:35.571633+00', NULL, 14, 1),
	('{"Multiattack. The rakshasa makes three Cursed Touch attacks.","Cursed Touch. Melee Attack Roll: +10 , reach 5 ft. Hit: 12 ( 2d6 + 5 ) Slashing damage plus 19 ( 3d12 ) Necrotic damage. If the target is a creature, it is cursed . While cursed, the target gains no benefit from finishing a Short or Long Rest.","Baleful Command (Recharge 5–6). Wisdom Saving Throw: DC 18, each enemy in a 30-foot Emanation originating from the rakshasa. Failure: 28 ( 8d6 ) Psychic damage, and the target has the Frightened and Incapacitated conditions until the start of the rakshasa’s next turn.","Spellcasting. The rakshasa casts one of the following spells, requiring no Material components and using Charisma as the spellcasting ability (spell save DC 18):","At Will: Detect Magic , Detect Thoughts , Disguise Self , Mage Hand , Minor Illusion","1/Day Each: Fly , Invisibility , Major Image , Plane Shift"}', 'Neutral Evil', 17, '{}', '6', 16, -1, 12, 3, '2026-05-15 05:45:35.571633+00', 'Dragon', NULL, 16, 2, 50, NULL, 'Shortbow , Shortsword', '72d4', 136, '6514776f-8984-4315-9792-494a86536bb0', '{Cold}', '+5', 14, 14, 0, 'Primordial (Ignan)', '{}', 'Guard Captain', 2, '{}', '{"See Living Shadow"}', '{"Darkvision 120 ft.","Passive Perception 13"}', 'Medium or Small', '{}', '30 ft.', NULL, NULL, NULL, NULL, 16, 1, '{"Ice Walk. The dragon can move across and climb icy surfaces without needing to make an ability check. Additionally, Difficult Terrain composed of ice or snow doesn’t cost it extra movement.","Legendary Resistance (3/Day, or 4/Day in Lair). If the dragon fails a saving throw, it can choose to succeed instead."}', '2026-05-15 05:45:35.571633+00', NULL, 10, 3),
	('{"Multiattack. The guard makes two attacks, using Javelin or Longsword in any combination.","Javelin. Melee or Ranged Attack Roll: +6 , reach 5 ft. or range 30/120 ft. Hit: 14 ( 3d6 + 4 ) Piercing damage.","Longsword. Melee Attack Roll: +6 , reach 5 ft. Hit: 15 ( 2d10 + 4 ) Slashing damage."}', 'Chaotic Evil', 16, '{}', '12', 8, -5, 16, 4, '2026-05-15 05:45:35.571633+00', 'Monstrosity', NULL, 9, 2, 700, NULL, NULL, '4d6', 60, 'ca0d7463-2eb3-4c15-8586-8507d2d68bb5', '{}', '+3', 17, 16, -2, 'Celestial, Common', '{}', 'Sahuagin Priest', 4, '{}', '{}', '{"Blindsight 30 ft., Darkvision 60 ft.","Passive Perception 8"}', 'Medium or Small', '{"Perception +17","Stealth +7"}', '5 ft.', NULL, NULL, NULL, NULL, 16, 2, '{"Amphibious. The kuo-toa can breathe air and water.","Sunlight Sensitivity. While in sunlight, the kuo-toa has Disadvantage on ability checks and attack rolls."}', '2026-05-15 05:45:35.571633+00', NULL, 16, 6),
	('{"Multiattack. The mind flayer makes three Arcane Tentacles attacks.","Arcane Tentacles. Melee or Ranged Attack Roll: +9 , reach 5 ft. or range 120 ft. Hit: 27 ( 4d10 + 5 ) Psychic damage, and the mind flayer can teleport the target up to 30 feet to an unoccupied space the mind flayer can see on a surface or liquid large enough to support the target. If this damage reduces the target to 0 Hit Points, the mind flayer kills it and magically devours its brain.","Mind Burst (Recharge 5–6). Intelligence Saving Throw: DC 17, each creature in a 40-foot Emanation originating from the mind flayer. Failure: 41 ( 8d8 + 5 ) Psychic damage, and the target has the Stunned condition until the end of the mind flayer’s next turn. Success: Half damage only.","Spellcasting. The mind flayer casts one of the following spells, requiring no spell components and using Intelligence as the spellcasting ability (spell save DC 17):","At Will: Detect Magic , Detect Thoughts , Disguise Self , Mage Hand (the hand is Invisible )","1/Day Each: Clairvoyance , Dimension Door , Fireball (level 5 version), Lightning Bolt (level 5 version), Plane Shift (self only), Sending"}', 'Neutral Evil', 15, '{}', '4', 12, 0, 14, 4, '2026-05-15 05:45:35.571633+00', 'Fiend', NULL, 16, 2, 450, NULL, NULL, '3d8 + 3', 243, '76119876-e27b-4fe9-a861-b13fa7e62a7b', '{}', '+2', 20, 10, 6, 'Giant', '{}', 'Pegasus', 4, '{}', '{}', '{"Blindsight 60 ft., Darkvision 120 ft.","Passive Perception 22"}', 'Medium', '{}', '30 ft.', NULL, '10 ft.', '25 ft. (hover)', NULL, 19, 7, '{"Legendary Resistance (4/Day, or 5/Day in Lair). If the dragon fails a saving throw, it can choose to succeed instead."}', '2026-05-15 05:45:35.571633+00', NULL, 14, 9),
	('{"Scimitar. Melee Attack Roll: +4 , reach 5 ft. Hit: 5 ( 1d6 + 2 ) Slashing damage, plus 2 ( 1d4 ) Slashing damage if the attack roll had Advantage.","Shortbow. Ranged Attack Roll: +4 , range 80/320 ft. Hit: 5 ( 1d6 + 2 ) Piercing damage, plus 2 ( 1d4 ) Piercing damage if the attack roll had Advantage."}', 'Neutral', 12, '{}', '1/4', 15, -2, 16, 7, '2026-05-15 05:45:35.571633+00', 'Aberration', NULL, 10, 3, 10000, NULL, NULL, '17d12 + 85', 37, '7d3c2002-b11f-4b97-9997-728604af63b4', '{Fire,"Poison; Poisoned"}', '+2', 14, 7, 0, 'Common, Draconic', '{}', 'Sphinx of Wonder', 2, '{}', '{}', '{"Darkvision 60 ft.","Passive Perception 10"}', 'Large', '{"Stealth +6"}', '60 ft.', NULL, NULL, NULL, NULL, 5, 4, '{}', '2026-05-15 05:45:35.571633+00', NULL, 10, 4),
	('{"Bite. Melee Attack Roll: +4 , reach 5 ft. Hit: 1 Piercing damage, and the target is subjected to the following effect. Constitution Saving Throw: DC 12. Failure: The target has the Poisoned condition until the end of the homunculus’s next turn. Failure by 5 or More: The target has the Poisoned condition for 1 minute. While Poisoned, the target has the Unconscious condition, which ends early if the target takes any damage."}', 'Neutral Evil', 19, '{"Rampage (2/Day). Immediately after dealing damage to a creature that is already Bloodied , the gnoll moves up to half its Speed, and it makes one Bone Whip attack."}', '10', 14, 0, 10, 5, '2026-05-15 05:45:35.571633+00', 'Monstrosity', NULL, 12, 0, 1100, NULL, 'Chain Shirt , Spear', '18d12 + 72', 332, 'e7fbb211-2c6d-4f70-951f-301899daf9b2', '{}', '+6', 16, 3, 0, 'Abyssal; telepathy 120 ft.', '{}', 'Modron Quadrone', 3, '{}', '{}', '{"Truesight 120 ft.","Passive Perception 18"}', 'Medium or Small', '{"Perception +12"}', '30 ft.', NULL, NULL, NULL, NULL, 18, -4, '{}', '2026-05-15 05:45:35.571633+00', NULL, 11, 2),
	('{"Vile Slime. Melee Attack Roll: +2 , reach 5 ft. Hit: 2 ( 1d4 ) Poison damage."}', 'Neutral', 19, '{}', '17', 18, 2, 16, 6, '2026-05-15 05:45:35.571633+00', 'Monstrosity', NULL, 10, 5, 1800, NULL, NULL, '7d4 + 7', 310, 'f1f0e8ca-3090-4ed0-8045-b45393596ee7', '{"Poison; Exhaustion",Grappled,Paralyzed,Petrified,Poisoned,Prone,Restrained,Unconscious}', '+7', 12, 14, 0, 'Common plus one other language', '{}', 'Salamander Fire Snake', 7, '{}', '{}', '{"Blindsight 30 ft., Tremorsense 60 ft.","Passive Perception 9"}', 'Small', '{}', '40 ft.', NULL, NULL, '80 ft.', NULL, 11, 2, '{"Elemental Restoration. If the djinni dies outside the Elemental Plane of Air, its body dissolves into mist, and it gains a new body in 1d4 days, reviving with all its Hit Points somewhere on the Plane of Air .","Magic Resistance. The djinni has Advantage on saving throws against spells and other magical effects.","Wishes. The djinni has a 30 percent chance of knowing the Wish spell. If the djinni knows it, the djinni can cast it only on behalf of a non-genie creature who communicates a wish in a way the djinni can understand. If the djinni casts the spell for the creature, the djinni suffers none of the spell’s stress. Once the djinni has cast it three times, the djinni can’t do so again for 365 days."}', '2026-05-15 05:45:35.571633+00', NULL, 13, 0),
	('{"Multiattack. The modron makes five Slam attacks or five Electrical Discharge attacks.","Slam. Melee Attack Roll: +4 , reach 5 ft. Hit: 5 ( 1d6 + 2 ) Force damage.","Electrical Discharge. Ranged Attack Roll: +4 , range 120 ft. Hit: 5 ( 1d6 + 2 ) Lightning damage.","Paralysis Gas (Recharge 5–6). Constitution Saving Throw: DC 11, each creature in a 30-foot Cone . Failure: The target has the Paralyzed condition and repeats the save at the end of each of its turns, ending the effect on itself on a success. After 1 minute, it succeeds automatically."}', 'Neutral Evil', 15, '{"Shape-Shift. The yuan-ti shape-shifts into a Medium snake or returns to its true form. If it dies, it stays in its current form. The yuan-ti’s game statistics are the same in each form, except where noted. Any equipment it is wearing or carrying isn’t transformed."}', '8', 5, -3, 25, 3, '2026-05-15 05:45:35.571633+00', 'Fiend', NULL, 14, 4, 2300, NULL, NULL, '2d8', 71, '6e6e6778-6f81-4b66-9918-0e48711cbaea', '{"Poison; Charmed",Exhaustion,Paralyzed,Petrified,Poisoned,Prone}', '+2', 10, 10, 6, 'None', '{}', 'Hezrou', 5, '{"Shield (2/Day). The mind flayer casts Shield in response to that spell’s trigger, using the same spellcasting ability as Spellcasting."}', '{Poison}', '{"Passive Perception 10"}', 'Gargantuan', '{"Perception +9"}', '20 ft.', NULL, NULL, '60 ft.', NULL, 4, 1, '{"Diabolical Restoration. If the devil dies outside the Nine Hells, its body disappears in sulfurous smoke, and it gains a new body instantly, reviving with all its Hit Points somewhere in the Nine Hells .","Magic Resistance. The devil has Advantage on saving throws against spells and other magical effects."}', '2026-05-15 05:45:35.571633+00', 'Fire', 12, 2),
	('{"Multiattack. The dragon makes three Rend attacks. It can replace one attack with a use of Weakening Breath.","Rend. Melee Attack Roll: +10 , reach 10 ft. Hit: 17 ( 2d10 + 6 ) Slashing damage.","Fire Breath (Recharge 5–6) . Dexterity Saving Throw: DC 17, each creature in a 30-foot Cone . Failure: 55 ( 10d10 ) Fire damage. Success: Half damage.","Weakening Breath. Strength Saving Throw: DC 17, each creature that isn’t currently affected by this breath in a 30-foot Cone . Failure: The target has Disadvantage on Strength-based d20 Tests and subtracts 3 ( 1d6 ) from its damage rolls. It repeats the save at the end of each of its turns, ending the effect on itself on a success. After 1 minute, it succeeds automatically."}', 'Chaotic Neutral', 17, '{}', '9', 10, -3, 14, 1, '2026-05-15 05:45:35.571633+00', 'Fiend', NULL, 16, 2, 7200, '13,000', NULL, '3d8 + 3', 97, '85e65b6e-19fa-4008-bee3-a529424b5d3b', '{Frightened}', '+3', 10, 3, -2, 'Common plus two other languages', '{}', 'Vampire', 3, '{"Burst of Ingenuity (2/Day). Trigger: The sphinx or another creature within 30 feet makes an ability check or a saving throw. Response: The sphinx adds 2 to the roll."}', '{}', '{"Passive Perception 14"}', 'Large', '{"Perception +9","Stealth +4"}', '30 ft.', NULL, NULL, NULL, NULL, 22, 2, '{}', '2026-05-15 05:45:35.571633+00', NULL, 10, 0),
	('{"Multiattack. The dragon makes three Rend attacks. It can replace one attack with a use of (A) Repulsion Breath or (B) Spellcasting to cast Guiding Bolt (level 2 version).","Rend. Melee Attack Roll: +16 , reach 15 ft. Hit: 18 ( 2d8 + 9 ) Slashing damage plus 9 ( 2d8 ) Lightning damage.","Lightning Breath (Recharge 5–6) . Dexterity Saving Throw: DC 23, each creature in a 120-foot-long, 10-foot-wide Line . Failure: 82 ( 15d10 ) Lightning damage. Success: Half damage.","Repulsion Breath. Strength Saving Throw: DC 23, each creature in a 30-foot Cone . Failure: The target is pushed up to 60 feet straight away from the dragon and has the Prone condition.","Spellcasting. The dragon casts one of the following spells, requiring no Material components and using Charisma as the spellcasting ability (spell save DC 22, +14 to hit with spell attacks):","At Will: Detect Magic , Guiding Bolt (level 2 version), Shapechange (Beast or Humanoid form only, no Temporary Hit Points gained from the spell, and no Concentration or Temporary Hit Points required to maintain the spell), Speak with Animals , Thaumaturgy","1/Day Each: Detect Thoughts , Control Water , Scrying , Water Breathing"}', 'Unaligned', 16, '{"Confusing Gaze (Recharge 5–6). Wisdom Saving Throw: DC 14, each creature in a 30-foot Cone . Failure: The target can’t take Reactions until the start of the umber hulk’s next turn, and the target rolls 1d8 to determine what it does on its next turn:","1–4. The target does nothing.","5–6. The target takes no action or Bonus Action and uses all its movement to move in a random direction.","7–8. The target makes a melee attack against a random creature within its reach or does nothing if it can’t make such an attack."}', '3', 16, 8, 22, 2, '2026-05-15 05:45:35.571633+00', 'Aberration', '(Metallic)', 17, 6, 700, NULL, NULL, '14d8 + 42', 11, 'a3b83c2b-e564-4832-901a-013a387f7663', '{"Psychic; Charmed",Frightened}', '+3', 11, 10, 0, 'Common plus one other language', '{}', 'Shadow Demon', 2, '{}', '{}', '{"Blindsight 30 ft.","Passive Perception 10"}', 'Medium', '{"Deception +5","Perception +4","Stealth +6"}', '40 ft.', NULL, NULL, NULL, NULL, 8, -2, '{"Amphibious. The dragon can breathe air and water.","Legendary Resistance (4/Day, or 5/Day in Lair). If the dragon fails a saving throw, it can choose to succeed instead."}', '2026-05-15 05:45:35.571633+00', NULL, 11, 0),
	('{"Multiattack. The mind flayer makes three Arcane Tentacles attacks.","Arcane Tentacles. Melee or Ranged Attack Roll: +9 , reach 5 ft. or range 120 ft. Hit: 27 ( 4d10 + 5 ) Psychic damage, and the mind flayer can teleport the target up to 30 feet to an unoccupied space the mind flayer can see on a surface or liquid large enough to support the target. If this damage reduces the target to 0 Hit Points, the mind flayer kills it and magically devours its brain.","Mind Burst (Recharge 5–6). Intelligence Saving Throw: DC 17, each creature in a 40-foot Emanation originating from the mind flayer. Failure: 41 ( 8d8 + 5 ) Psychic damage, and the target has the Stunned condition until the end of the mind flayer’s next turn. Success: Half damage only.","Spellcasting. The mind flayer casts one of the following spells, requiring no spell components and using Intelligence as the spellcasting ability (spell save DC 17):","At Will: Detect Magic , Detect Thoughts , Disguise Self , Mage Hand (the hand is Invisible )","1/Day Each: Clairvoyance , Dimension Door , Fireball (level 5 version), Lightning Bolt (level 5 version), Plane Shift (self only), Sending"}', 'Neutral Evil', 15, '{"Captain’s Charm. Wisdom Saving Throw: DC 14, one creature the pirate can see within 30 feet. Failure: The target has the Charmed condition until the start of the pirate’s next turn."}', '5', 3, 2, 13, 1, '2026-05-15 05:45:35.571633+00', 'Dragon', '(Devil)', 11, 1, 3900, NULL, NULL, '3d10 + 3', 97, '0da9561a-61eb-4dba-9cf6-20f66e9199d6', '{}', '+3', 19, 1, 0, 'Sahuagin', '{}', 'Remorhaz', 3, '{}', '{Necrotic,Radiant}', '{"Passive Perception 15"}', 'Huge', '{"Athletics +4","Deception +4"}', '5 ft.', NULL, NULL, NULL, NULL, 18, 5, '{"Fire Aura. At the end of each of the elemental’s turns, each creature in a 10-foot Emanation originating from the elemental takes 5 ( 1d10 ) Fire damage. Creatures and flammable objects in the Emanation start burning .","Fire Form. The elemental can move through a space as narrow as 1 inch without expending extra movement to do so, and it can enter a creature’s space and stop there. The first time it enters a creature’s space on a turn, that creature takes 5 ( 1d10 ) Fire damage.","Illumination. The elemental sheds Bright Light in a 30-foot radius and Dim Light for an additional 30 feet.","Water Susceptibility. The elemental takes 3 ( 1d6 ) Cold damage for every 5 feet the elemental moves in water or for every gallon of water splashed on it."}', '2026-05-15 05:45:35.571633+00', NULL, 18, 0),
	('{"Smother. Melee Attack Roll: +5 , reach 5 ft. Hit: 10 ( 2d6 + 3 ) Bludgeoning damage. If the target is a Medium or smaller creature, the rug can give it the Grappled condition (escape DC 13) instead of dealing damage. Until the grapple ends, the target has the Blinded and Restrained conditions, is suffocating , and takes 10 ( 2d6 + 3 ) Bludgeoning damage at the start of each of its turns. The rug can smother only one creature at a time.","While grappling the target, the rug can’t take this action, the rug halves the damage it takes (round down), and the target takes the same amount of damage."}', 'Chaotic Neutral', 16, '{}', '4', 16, 2, 20, 4, '2026-05-15 05:45:35.571633+00', 'Elemental', '(Yugoloth)', 8, 2, 8400, NULL, NULL, '16d10 + 64', 68, '87faad12-d5ca-4386-a41c-e426b6ad708d', '{Fire}', '+14', 12, 11, 3, 'All; telepathy 120 ft.', '{}', 'Imp', 3, '{}', '{}', '{"Passive Perception 13"}', 'Medium', '{"Perception +6","Persuasion +8"}', '5 ft.', NULL, NULL, '60 ft.', NULL, 19, 4, '{}', '2026-05-15 05:45:35.571633+00', 'Fire', 11, 9),
