	('{"Multiattack. The naga makes two Bite attacks. It can replace any attack with a use of Serpentine Gaze.","Bite. Melee Attack Roll: +5 , reach 10 ft. Hit: 10 ( 2d6 + 3 ) Piercing damage plus 7 ( 2d6 ) Necrotic damage.","Serpentine Gaze. Wisdom Saving Throw: DC 13, one creature the naga can see within 60 feet. Failure: 13 ( 3d6 + 3 ) Psychic damage, and the target has the Charmed condition until the start of the naga’s next turn.","Spellcasting. The naga casts one of the following spells, requiring no Material components and using Intelligence as the spellcasting ability (spell save DC 13):","At Will: Mage Hand , Thaumaturgy","1/Day Each: Command , Detect Thoughts , Lightning Bolt"}', 'Chaotic Evil', 19, '{}', '8', 16, -4, 14, 7, '2026-05-15 05:45:35.571633+00', 'Elemental', NULL, 13, -1, 15000, NULL, NULL, '11d8', 65, 'a2394235-2cd1-4cd7-9821-5b79e43f05f0', '{Deafened}', '+4', 13, 20, -2, 'Common, Elvish', '{}', 'Mind Flayer Arcanist', 2, '{}', '{}', '{"Darkvision 120 ft.","Passive Perception 11"}', 'Tiny', '{}', '30 ft.', NULL, '40 ft.', NULL, NULL, 18, 5, '{"Flyby. The peryton doesn’t provoke an Opportunity Attack when it flies out of an enemy’s reach."}', '2026-05-15 05:45:35.571633+00', NULL, 10, 8),
	('{"Bite. Melee Attack Roll: +1 , reach 5 ft. Hit: 1 ( 1d4 - 1 ) Necrotic damage."}', 'Neutral Evil', 18, '{}', '1/2', 3, 5, 14, 7, '2026-05-15 05:45:35.571633+00', 'Aberration', NULL, 12, 2, 1800, NULL, NULL, '26d20 + 208', 28, '6ebf5f09-5ac1-424c-9556-30e49a893451', '{}', '+12', 24, 7, -4, 'Abyssal, Common, Draconic', '{}', 'Brazen Gorgon', 2, '{}', '{}', '{"Darkvision 120 ft.","Passive Perception 10"}', 'Medium', '{"Perception +6"}', '30 ft.', NULL, NULL, '80 ft.', NULL, 18, -2, '{"Detect Life. The banshee magically senses the direction of creatures up to 1 mile away that aren’t Constructs or Undead.","Incorporeal Movement. The banshee can move through other creatures and objects as if they were Difficult Terrain . It takes 5 ( 1d10 ) Force damage if it ends its turn inside an object."}', '2026-05-15 05:45:35.571633+00', NULL, 11, 7),
	('{"Multiattack. The goblin makes two Hex Stick attacks. It can replace one attack with a use of Spellcasting.","Hex Stick. Melee or Ranged Attack Roll: +5 , reach 5 ft. or range 60 ft. Hit: 12 ( 2d8 + 3 ) Psychic damage.","Spellcasting. The goblin casts one of the following spells, using Intelligence as the spellcasting ability (spell save DC 13):","At Will: Minor Illusion","1/Day Each: Blindness/Deafness , Faerie Fire , Grease"}', 'Neutral', 16, '{"Vow of Revenge (1/Day). The revenant curses one creature it can see within 30 feet of itself. The revenant knows the distance to and direction of the cursed target, even if it is on a different plane of existence. The curse ends on the target if the revenant uses this Bonus Action on a different creature."}', '7', 14, -1, 10, 7, '2026-05-15 05:45:35.571633+00', 'Humanoid', NULL, 17, 1, 10000, NULL, NULL, '12d10 + 48', 45, '3144a56f-8312-48ae-96ed-dde3bece657d', '{}', '+2', 12, 14, 2, 'Primordial (Aquan, Ignan)', '{}', 'Larva', 2, '{}', '{}', '{"Blindsight 30 ft.","Passive Perception 10"}', 'Medium', '{}', '30 ft.', NULL, NULL, NULL, NULL, 15, 8, '{}', '2026-05-15 05:45:35.571633+00', NULL, 13, 5),
