	('{"Rend. Melee Attack Roll: +4 , reach 5 ft. Hit: 7 ( 1d10 + 2 ) Slashing damage.","Acid Breath (Recharge 5–6) . Dexterity Saving Throw: DC 11, each creature in a 20-foot-long, 5-foot-wide Line . Failure: 18 ( 4d8 ) Acid damage. Success: Half damage.","Slowing Breath. Constitution Saving Throw: DC 11, each creature in a 15-foot Cone . Failure: The target can’t take Reactions; its Speed is halved; and it can take either an action or a Bonus Action on its turn, not both. This effect lasts until the end of its next turn."}', 'Lawful Evil', 15, '{"Misty Step. The giant casts the Misty Step spell, using the same spellcasting ability as Spellcasting."}', '13', 12, 0, 10, 1, '2026-05-15 05:45:35.571633+00', 'Undead', NULL, 14, 3, 50, NULL, NULL, '5d6 + 5', 55, 'f54ddffa-bd50-4580-b2c8-a52fb7a3e151', '{Fire}', '+2', 18, 5, 0, 'Infernal; telepathy 120 ft.', '{}', 'Slaad Tadpole', 2, '{}', '{Cold}', '{"Blindsight 60 ft.","Passive Perception 8"}', 'Huge', '{}', '40 ft.', NULL, NULL, '60 ft.', NULL, 19, 3, '{"Magic Resistance. The imp has Advantage on saving throws against spells and other magical effects."}', '2026-05-15 05:45:35.571633+00', NULL, 12, 7),
	('{"Multiattack. The wyvern makes one Bite attack and one Sting attack.","Bite. Melee Attack Roll: +7 , reach 5 ft. Hit: 13 ( 2d8 + 4 ) Piercing damage.","Sting. Melee Attack Roll: +7 , reach 10 ft. Hit: 11 ( 2d6 + 4 ) Piercing damage plus 24 ( 7d6 ) Poison damage, and the target has the Poisoned condition until the start of the wyvern’s next turn."}', 'Neutral', 14, '{}', '1/2', 6, 0, 12, 3, '2026-05-15 05:45:35.571633+00', 'Humanoid', '(Titan)', 16, -5, 1800, NULL, NULL, '26d20 + 208', 66, '52322d8a-4d19-401e-a4d3-05d8ae9a26ea', '{}', '+0', 7, 9, -2, 'None', '{}', 'Cloud Giant', 2, '{"Watery Rebuke. Trigger: An enemy the merfolk can see enters a space within 5 feet of the merfolk. Response—Strength Saving Throw: DC 15, the triggering enemy. Failure: 14 ( 4d6 ) Cold damage. If the target is Large or smaller, it is pushed up to 30 feet straight away from the merfolk by conjured water."}', '{}', '{"Blindsight 30 ft","Passive Perception 5"}', 'Medium', '{"Perception +5"}', '40 ft.', NULL, NULL, NULL, NULL, 16, 1, '{"Pack Tactics. The warrior has Advantage on an attack roll against a creature if at least one of the warrior’s allies is within 5 feet of the creature and the ally doesn’t have the Incapacitated condition."}', '2026-05-15 05:45:35.571633+00', NULL, 14, 1),
