INSERT INTO "public"."spells" ("casting_time", "created_at", "description", "duration", "id", "is_concentration", "is_material", "is_ritual", "is_somatic", "is_verbal", "level", "material_description", "name", "range", "school", "upcast_description", "updated_at") VALUES
	('Action or Ritual', '2026-05-15 05:45:35.483105+00', 'You launch a sunbeam in a 5-foot-wide, 60-foot-long Line. Each creature in the Line makes a Constitution saving throw. On a failed save, a creature takes 6d8 Radiant damage and has the Blinded condition until the start of your next turn. On a successful save, it takes half as much damage only. Until the spell ends, you can take a Magic action to create a new Line of radiance. For the duration, a mote of brilliant radiance shines above you. It sheds Bright Light in a 30-foot radius and Dim Light for an additional 30 feet. This light is sunlight.', '1 minute', 'e6be6231-cf96-42af-950a-3661b6423153', false, false, false, true, true, 9, 'rare oils worth 1,000+ GP, which the spell consumes', 'Mordenkainen’s Sword', '60 feet', 'Conjuration', 'You can target one additional creature for each spell slot level above 2.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You conjure a portal linking an unoccupied space you can see within range to a precise location on a different plane of existence. The portal is a circular opening, which you can make 5 to 20 feet in diameter. You can orient the portal in any direction you choose. The portal lasts for the duration, and the portal’s destination is visible through it. The portal has a front and a back on each plane where it appears. Travel through the portal is possible only by moving through its front. Anything that does so is instantly transported to the other plane, appearing in the unoccupied space nearest to the portal. Deities and other planar rulers can prevent portals created by this spell from opening in their presence or anywhere within their domains. When you cast this spell, you can speak the name of a specific creature (a pseudonym, title, or nickname doesn’t work). If that creature is on a plane other than the one you are on, the portal opens next to the named creature and transports it to the nearest unoccupied space on your side of the portal. You gain no special power over the creature, and it is free to act as the DM deems appropriate. It might leave, attack you, or help you.', 'Concentration, up to 1 hour', '00a539a7-554d-4c0c-86f8-60acbf3eff65', false, false, false, true, true, 0, 'a pinch of sulfur', 'Polymorph', '30 feet', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create a magical restraint to hold a creature. Choices include Burial, Chaining, Hedged Prison, Minimus Containment, or Slumber. The creature does not need to breathe, eat, or drink and does not age while imprisoned.', 'Concentration, up to 10 minutes', 'e64455ec-cb6f-4532-ba85-7e2c12f98a55', false, false, false, true, true, 6, 'a statuette of yourself worth 5+ GP', 'Globe of Invulnerability', 'Touch', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You call forth a Dragon spirit. It manifests in an unoccupied space that you can see within range and uses the Draconic Spirit stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends. The creature is an ally to you and your allies. In combat, the creature shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the Dodge action and uses its movement to avoid danger. Draconic Spirit Large Dragon, Neutral AC 14 + the spell’s level HP 50 + 10 for each spell level above 5 Speed 30 ft., Fly 60 ft., Swim 30 ft. Mod Save STR 19 +4 +4 DEX 14 +2 +2 CON 17 +3 +3 Mod Save INT 10 +0 +0 WIS 14 +2 +2 CHA 14 +2 +2 Resistances Acid, Cold, Fire, Lightning, Poison Immunities Charmed, Frightened, Poisoned Senses Blindsight 30 ft., Darkvision 60 ft.; Passive Perception 12 Languages Draconic, understands the languages you know CR None (XP 0; PB equals your Proficiency Bonus) Traits Shared Resistances. When you summon the spirit, choose one of its Resistances. You have Resistance to the chosen damage type until the spell ends. Actions Multiattack. The spirit makes a number of Rend attacks equal to half the spell’s level (round down), and it uses Breath Weapon. Rend. Melee Attack Roll: Bonus equals your spell attack modifier, reach 10 feet. Hit: 1d6 + 4 + the spell’s level Piercing damage. Breath Weapon. Dexterity Saving Throw: DC equals your spell save DC, each creature in a 30-foot Cone. Failure: 2d6 damage of a type this spirit has Resistance to (your choice when you cast the spell). Success: Half damage.', '24 hours', 'e495296b-32c0-4915-8ef5-87ab5ae425fe', false, false, false, true, true, 3, 'a bit of gauze', 'Shining Smite', 'Touch', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 minute', '2026-05-15 05:45:35.483105+00', 'The target takes an extra 4d6 Psychic damage from the attack, and the target must succeed on a Wisdom saving throw or have the Stunned condition until the end of your next turn.', 'Concentration, up to 1 minute', 'a6c68221-992f-4816-8e76-20bf358faed3', false, true, false, true, true, 4, NULL, 'Otiluke’s Freezing Sphere', 'Touch', 'Enchantment', 'The damage increases by 1d6 for each spell slot level above 3.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A creature of your choice that you can see within range regains Hit Points equal to 2d4 plus your spellcasting ability modifier.', 'Instantaneous', '214dae5e-3556-4e95-9d60-a11c5122b685', true, false, false, false, true, 5, NULL, 'Detect Evil and Good', '60 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'As you cast the spell, you draw a 5-foot-radius circle on the ground inscribed with sigils that link your location to a permanent teleportation circle of your choice whose sigil sequence you know and that is on the same plane of existence as you. A shimmering portal opens within the circle you drew and remains open until the end of your next turn. Any creature that enters the portal instantly appears within 5 feet of the destination circle or in the nearest unoccupied space if that space is occupied. Many major temples, guildhalls, and other important places have permanent teleportation circles. Each circle includes a unique sigil sequence—a string of runes arranged in a particular pattern. When you first gain the ability to cast this spell, you learn the sigil sequences for two destinations on the Material Plane, determined by the DM. You might learn additional sigil sequences during your adventures. You can commit a new sigil sequence to memory after studying it for 1 minute. You can create a permanent teleportation circle by casting this spell in the same location every day for 365 days.', 'Up to 1 minute', 'f9dd51c5-8414-4849-9ce8-c903c830ccff', false, true, false, true, true, 0, 'a focus worth 1,000+ GP, such as a crystal ball, mirror, or water-filled font', 'Greater Restoration', 'Touch', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Choose up to five falling creatures. Their rate of descent slows to 60 feet per round. If they land before the spell ends, they take no falling damage.', 'Instantaneous', '4d8b8cf2-81c8-4190-906c-99265b06df39', false, true, false, true, true, 7, 'a bit of fleece', 'Magic Jar', '30 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create a line of wind. You can push a Medium or smaller creature 5 feet (STR save), push an object 10 feet, or create harmless sensory effects like rustling leaves.', 'Instantaneous', 'b12ba95d-c55c-4a01-8610-9e95d032bbd3', false, true, false, false, true, 0, NULL, 'Stoneskin', '60 feet', 'Enchantment', 'The Cold damage increases by 1d6 for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A 60-foot-radius Sphere of light spreads from a point. The light is Bright light and sheds Dim light for an additional 60 feet. It dispels any darkness created by a spell of level 3 or lower.', 'Concentration, up to 1 minute', 'a64781a7-cff7-4197-b867-ee9bed8f0dc6', false, true, false, true, true, 6, NULL, 'Reincarnate', 'Touch', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You point at a location within range, and a glowing, 1-foot-diameter ball of acid streaks there and explodes in a 20-foot-radius Sphere. Each creature in that area makes a Dexterity saving throw. On a failed save, a creature takes 10d4 Acid damage and another 5d4 Acid damage at the end of its next turn. On a successful save, a creature takes half the initial damage only.', 'Concentration, up to 10 minutes', '6b9c23af-6b14-41e0-b7db-2c3fb8d6a46e', false, true, false, true, true, 6, 'a drop of water or a piece of ice', 'Etherealness', 'Self', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action, which you take immediately after hitting a creature with a Melee weapon or an Unarmed Strike', '2026-05-15 05:45:35.483105+00', 'You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 20-foot Cube. The image appears at a spot that you can see within range and lasts for the duration. It seems real, including sounds, smells, and temperature appropriate to the thing depicted, but it can’t deal damage or cause conditions. If you are within range of the illusion, you can take a Magic action to cause the image to move to any other spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking. Similarly, you can cause the illusion to make different sounds at different times, even making it carry on a conversation, for example. Physical interaction with the image reveals it to be an illusion, for things can pass through it. A creature that takes a Study action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and its other sensory qualities become faint to the creature.', '24 hours', '5e645b7e-c1f4-45e3-bf76-1b3f89f5de11', false, false, false, true, true, 2, 'a mix of salt, powdered silver, and holy water worth 1,000+ GP, which the spell consumes', 'Vicious Mockery', 'Touch', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 15-foot Cube. The image appears at a spot within range and lasts for the duration. The image is purely visual; it isn’t accompanied by sound, smell, or other sensory effects. As a Magic action, you can cause the image to move to any spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking. Physical interaction with the image reveals it to be an illusion, since things can pass through it. A creature that takes a Study action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image.', 'Concentration, up to 1 hour', '4e7c9822-8c06-49d4-ace5-b717f2c6cb1f', false, true, false, true, true, 2, NULL, 'Dissonant Whispers', '30 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A Large spectral guardian appears and hovers for the duration in an unoccupied space that you can see within range. The guardian occupies that space and is invulnerable, and it appears in a form appropriate for your deity or pantheon. Any enemy that moves to a space within 10 feet of the guardian for the first time on a turn or starts its turn there makes a Dexterity saving throw, taking 20 Radiant damage on a failed save or half as much damage on a successful one. The guardian vanishes when it has dealt a total of 60 damage.', 'Concentration, up to 1 hour', '6dbb1791-caa4-4083-9292-968ba6331499', false, false, false, true, true, 3, NULL, 'Dimension Door', '150 feet', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'You have Advantage on Charisma checks directed at one non-hostile creature. When the spell ends, the creature realizes you used magic to influence it and may become hostile.', 'Concentration, up to 1 minute', '6631f252-adb7-488b-a629-ebe7e9d39f5a', false, false, false, true, true, 1, NULL, 'Mordenkainen’s Faithful Hound', '150 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Reaction, which you take in response to taking damage from a creature that you can see within 60 feet of yourself', '2026-05-15 05:45:35.483105+00', 'This spell creates a circular, horizontal plane of force, 3 feet in diameter and 1 inch thick, that floats 3 feet above the ground. It can carry up to 500 pounds.', 'Concentration, up to 10 minutes', 'd7693218-39f5-4320-9ac5-3925e2c0162b', false, true, false, true, true, 3, 'powdered diamond worth 200+ GP, which the spell consumes', 'Tasha’s Hideous Laughter', '60 feet', 'Abjuration', 'You can target one additional creature for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You call forth an Elemental spirit. It manifests in an unoccupied space that you can see within range and uses the Elemental Spirit stat block. When you cast the spell, choose an element: Air, Earth, Fire, or Water. The creature resembles a bipedal form wreathed in the chosen element, which determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends. The creature is an ally to you and your allies. In combat, the creature shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the Dodge action and uses its movement to avoid danger. Elemental Spirit Medium Elemental, Neutral AC 11 + the spell’s level HP 50 + 10 for each spell level above 4 Speed 40 ft.; Burrow 40 ft. (Earth only); Fly 40 ft. (hover; Air only); Swim 40 ft. (Water only) Mod Save STR 18 +4 +4 DEX 15 +2 +2 CON 17 +3 +3 Mod Save INT 4 –3 –3 WIS 10 +0 +0 CHA 16 +3 +3 Resistances Acid (Water only), Lightning and Thunder (Air only), Piercing and Slashing (Earth only) Immunities Fire (Fire only), Poison; Exhaustion, Paralyzed, Petrified, Poisoned Senses Darkvision 60 ft.; Passive Perception 10 Languages Primordial, understands the languages you know CR None (XP 0; PB equals your Proficiency Bonus) Traits Amorphous Form (Air, Fire, and Water Only). The spirit can move through a space as narrow as 1 inch wide without it counting as Difficult Terrain. Actions Multiattack. The spirit makes a number of Slam attacks equal to half this spell’s level (round down). Slam. Melee Attack Roll: Bonus equals your spell attack modifier, reach 5 ft. Hit: 1d10 + 4 + the spell’s level Bludgeoning (Earth only), Cold (Water only), Lightning (Air only), or Fire (Fire only) damage.', 'Instantaneous', '70397ab1-6e1f-493a-b6a7-ec51fbfd3645', false, true, false, true, true, 2, NULL, 'Guidance', '15 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Choose a Humanoid that you can see within range. The target must succeed on a Wisdom saving throw or have the Paralyzed condition for the duration. At the end of each of its turns, the target repeats the save, ending the spell on itself on a success.', 'Concentration, up to 1 hour', 'e532123e-4600-415d-a3c5-48b04e9de8d8', false, true, false, true, true, 7, NULL, 'Spare the Dying', 'Self', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action or Ritual', '2026-05-15 05:45:35.483105+00', 'As you hit the target, it takes an extra 1d6 Fire damage from the attack. At the start of each of its turns until the spell ends, the target takes 1d6 Fire damage and then makes a Constitution saving throw. On a failed save, the spell continues. On a successful save, the spell ends.', 'Until dispelled', '6ea11d4a-5148-4c6f-9510-657ab3dbe3dd', true, false, false, true, true, 1, NULL, 'Maze', '60 feet', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Reaction, which you take in response to taking damage from a creature that you can see within 60 feet of yourself', '2026-05-15 05:45:35.483105+00', 'With a touch, you revive a dead creature if it has been dead no longer than 10 days and it wasn’t Undead when it died. The creature returns to life with 1 Hit Point. This spell also neutralizes any poisons that affected the creature at the time of death. This spell closes all mortal wounds, but it doesn’t restore missing body parts. If the creature is lacking body parts or organs integral for its survival—its head, for instance—the spell automatically fails. Coming back from the dead is an ordeal. The target takes a -4 penalty to d20 Tests. Every time the target finishes a Long Rest, the penalty is reduced by 1 until it becomes 0.', '8 hours', '8cdc9e71-6bf3-44f8-b166-4cce5e4307b9', true, true, false, true, true, 6, 'a hummingbird feather', 'Enthrall', 'Touch', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create a ward that protects up to 2,500 square feet of floor space. The warded area can be up to 20 feet tall, and you shape it as one 50-foot square, one hundred 5-foot squares that are contiguous, or twenty-five 10-foot squares that are contiguous. When you cast this spell, you can specify individuals that are unaffected by the spell’s effects. You can also specify a password that, when spoken aloud within 5 feet of the warded area, makes the speaker immune to its effects. The spell creates the effects below within the warded area. Dispel Magic has no effect on Guards and Wards itself, but each of the following effects can be dispelled. If all four are dispelled, Guards and Wards ends. If you cast the spell every day for 365 days on the same area, the spell thereafter lasts until all its effects are dispelled. Corridors. Fog fills all the warded corridors, making them Heavily Obscured. In addition, at each intersection or branching passage offering a choice of direction, there is a 50 percent chance that a creature other than you believes it is going in the opposite direction from the one it chooses. Doors. All doors in the warded area are magically locked, as if sealed by the Arcane Lock spell. In addition, you can cover up to ten doors with an illusion to make them appear as plain sections of wall. Stairs. Webs fill all stairs in the warded area from top to bottom, as in the Web spell. These strands regrow in 10 minutes if they are destroyed while Guards and Wards lasts. Other Spell Effect. Place one of the following magical effects within the warded area: Dancing Lights in four corridors, with a simple program that the lights repeat as long as Guards and Wards lasts Magic Mouth in two locations Stinking Cloud in two locations (the vapors return within 10 minutes if dispersed while Guards and Wards lasts) Gust of Wind in one corridor or room (the wind blows continuously while the spell lasts) Suggestion in one 5-foot square; any creature that enters that square receives the suggestion mentally', '10 minutes', '128b03a5-d9f8-40c1-9d64-bacdc915ec32', true, false, false, true, false, 7, 'a legume seed', 'Mass Cure Wounds', '60 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create a 20-foot-radius Sphere of fog centered on a point. The sphere spreads around corners, and its area is Heavily Obscured.', 'Concentration, up to 1 minute', 'af6e8f69-4456-4914-b352-496e4a326e42', false, false, false, true, true, 9, NULL, 'Hallucinatory Terrain', '10 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You or a creature you touch becomes Invisible. Unlike standard Invisibility, the spell does not end if the target attacks or casts a spell.', 'Concentration, up to 1 hour', 'a6b68551-90f3-4a24-8f07-8b151336e0b3', true, true, false, true, true, 5, NULL, 'See Invisibility', 'Self', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Reaction, which you take in response to taking damage from a creature that you can see within 60 feet of yourself', '2026-05-15 05:45:35.483105+00', 'You create a line of wind. You can push a Medium or smaller creature 5 feet (STR save), push an object 10 feet, or create harmless sensory effects like rustling leaves.', 'Concentration, up to 1 minute', 'fd0410b7-b3bb-46df-91d9-f420451bca00', false, true, false, true, true, 2, 'a straight piece of iron', 'Heal', 'Touch', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Slick grease covers a 10-foot square. It is difficult terrain, and creatures must succeed on a DEX save or fall Prone when it appears, or when they enter or end their turn there. (Note: No longer flammable in 2024).', 'Concentration, up to 1 minute', '3946529a-9642-4110-8efe-9e2bb2fa3b4a', true, true, false, true, true, 3, 'pork rind or butter', 'Revivify', '120 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You banish a creature that you can see within range into a labyrinthine demiplane. The target remains there for the duration or until it escapes the maze. The target can take a Study action to try to escape. When it does so, it makes a DC 20 Intelligence (Investigation) check. If it succeeds, it escapes, and the spell ends. When the spell ends, the target reappears in the space it left or, if that space is occupied, in the nearest unoccupied space.', 'Concentration, up to 1 hour', 'b2643d51-b67c-4368-9e30-f58390a4a81b', false, false, false, true, true, 5, NULL, 'Teleport', '150 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Guided by a flash of magical insight, you make one attack with the weapon used in the spell’s casting. The attack uses your spellcasting ability for the attack and damage rolls instead of using Strength or Dexterity. If the attack deals damage, it can be Radiant damage or the weapon’s normal damage type (your choice). Cantrip Upgrade. Whether you deal Radiant damage or the weapon’s normal damage type, the attack deals extra Radiant damage when you reach levels 5 (1d6), 11 (2d6), and 17 (3d6).', 'Concentration, up to 1 minute', 'f8327279-984f-4e55-9a16-e97515983d61', false, true, false, true, true, 1, NULL, 'Greater Invisibility', '30 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A passage appears at a point that you can see on a wooden, plaster, or stone surface (such as a wall, ceiling, or floor) within range and lasts for the duration. You choose the opening’s dimensions: up to 5 feet wide, 8 feet tall, and 20 feet deep. The passage creates no instability in a structure surrounding it. When the opening disappears, any creatures or objects still in the passage created by the spell are safely ejected to an unoccupied space nearest to the surface on which you cast the spell.', 'Concentration, up to 1 minute', 'be3c938e-240d-4f44-8123-61e40bcc9de2', false, true, false, false, true, 0, NULL, 'Teleport', 'Self', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You and up to eight willing creatures who link hands in a circle are transported to a different plane of existence. You can specify a target destination in general terms, such as the City of Brass on the Elemental Plane of Fire or the palace of Dispater on the second level of the Nine Hells, and you appear in or near that destination, as determined by the DM. Alternatively, if you know the sigil sequence of a teleportation circle on another plane of existence, this spell can take you to that circle. If the teleportation circle is too small to hold all the creatures you transported, they appear in the closest unoccupied spaces next to the circle.', 'Instantaneous', '654c4c5a-e509-47f3-87cd-10488076fd5a', false, true, false, false, true, 2, 'a gem-encrusted bowl worth 1,000+ GP, which the spell consumes', 'Giant Insect', '60 feet', 'Transmutation', 'All the damage increases by 1d6 for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('1 hour', '2026-05-15 05:45:35.483105+00', 'When you make a Charisma check, you can replace the roll with a 15. Magic that would determine if you are lying indicates you are telling the truth regardless of what you say.', '10 days', '5f307de8-092b-4b70-bc70-c359942cfa08', true, true, false, true, true, 7, 'a crystal bead', 'Geas', '60 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action or Ritual', '2026-05-15 05:45:35.483105+00', 'You step into the border regions of the Ethereal Plane. You can move in any direction and pass through objects on the Material Plane.', 'Concentration, up to 1 minute', '9d14fe22-9e36-4932-b5b3-78cf4f6a668c', true, true, false, true, true, 2, 'a pickled tentacle and an eyeball in a platinum-inlaid vial worth 400+ GP', 'Flame Blade', '60 feet', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Until the spell ends, one willing creature you touch is protected against creatures that are Aberrations, Celestials, Elementals, Fey, Fiends, or Undead. The protection grants several benefits. Creatures of those types have Disadvantage on attack rolls against the target. The target also can’t be possessed by or gain the Charmed or Frightened conditions from them. If the target is already possessed, Charmed, or Frightened by such a creature, the target has Advantage on any new saving throw against the relevant effect.', 'Instantaneous', '4a4c3b69-63a2-4827-8bbd-d9bc5e6ac164', false, false, false, false, true, 8, 'a bit of phosphorus or wychwood, or a glowworm', 'Dominate Person', '60 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Each creature of your choice in a 5-foot-radius Sphere centered on a point within range must succeed on a Wisdom saving throw or have the Incapacitated condition until the end of its next turn, at which point it must repeat the save. If the target fails the second save, the target has the Unconscious condition for the duration. The spell ends on a target if it takes damage or someone within 5 feet of it takes an action to shake it out of the spell’s effect. Creatures that don’t sleep, such as elves, or that have Immunity to the Exhaustion condition automatically succeed on saves against this spell.', 'Concentration, up to 1 minute', '29b4a417-4a0f-4e35-b52b-3618529d77e3', false, false, false, true, true, 2, NULL, 'Greater Restoration', 'Touch', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You imbue plants in an immobile 30-foot Emanation with limited sentience and animation, giving them the ability to communicate with you and follow your simple commands. You can question plants about events in the spell’s area within the past day, gaining information about creatures that have passed, weather, and other circumstances. You can also turn Difficult Terrain caused by plant growth (such as thickets and undergrowth) into ordinary terrain that lasts for the duration. Or you can turn ordinary terrain where plants are present into Difficult Terrain that lasts for the duration. The spell doesn’t enable plants to uproot themselves and move about, but they can move their branches, tendrils, and stalks for you. If a Plant creature is in the area, you can communicate with it as if you shared a common language.', 'Instantaneous', '3c30770d-107e-4cff-84cf-5f3718444cb8', true, true, false, true, true, 6, NULL, 'Starry Wisp', 'Self', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You try to temporarily sliver the mind of one creature you can see within range. The target must succeed on an Intelligence saving throw or take 1d6 Psychic damage and subtract 1d4 from the next saving throw it makes before the end of your next turn. Cantrip Upgrade. The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).', 'Concentration, up to 1 day', '53f239b8-f676-4763-ad81-eaaa472ef943', false, false, false, true, true, 1, NULL, 'Knock', '60 feet', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'This spell allows you to move at an incredible pace. For the duration, you can take the Dash action as a Bonus Action on each of your turns.', '10 days', '37977879-e814-4a19-8940-f089b804173b', true, false, false, true, true, 4, NULL, 'Giant Insect', '60 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'You and up to five willing creatures within 5 feet of you instantly teleport to a previously designated sanctuary. You and any creatures that teleport with you appear in the nearest unoccupied space to the spot you designated when you prepared your sanctuary (see below). If you cast this spell without first preparing a sanctuary, the spell has no effect. You must designate a location, such as a temple, as a sanctuary by casting this spell there.', 'Until dispelled or triggered', 'a754303c-daf3-4031-9b12-fa038b8f9b6b', true, false, false, true, true, 2, 'a glass sphere', 'Dispel Evil and Good', '150 feet', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action or Ritual', '2026-05-15 05:45:35.483105+00', 'Choose up to three creatures within range. Each target’s Hit Point maximum and current Hit Points increase by 5 for the duration.', '8 hours', 'a1eac07f-cba4-4954-9ae2-b947549a9650', false, false, false, true, true, 5, 'a gilded flower worth 300+ GP', 'Daylight', 'Self', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch another creature that is willing and create a mystic connection between you and the target until the spell ends. While the target is within 60 feet of you, it gains a +1 bonus to AC and saving throws, and it has Resistance to all damage. Also, each time it takes damage, you take the same amount of damage. The spell ends if you drop to 0 Hit Points or if you and the target become separated by more than 60 feet. It also ends if the spell is cast again on either of the connected creatures.', 'Concentration, up to 10 minutes', '18fef4db-2cc5-40d4-8958-f731a2c2008e', false, false, false, true, true, 2, 'a straight piece of iron', 'Knock', 'Touch', 'Illusion', 'The damage increases by 1d6 for each spell slot level above 6.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You conjure a shimmering door in range that lasts for the duration. The door leads to an extradimensional dwelling and is 5 feet wide and 10 feet tall. You and any creature you designate when you cast the spell can enter the extradimensional dwelling as long as the door remains open. You can open or close it (no action required) if you are within 30 feet of it. While closed, the door is imperceptible. Beyond the door is a magnificent foyer with numerous chambers beyond. The dwelling’s atmosphere is clean, fresh, and warm. You can create any floor plan you like for the dwelling, but it can’t exceed 50 contiguous 10-foot Cubes. The place is furnished and decorated as you choose. It contains sufficient food to serve a nine-course banquet for up to 100 people. Furnishings and other objects created by this spell dissipate into smoke if removed from it. A staff of 100 near-transparent servants attends all who enter. You determine the appearance of these servants and their attire. They are invulnerable and obey your commands. Each servant can perform tasks that a human could perform, but they can’t attack or take any action that would directly harm another creature. Thus the servants can fetch things, clean, mend, fold clothes, light fires, serve food, pour wine, and so on. The servants can’t leave the dwelling. When the spell ends, any creatures or objects left inside the extradimensional space are expelled into the unoccupied spaces nearest to the entrance.', 'Instantaneous', 'd558f716-d27b-4b31-8cfd-8a4be2c26391', true, true, false, true, true, 6, 'a yew leaf', 'Phantasmal Force', '60 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You write on parchment, paper, or another suitable material and imbue it with an illusion that lasts for the duration. To you and any creatures you designate when you cast the spell, the writing appears normal, seems to be written in your hand, and conveys whatever meaning you intended when you wrote the text. To all others, the writing appears as if it were written in an unknown or magical script that is unintelligible. Alternatively, the illusion can alter the meaning, handwriting, and language of the text, though the language must be one you know. If the spell is dispelled, the original script and the illusion both disappear. A creature that has Truesight can read the hidden message.', '24 hours', 'bea1c1a6-b9dc-4f70-ba62-509ff5ef5d35', true, true, false, true, true, 1, 'a feather from the wing of a bird', 'Otto’s Irresistible Dance', 'Self', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'Choose a willing creature that you can see within range. Until the spell ends, the target’s Speed is doubled, it gains a +2 bonus to Armor Class, it has Advantage on Dexterity saving throws, and it gains an additional action on each of its turns. That action can be used to take only the Attack (one attack only), Dash, Disengage, Hide, or Utilize action. When the spell ends, the target is Incapacitated and has a Speed of 0 until the end of its next turn, as a wave of lethargy washes over it.', '30 days', '225c4bab-fc66-4da1-98de-392fbb188d4f', false, false, false, true, true, 0, NULL, 'Freedom of Movement', '1 mile', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You cause a creature or object to grow larger (Enlarge) or smaller (Reduce). Enlarge grants Advantage on Str checks/saves and +1d4 damage. Reduce grants Disadvantage and -1d4 damage.', '1 hour', '57e4860e-c680-4b40-842c-4892109a2a89', true, true, false, true, true, 1, '10 GP worth of charcoal, incense, and herbs that must be consumed by fire in a brass brazier', 'True Polymorph', 'Self', 'Abjuration', 'The damage increases by 1d8 for each spell slot level above 1. The orb can leap a maximum number of times equal to the level of the slot expended, and a creature can be targeted only once by each casting of this spell.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A green ray shoots from your finger. A target takes 10d6 + 40 Force damage. If this damage reduces the target to 0 HP, it is disintegrated.', 'Concentration, up to 10 minutes', '8b78bb8d-19d2-45a8-8dbd-db092692bd51', false, true, false, false, true, 6, NULL, 'Guiding Bolt', 'Self', 'Conjuration', 'You can target one additional creature for each spell slot level above 2.', '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'For the duration, you can sense the presence and location of poisons, poisonous creatures, and diseases within 30 feet of you.', '10 minutes', '744ef1f6-5bfd-43c2-8225-e17fdd3c6b58', false, false, true, true, true, 2, NULL, 'Tasha’s Bubbling Cauldron', 'Self', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action or Ritual', '2026-05-15 05:45:35.483105+00', 'You launch a sunbeam in a 5-foot-wide, 60-foot-long Line. Each creature in the Line makes a Constitution saving throw. On a failed save, a creature takes 6d8 Radiant damage and has the Blinded condition until the start of your next turn. On a successful save, it takes half as much damage only. Until the spell ends, you can take a Magic action to create a new Line of radiance. For the duration, a mote of brilliant radiance shines above you. It sheds Bright Light in a 30-foot radius and Dim Light for an additional 30 feet. This light is sunlight.', 'Concentration, up to 1 minute', 'd4f7a696-2fb5-48ac-ab61-a5ef2fe02d20', true, false, false, false, true, 4, 'salt and copper pieces', 'Shocking Grasp', 'Self', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch a willing creature. Once before the spell ends, the target can roll a d4 and add the number to one ability check of its choice.', 'Concentration, up to 1 hour', 'e01abe7b-35ce-4fc8-acd8-b82a63830b85', true, true, false, true, true, 6, 'a leaf of sumac', 'Phantasmal Killer', 'Touch', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You evoke a fiery blade in your free hand. It deals 3d6 Fire damage on a hit. It sheds Bright light in a 10-foot radius and Dim light for an additional 10 feet.', 'Concentration, up to 10 minutes', '39926cee-bbe8-4127-b09f-db480c1755a8', false, false, false, true, true, 1, 'a miniature door worth 15+ GP', 'Goodberry', 'Self (30-foot Emanation)', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 hour', '2026-05-15 05:45:35.483105+00', 'Your strike rings with thunder that is audible within 300 feet of you, and the target takes an extra 2d6 Thunder damage from the attack. Additionally, if the target is a creature, it must succeed on a Strength saving throw or be pushed 10 feet away from you and have the Prone condition.', 'Instantaneous', 'bb798b29-e56b-4b02-b71e-34bd1957ea0a', true, true, true, true, true, 8, 'a handful of sand, a dab of ink, and a writing quill', 'Gust of Wind', '120 feet', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'You touch another creature that is willing and create a mystic connection between you and the target until the spell ends. While the target is within 60 feet of you, it gains a +1 bonus to AC and saving throws, and it has Resistance to all damage. Also, each time it takes damage, you take the same amount of damage. The spell ends if you drop to 0 Hit Points or if you and the target become separated by more than 60 feet. It also ends if the spell is cast again on either of the connected creatures.', '1 hour', 'e9dd01c6-55d2-4531-83ac-48546dba0a2d', false, true, false, true, true, 0, 'a grasshopper’s hind leg', 'Shocking Grasp', '500 miles', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('24 hours', '2026-05-15 05:45:35.483105+00', 'A 60-foot-radius Sphere of light spreads from a point. The light is Bright light and sheds Dim light for an additional 60 feet. It dispels any darkness created by a spell of level 3 or lower.', 'Instantaneous', '2f7f56f4-e09b-4d3c-931b-12063b45c3cb', false, false, false, true, true, 2, 'mistletoe', 'Nondetection', 'Self', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Name or describe a famous person, place, or object. The spell brings to your mind a brief summary of the significant lore about that famous thing, as described by the DM. The lore might consist of important details, amusing revelations, or even secret lore that has never been widely known. The more information you already know about the thing, the more precise and detailed the information you receive is. That information is accurate but might be couched in figurative language or poetry, as determined by the DM. If the famous thing you chose isn’t actually famous, you hear sad musical notes played on a trombone, and the spell fails.', 'Instantaneous', 'e37d9ef7-e021-43e2-b28a-167e86af872f', true, true, false, true, true, 2, 'a shard of glass', 'Steel Wind Strike', '60 feet', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'As your attack hits or misses the target, the weapon or ammunition you’re using transforms into a lightning bolt. Instead of taking any damage or other effects from the attack, the target takes 4d8 Lightning damage on a hit or half as much damage on a miss. Each creature within 10 feet of the target then makes a Dexterity saving throw, taking 2d8 Lightning damage on a failed save or half as much damage on a successful one. The weapon or ammunition then returns to its normal form.', 'Concentration, up to 10 minutes', '7b9f2729-086a-4907-b14e-05f1b6046e06', false, false, false, true, true, 0, 'a gilded skull worth 300+ GP', 'Magic Circle', '120 feet', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A frigid globe streaks from you to a point of your choice within range, where it explodes in a 60-foot-radius Sphere. Each creature in that area makes a Constitution saving throw, taking 10d6 Cold damage on a failed save or half as much damage on a successful one. If the globe strikes a body of water, it freezes the water to a depth of 6 inches over an area 30 feet square. This ice lasts for 1 minute. Creatures that were swimming on the surface of frozen water are trapped in the ice and have the Restrained condition. A trapped creature can take an action to make a Strength (Athletics) check against your spell save DC to break free. You can refrain from firing the globe after completing the spell’s casting. If you do so, a globe about the size of a sling bullet, cool to the touch, appears in your hand. At any time, you or a creature you give the globe to can throw the globe (to a range of 40 feet) or hurl it with a sling (to the sling’s normal range). It shatters on impact, with the same effect as a normal casting of the spell. You can also set the globe down without shattering it. After 1 minute, if the globe hasn’t already shattered, it explodes.', 'Up to 1 hour', '77eb599d-4d22-4dad-8f78-22ea895b2bf3', true, true, false, true, true, 4, NULL, 'Searing Smite', 'Touch', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A nonmagical wall of solid stone springs into existence at a point you choose within range. The wall is 6 inches thick and is composed of ten 10-foot-by-10-foot panels. Each panel must be contiguous with another panel. Alternatively, you can create 10-foot-by-20-foot panels that are only 3 inches thick. If the wall cuts through a creature’s space when it appears, the creature is pushed to one side of the wall (you choose which side). If a creature would be surrounded on all sides by the wall (or the wall and another solid surface), that creature can make a Dexterity saving throw. On a success, it can use its Reaction to move up to its Speed so that it is no longer enclosed by the wall. The wall can have any shape you desire, though it can’t occupy the same space as a creature or object. The wall doesn’t need to be vertical or rest on a firm foundation. It must, however, merge with and be solidly supported by existing stone. Thus, you can use this spell to bridge a chasm or create a ramp. If you create a span greater than 20 feet in length, you must halve the size of each panel to create supports. You can crudely shape the wall to create battlements and the like. The wall is an object made of stone that can be damaged and thus breached. Each panel has AC 15 and 30 Hit Points per inch of thickness, and it has Immunity to Poison and Psychic damage. Reducing a panel to 0 Hit Points destroys it and might cause connected panels to collapse at the DM’s discretion. If you maintain your Concentration on this spell for its full duration, the wall becomes permanent and can’t be dispelled. Otherwise, the wall disappears when the spell ends.', 'Concentration, up to 10 minutes', '86864c7a-cb8d-4f4d-90e4-1a334caf98fa', false, true, false, true, true, 1, 'a statuette of yourself worth 5+ GP', 'Meld into Stone', 'Self', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'Your prayer empowers you. Until the spell ends, your weapon attacks deal an extra 1d4 Radiant damage on a hit.', '10 days', '96ee3077-7448-48c7-a7ef-5e3ced068ea9', false, false, false, true, true, 2, 'a drop of mercury', 'Imprisonment', 'Self', 'Abjuration', 'The damage increases by 1d6 for each spell slot level above 2.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A nonmagical weapon you touch becomes a magic weapon. Choose Acid, Cold, Fire, Lightning, or Thunder. The weapon has a +1 bonus to attack rolls and deals an extra 1d4 damage of the chosen type.', '8 hours', '09f4a005-4bfe-4637-9b47-65cab5f0fd2d', true, true, false, true, true, 6, 'a shaving of licorice root', 'Disguise Self', 'Self', 'Transmutation', 'You can target one additional creature for each spell slot level above 3.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You attempt to bind a Celestial, an Elemental, a Fey, or a Fiend to your service. The creature must be within range for the entire casting of the spell. (Typically, the creature is first summoned into the center of the inverted version of the Magic Circle spell to trap it while this spell is cast.) At the completion of the casting, the target must succeed on a Charisma saving throw or be bound to serve you for the duration. If the creature was summoned or created by another spell, that spell’s duration is extended to match the duration of this spell. A bound creature must follow your commands to the best of its ability. You might command the creature to accompany you on an adventure, to guard a location, or to deliver a message. If the creature is Hostile, it strives to twist your commands to achieve its own objectives. If the creature carries out your commands completely before the spell ends, it travels to you to report this fact if you are on the same plane of existence. If you are on a different plane, it returns to the place where you bound it and remains there until the spell ends.', 'Concentration, up to 1 minute', '6cd25a19-5f47-471f-8ff0-4807adcf028e', true, false, false, true, true, 8, NULL, 'Heat Metal', 'Self (60-foot line)', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create a twisting pattern of colors in a 30-foot Cube within range. The pattern appears for a moment and vanishes. Each creature in the area who can see the pattern must succeed on a Wisdom saving throw or have the Charmed condition for the duration. While Charmed, the creature has the Incapacitated condition and a Speed of 0. The spell ends for an affected creature if it takes any damage or if someone else uses an action to shake the creature out of its stupor.', '1 hour', '04063237-3f24-43a0-af2e-c9add8cf9169', true, false, false, true, true, 1, NULL, 'See Invisibility', 'Touch', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A creature you touch has the Invisible condition until the spell ends.', 'Concentration, up to 1 minute', '79f28ed9-3b58-4be5-936d-1aa7111b76ab', false, false, true, true, true, 4, NULL, 'Dancing Lights', 'Self', 'Evocation', 'The damage increases by 1d6 for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'Until the spell ends, one willing creature you touch has Resistance to Bludgeoning, Piercing, and Slashing damage.', 'Until dispelled or triggered', '464defa7-169d-4ea3-8c60-02f65ad510d4', false, true, false, true, true, 1, 'rare inks worth 50+ GP, which the spell consumes', 'Geas', 'Self', 'Abjuration', 'Both types of damage increase by 1d8 for each spell slot level above 6.', '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'You create an illusion of an object, a creature, or some other visible phenomenon within range that activates when a specific trigger occurs. The illusion is imperceptible until then. It must be no larger than a 30-foot Cube, and you decide when you cast the spell how the illusion behaves and what sounds it makes. This scripted performance can last up to 5 minutes. When the trigger you specify occurs, the illusion springs into existence and performs in the manner you described. Once the illusion finishes performing, it disappears and remains dormant for 10 minutes, after which the illusion can be activated again. The trigger can be as general or as detailed as you like, though it must be based on visual or audible phenomena that occur within 30 feet of the area. For example, you could create an illusion of yourself to appear and warn off others who attempt to open a trapped door. Physical interaction with the image reveals it to be illusory, since things can pass through it. A creature that takes the Study action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and any noise it makes sounds hollow to the creature.', 'Concentration, up to 1 hour', '1c796490-51ca-45b4-917a-bf49173977b1', false, true, false, true, true, 6, 'a diamond worth 5,000+ GP', 'Summon Beast', '500 miles', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'A wall of water springs into existence at a point you choose within range. You can make the wall up to 300 feet long, 300 feet high, and 50 feet thick. The wall lasts for the duration. When the wall appears, each creature in its area makes a Strength saving throw, taking 6d10 Bludgeoning damage on a failed save or half as much damage on a successful one. At the start of each of your turns after the wall appears, the wall, along with any creatures in it, moves 50 feet away from you. Any Huge or smaller creature inside the wall or whose space the wall enters when it moves must succeed on a Strength saving throw or take 5d10 Bludgeoning damage. A creature can take this damage only once per round. At the end of the turn, the wall’s height is reduced by 50 feet, and the damage the wall deals on later rounds is reduced by 1d10. When the wall reaches 0 feet in height, the spell ends. A creature caught in the wall can move by swimming. Because of the wave’s force, though, the creature must succeed on a Strength (Athletics) check against your spell save DC to move at all. If it fails the check, it can’t move. A creature that moves out of the wall falls to the ground.', 'Instantaneous', '8b170320-828f-48f9-aa6c-b59dcf1e6de8', false, true, false, true, true, 3, NULL, 'Power Word Fortify', '60 feet', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A creature you touch becomes Invisible. The spell ends early if the target attacks or casts a spell.', 'Instantaneous', '6e3e86f2-c623-4991-83a5-e11eddb1f806', false, false, false, true, true, 5, 'incense and diamond dust worth 200 GP', 'Water Walk', 'Touch', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Until the spell ends, one willing creature you touch is protected against creatures that are Aberrations, Celestials, Elementals, Fey, Fiends, or Undead. The protection grants several benefits. Creatures of those types have Disadvantage on attack rolls against the target. The target also can’t be possessed by or gain the Charmed or Frightened conditions from them. If the target is already possessed, Charmed, or Frightened by such a creature, the target has Advantage on any new saving throw against the relevant effect.', 'Concentration, up to 1 hour', '973e7912-587c-4da4-a2a5-6e40ae52e246', false, false, false, false, true, 1, 'dust and water', 'Holy Aura', 'Self', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You infuse an area with holy or unholy power. Celestials, Elementals, Fey, Fiends, and Undead cannot enter. You can also add a secondary effect like Courage, Darkness, or Energy Vulnerability.', 'Concentration, up to 10 minutes', '30de6e37-2eef-4014-8e3c-1e3328979d00', true, true, false, true, true, 3, 'jade dust worth 25+ GP', 'Vitriolic Sphere', 'Self', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A creature of your choice that you can see regains HP equal to 1d4 + your spellcasting ability modifier.', 'Concentration, up to 10 minutes', 'df492a81-5d2c-425d-b19c-bb75066fea97', true, true, false, true, true, 4, 'pork rind or butter', 'Tongues', 'Special', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A vertical column of divine fire roars down from the heavens. Each creature in a 10-foot-radius, 40-foot-high Cylinder takes 4d6 Fire damage and 4d6 Radiant damage (Dex save for half).', 'Instantaneous', '9d5d672d-f1bb-4280-b332-ed066ad60c91', true, false, false, true, true, 1, 'a sunburst token', 'Detect Magic', '30 feet', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action (Overgrowth) or 8 hours (Enrichment)', '2026-05-15 05:45:35.483105+00', 'You shape a creature''s dreams. You or a messenger appears in the dreams of a target you know and can converse with it as long as it is asleep.', 'Concentration, up to 10 minutes', 'bca76339-fead-4d88-99f6-2f461a39201a', false, true, false, true, true, 1, NULL, 'Word of Recall', 'Self', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You unleash a wave of thunderous energy. Each creature in a 15-foot Cube originating from you makes a Constitution saving throw. On a failed save, a creature takes 2d8 Thunder damage and is pushed 10 feet away from you. On a successful save, a creature takes half as much damage only. In addition, unsecured objects that are entirely within the Cube are pushed 10 feet away from you, and a thunderous boom is audible within 300 feet.', 'Concentration, up to 1 minute', '2b2b5145-f7b3-40ef-aa9e-0933f70fdcea', false, true, false, true, true, 7, 'a glass bead', 'Ice Storm', '150 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('10 minutes', '2026-05-15 05:45:35.483105+00', 'A wall of water springs into existence at a point you choose within range. You can make the wall up to 300 feet long, 300 feet high, and 50 feet thick. The wall lasts for the duration. When the wall appears, each creature in its area makes a Strength saving throw, taking 6d10 Bludgeoning damage on a failed save or half as much damage on a successful one. At the start of each of your turns after the wall appears, the wall, along with any creatures in it, moves 50 feet away from you. Any Huge or smaller creature inside the wall or whose space the wall enters when it moves must succeed on a Strength saving throw or take 5d10 Bludgeoning damage. A creature can take this damage only once per round. At the end of the turn, the wall’s height is reduced by 50 feet, and the damage the wall deals on later rounds is reduced by 1d10. When the wall reaches 0 feet in height, the spell ends. A creature caught in the wall can move by swimming. Because of the wave’s force, though, the creature must succeed on a Strength (Athletics) check against your spell save DC to move at all. If it fails the check, it can’t move. A creature that moves out of the wall falls to the ground.', '1 round', '1f6be425-ea1a-42f9-ae4d-027b708b71b4', true, false, false, true, true, 5, 'a piece of cork', 'Tasha’s Hideous Laughter', '120 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You strike the ground, creating a shockwave in a 30-foot Emanation. Each creature of your choice takes 5d6 Thunder damage and 5d6 Radiant or Necrotic damage and is knocked Prone (Con save for half).', '24 hours', 'e24fb287-ebf6-4669-9725-83145ab556f9', true, false, false, true, true, 2, NULL, 'Vitriolic Sphere', '30 feet', 'Necromancy', 'You can target one additional creature for each spell slot level above 5.', '2026-05-15 05:45:35.483105+00'),
	('10 minutes', '2026-05-15 05:45:35.483105+00', 'For the duration, no sound can be created within or pass through a 20-foot-radius Sphere centered on a point you choose within range. Any creature or object entirely inside the Sphere has Immunity to Thunder damage, and creatures have the Deafened condition while entirely inside it. Casting a spell that includes a Verbal component is impossible there.', 'Concentration, up to 1 hour', '7d2dab3b-9b73-4b9c-aaa1-65856f1db732', false, true, false, true, true, 7, 'mistletoe', 'Time Stop', '60 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Choose a creature you can see. It must succeed on a WIS save or be Paralyzed. It repeats the save at the end of each of its turns.', 'Concentration, up to 1 minute', '3c5216ed-af6e-4582-853a-fa5c646875bd', false, false, false, false, false, 9, NULL, 'Hallow', 'Touch', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 minute', '2026-05-15 05:45:35.483105+00', 'You attempt to beguile a Beast. It makes a Wisdom save or has the Charmed condition. While Charmed, you have a telepathic link and can issue commands.', 'Instantaneous', 'e9db7ae5-7f9a-48e0-99fa-cfa06b168726', true, false, false, true, true, 6, 'a glass sphere', 'Harm', '120 feet', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'Choose a creature that you can see within range. Positive energy washes through the target, restoring 70 Hit Points. This spell also ends the Blinded, Deafened, and Poisoned conditions on the target.', 'Concentration, up to 1 minute', '6595174d-3fd9-42f4-9d43-29b7458ecc8f', true, false, false, true, false, 2, 'a gilded skull worth 300+ GP', 'Heroism', 'Self', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You project a phantasmal image of a creature''s worst fears in a 60-foot Cone. Each creature in the area must succeed on a Wisdom save or have the Frightened condition.', 'Instantaneous', '5c0434e2-8aa4-4d91-99ff-87a6b1a79bc2', true, false, false, false, true, 5, 'a glass sphere', 'Stone Shape', 'Self', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('10 minutes', '2026-05-15 05:45:35.483105+00', 'You touch a creature and magically remove one of the following effects from it: 1 Exhaustion level The Charmed or Petrified condition A curse, including the target’s Attunement to a cursed magic item Any reduction to one of the target’s ability scores Any reduction to the target’s Hit Point maximum', '24 hours', 'e5c4129f-f367-46cd-86df-cc318fe90d3b', true, false, false, true, true, 1, 'incense and a sacrificial offering appropriate to your religion, together worth 25+ GP, which the spell consumes', 'Levitate', '30 feet', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 minute', '2026-05-15 05:45:35.483105+00', 'You touch an object or creature to learn its magical properties, how to use them, whether it requires Attunement, and how many charges it has. (Note: Identify now takes 1 minute by default in 2024).', 'Instantaneous', '4a30be56-40d7-45d9-8ecf-23a44bbe690e', false, false, false, true, true, 6, NULL, 'Destructive Wave', 'Touch', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'For the duration, you sense the presence of magic within 30 feet of you. You can take a Magic action to see a faint aura around visible creatures or objects that bear magic.', '10 minutes', '9b53a868-e426-4ec0-94dd-7224349546de', false, false, false, true, true, 3, 'a speck of glass or crystal', 'False Life', '10 feet', 'Conjuration', 'You can target one additional creature for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A frigid globe streaks from you to a point of your choice within range, where it explodes in a 60-foot-radius Sphere. Each creature in that area makes a Constitution saving throw, taking 10d6 Cold damage on a failed save or half as much damage on a successful one. If the globe strikes a body of water, it freezes the water to a depth of 6 inches over an area 30 feet square. This ice lasts for 1 minute. Creatures that were swimming on the surface of frozen water are trapped in the ice and have the Restrained condition. A trapped creature can take an action to make a Strength (Athletics) check against your spell save DC to break free. You can refrain from firing the globe after completing the spell’s casting. If you do so, a globe about the size of a sling bullet, cool to the touch, appears in your hand. At any time, you or a creature you give the globe to can throw the globe (to a range of 40 feet) or hurl it with a sling (to the sling’s normal range). It shatters on impact, with the same effect as a normal casting of the spell. You can also set the globe down without shattering it. After 1 minute, if the globe hasn’t already shattered, it explodes.', 'Instantaneous', '2faf7fb8-5e23-4719-bd1b-e9641d2fda80', true, false, false, false, true, 0, NULL, 'Fear', 'Self', 'Transmutation', 'Use the spell slot’s level for the spell’s level in the stat block.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You flourish the weapon used in the casting and then vanish to strike like the wind. Choose up to five creatures you can see within range. Make a melee spell attack against each target. On a hit, a target takes 6d10 Force damage. You then teleport to an unoccupied space you can see within 5 feet of one of the targets.', '24 hours', 'b0c4a92b-120b-489a-bd48-0d9d6b58007c', false, true, false, true, true, 1, 'a bit of fleece', 'Heat Metal', 'Touch', 'Abjuration', 'You can target one additional creature for each spell slot level above 3.', '2026-05-15 05:45:35.483105+00'),
	('Reaction, which you take in response to taking damage from a creature that you can see within 60 feet of yourself', '2026-05-15 05:45:35.483105+00', 'A bright streak flashes from your pointing finger to a point within range and then blossoms with a low roar into an explosion of flame. Creatures take 8d6 Fire damage (Dex save for half).', '8 hours', '780c98fd-817d-4b42-96bc-1cd02cbfd47c', false, true, false, true, true, 1, 'a piece of sunstone', 'Tasha’s Hideous Laughter', 'Self', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch a creature. The target’s Speed increases by 10 feet until the spell ends.', '8 hours', '8312efd5-668a-42e0-8811-11517dc47258', false, true, false, true, true, 7, 'a drop of molasses', 'Thunderwave', 'Self', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'With a touch, you revive a dead creature if it has been dead no longer than 10 days and it wasn’t Undead when it died. The creature returns to life with 1 Hit Point. This spell also neutralizes any poisons that affected the creature at the time of death. This spell closes all mortal wounds, but it doesn’t restore missing body parts. If the creature is lacking body parts or organs integral for its survival—its head, for instance—the spell automatically fails. Coming back from the dead is an ordeal. The target takes a -4 penalty to d20 Tests. Every time the target finishes a Long Rest, the penalty is reduced by 1 until it becomes 0.', 'Instantaneous', 'fc66ed06-ec88-4503-8b40-9ebf0216183f', false, true, false, true, true, 4, 'a tart and a feather', 'Guardian of Faith', '60 feet', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Describe or name a creature that is familiar to you. You sense the direction to the creature’s location if that creature is within 1,000 feet of you. If the creature is moving, you know the direction of its movement. The spell can locate a specific creature known to you or the nearest creature of a specific kind (such as a human or a unicorn) if you have seen such a creature up close—within 30 feet—at least once. If the creature you described or named is in a different form, such as under the effects of a Flesh to Stone or Polymorph spell, this spell doesn’t locate the creature. This spell can’t locate a creature if any thickness of lead blocks a direct path between you and the creature.', 'Instantaneous', 'cf10eab7-9565-4c1b-99d1-9dd9e3994941', true, true, false, true, true, 5, 'a pickled tentacle and an eyeball in a platinum-inlaid vial worth 400+ GP', 'Rope Trick', 'Touch', 'Illusion', 'You automatically end the effects of a spell on the target if the spell’s level is equal to or less than the level of the spell slot used.', '2026-05-15 05:45:35.483105+00'),
	('1 minute', '2026-05-15 05:45:35.483105+00', 'You create a twisting pattern of colors in a 30-foot Cube within range. The pattern appears for a moment and vanishes. Each creature in the area who can see the pattern must succeed on a Wisdom saving throw or have the Charmed condition for the duration. While Charmed, the creature has the Incapacitated condition and a Speed of 0. The spell ends for an affected creature if it takes any damage or if someone else uses an action to shake the creature out of its stupor.', 'Concentration, up to 1 minute', '6f1d2c12-7960-48c3-8769-58118b917eff', false, true, false, false, true, 5, NULL, 'Heroism', '30 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Describe or name a creature that is familiar to you. You sense the direction to the creature’s location if that creature is within 1,000 feet of you. If the creature is moving, you know the direction of its movement. The spell can locate a specific creature known to you or the nearest creature of a specific kind (such as a human or a unicorn) if you have seen such a creature up close—within 30 feet—at least once. If the creature you described or named is in a different form, such as under the effects of a Flesh to Stone or Polymorph spell, this spell doesn’t locate the creature. This spell can’t locate a creature if any thickness of lead blocks a direct path between you and the creature.', '1 hour', '11863818-a22f-425b-8c78-6889ae2f6624', true, false, false, true, true, 2, 'a statuette of yourself worth 5+ GP', 'Magic Weapon', '90 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create a vine-like whip covered in thorns that lashes out at your command toward a creature in range. Make a melee spell attack against the target. On a hit, the target takes 1d6 Piercing damage, and if it is Large or smaller, you can pull it up to 10 feet closer to you. Cantrip Upgrade. The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).', 'Concentration, up to 1 hour', '908af1cb-b3c1-4082-927b-6e1c440b2ac8', false, true, false, true, true, 1, 'a chest, 3 feet by 2 feet by 2 feet, constructed from rare materials worth 5,000+ GP, and a Tiny replica of the chest made from the same materials worth 50+ GP', 'Otiluke’s Freezing Sphere', 'Touch', 'Abjuration', 'The damage increases by 1d6 for each spell slot level above 6.', '2026-05-15 05:45:35.483105+00'),
	('1 minute', '2026-05-15 05:45:35.483105+00', 'You conjure a portal linking an unoccupied space you can see within range to a precise location on a different plane of existence. The portal is a circular opening, which you can make 5 to 20 feet in diameter. You can orient the portal in any direction you choose. The portal lasts for the duration, and the portal’s destination is visible through it. The portal has a front and a back on each plane where it appears. Travel through the portal is possible only by moving through its front. Anything that does so is instantly transported to the other plane, appearing in the unoccupied space nearest to the portal. Deities and other planar rulers can prevent portals created by this spell from opening in their presence or anywhere within their domains. When you cast this spell, you can speak the name of a specific creature (a pseudonym, title, or nickname doesn’t work). If that creature is on a plane other than the one you are on, the portal opens next to the named creature and transports it to the nearest unoccupied space on your side of the portal. You gain no special power over the creature, and it is free to act as the DM deems appropriate. It might leave, attack you, or help you.', 'Concentration, up to 10 minutes', '48668c46-930d-440f-bfdb-b302dbbd7a38', true, true, false, true, true, 3, 'mushroom powder worth 25+ GP, which the spell consumes', 'Ice Knife', '60 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Hail falls in a 20-foot-radius, 40-foot-high cylinder. Creatures take 2d8 Bludgeoning and 4d6 Cold damage (DEX save for half). The area becomes difficult terrain until the end of your next turn.', 'Concentration, up to 1 minute', '767041eb-29a9-46c3-bc63-80c9b7f630fa', false, false, false, true, true, 3, 'a diamond worth 1,000+ GP, which the spell consumes', 'Dispel Magic', 'Touch', 'Divination', 'Use the spell slot’s level for the spell’s level in the stat block.', '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'You transform a willing creature and its gear into a misty cloud. The target has a flying speed of 10 feet, resistance to nonmagical damage, and advantage on STR, DEX, and CON saves. It can pass through small holes but cannot attack or cast spells.', '1 hour', '8e4f279f-35b1-4d0f-b7cd-022918422274', false, true, true, true, true, 1, NULL, 'Rary’s Telepathic Bond', 'Self', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You make an area within range magically secure. The area is a Cube that can be as small as 5 feet to as large as 100 feet on each side. The spell lasts for the duration. When you cast the spell, you decide what sort of security the spell provides, choosing any of the following properties: Sound can’t pass through the barrier at the edge of the warded area. The barrier of the warded area appears dark and foggy, preventing vision (including Darkvision) through it. Sensors created by Divination spells can’t appear inside the protected area or pass through the barrier at its perimeter. Creatures in the area can’t be targeted by Divination spells. Nothing can teleport into or out of the warded area. Planar travel is blocked within the warded area. Casting this spell on the same spot every day for 365 days makes the spell last until dispelled.', '1 hour', '67882e7c-3f4c-40b0-838b-4efa704128a2', false, true, false, true, true, 2, '2 Copper Pieces, which the spell consumes', 'Fear', '60 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('10 minutes', '2026-05-15 05:45:35.483105+00', 'You have Advantage on Charisma checks directed at one non-hostile creature. When the spell ends, the creature realizes you used magic to influence it and may become hostile.', 'Concentration, up to 10 minutes', '4a137e20-c91d-4759-b843-005291bf6957', false, false, false, false, true, 6, NULL, 'Otto’s Irresistible Dance', 'Touch', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'You inscribe a harmful glyph either on a surface (such as a section of floor or wall) or within an object that can be closed (such as a book or chest). The glyph can cover an area no larger than 10 feet in diameter. If you choose an object, it must remain in place; if it is moved more than 10 feet from where you cast this spell, the glyph is broken, and the spell ends without being triggered. The glyph is nearly imperceptible and requires a successful Wisdom (Perception) check against your spell save DC to notice. When you inscribe the glyph, you set its trigger and choose which effect the symbol bears: Death, Discord, Fear, Pain, Sleep, or Stunning. Each one is explained below. Set the Trigger. You decide what triggers the glyph when you cast the spell. For glyphs inscribed on a surface, common triggers include touching or stepping on the glyph, removing another object covering it, or approaching within a certain distance of it. For glyphs inscribed within an object, common triggers include opening that object or seeing the glyph. You can refine the trigger so that only creatures of certain types activate it (for example, the glyph could be set to affect Aberrations). You can also set conditions for creatures that don’t trigger the glyph, such as those who say a certain password. Once triggered, the glyph glows, filling a 60-foot-radius Sphere with Dim Light for 10 minutes, after which time the spell ends. Each creature in the Sphere when the glyph activates is targeted by its effect, as is a creature that enters the Sphere for the first time on a turn or ends its turn there. A creature is targeted only once per turn. Death. Each target makes a Constitution saving throw, taking 10d10 Necrotic damage on a failed save or half as much damage on a successful save. Discord. Each target makes a Wisdom saving throw. On a failed save, a target argues with other creatures for 1 minute. During this time, it is incapable of meaningful communication and has Disadvantage on attack rolls and ability checks. Fear. Each target must succeed on a Wisdom saving throw or have the Frightened condition for 1 minute. While Frightened, the target must move at least 30 feet away from the glyph on each of its turns, if able. Pain. Each target must succeed on a Constitution saving throw or have the Incapacitated condition for 1 minute. Sleep. Each target must succeed on a Wisdom saving throw or have the Unconscious condition for 10 minutes. A creature awakens if it takes damage or if someone takes an action to shake it awake. Stunning. Each target must succeed on a Wisdom saving throw or have the Stunned condition for 1 minute.', 'Concentration, up to 1 hour', '92118c7a-d8a6-4a12-8625-9807e2ac90a8', false, true, false, true, true, 5, NULL, 'Gate', 'Self', 'Conjuration', 'The damage increases by 1d10 for each spell slot level above 5.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A willing creature is immune to being Frightened and gains Temporary HP equal to your spellcasting ability modifier at the start of each of its turns.', 'Concentration, up to 10 minutes', 'c130ebce-5a07-4587-ad20-7fb5ef559635', true, false, false, true, true, 1, 'mushroom powder worth 25+ GP, which the spell consumes', 'Guidance', 'Touch', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Your strike rings with thunder that is audible within 300 feet of you, and the target takes an extra 2d6 Thunder damage from the attack. Additionally, if the target is a creature, it must succeed on a Strength saving throw or be pushed 10 feet away from you and have the Prone condition.', 'Instantaneous', '625c43df-d2d1-49ba-87ad-4366ceecde84', false, true, false, true, true, 0, 'a pinch of sulfur', 'Meld into Stone', '30 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You attempt to beguile a Humanoid. It makes a Wisdom save or has the Charmed condition. While Charmed, you have a telepathic link and can issue commands.', 'Concentration, up to 1 minute', 'af2392a4-0207-4468-8cdb-c75f46d7ab53', false, true, false, true, true, 1, NULL, 'Swift Quiver', 'Touch', 'Conjuration', 'The healing increases by 10 for each spell slot level above 6.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You weave a distracting string of words. Each creature of your choice within range makes a Wisdom save. On failure, it has Disadvantage on Wisdom (Perception) checks to notice anyone other than you.', 'Concentration, up to 1 hour', 'e1225e35-ece8-4ef6-ba06-e9597bc12513', true, true, false, true, true, 1, 'air, a pebble, ash, and water inside a gold-inlaid vial worth 400+ GP', 'Ice Knife', 'Self', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 hour', '2026-05-15 05:45:35.483105+00', 'You create a seismic disturbance. The ground shakes, structures take damage, and creatures make saves to avoid being knocked Prone or trapped in fissures.', 'Instantaneous', '7f9ba33c-6356-462b-a630-3d29eacbf328', false, false, false, true, true, 3, 'iron bar', 'Mage Hand', 'Self', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A wave of healing energy washes out from a point you can see within range. Choose up to six creatures in a 30-foot-radius Sphere centered on that point. Each target regains Hit Points equal to 5d8 plus your spellcasting ability modifier.', 'Instantaneous', 'a1a65d5b-0328-464a-8517-930a5dd9d049', false, false, false, true, true, 3, NULL, 'Gust of Wind', '150 feet', 'Transmutation', 'The damage increases by 1d8 for each spell slot level above 2.', '2026-05-15 05:45:35.483105+00'),
	('10 minutes', '2026-05-15 05:45:35.483105+00', 'A frigid globe streaks from you to a point of your choice within range, where it explodes in a 60-foot-radius Sphere. Each creature in that area makes a Constitution saving throw, taking 10d6 Cold damage on a failed save or half as much damage on a successful one. If the globe strikes a body of water, it freezes the water to a depth of 6 inches over an area 30 feet square. This ice lasts for 1 minute. Creatures that were swimming on the surface of frozen water are trapped in the ice and have the Restrained condition. A trapped creature can take an action to make a Strength (Athletics) check against your spell save DC to break free. You can refrain from firing the globe after completing the spell’s casting. If you do so, a globe about the size of a sling bullet, cool to the touch, appears in your hand. At any time, you or a creature you give the globe to can throw the globe (to a range of 40 feet) or hurl it with a sling (to the sling’s normal range). It shatters on impact, with the same effect as a normal casting of the spell. You can also set the globe down without shattering it. After 1 minute, if the globe hasn’t already shattered, it explodes.', '8 hours', 'e9074a7e-8637-4615-b1fa-e1e556338b60', false, false, false, true, true, 1, NULL, 'Giant Insect', '60 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 minute', '2026-05-15 05:45:35.483105+00', 'A passage appears at a point that you can see on a wooden, plaster, or stone surface (such as a wall, ceiling, or floor) within range and lasts for the duration. You choose the opening’s dimensions: up to 5 feet wide, 8 feet tall, and 20 feet deep. The passage creates no instability in a structure surrounding it. When the opening disappears, any creatures or objects still in the passage created by the spell are safely ejected to an unoccupied space nearest to the surface on which you cast the spell.', '1 hour', '8eed0bcf-730d-4271-bf0a-bb67e20a246f', false, false, false, false, true, 7, 'a pinch of powdered iron', 'Water Walk', '60 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch a corpse to protect it from decay and prevent it from becoming Undead. The duration doesn’t count against the time limit of spells like Raise Dead or Revivify.', 'Concentration, up to 1 minute', 'd098be4e-eb18-450c-b31d-d00ce3ba090d', true, true, false, false, true, 3, 'powdered ruby worth 1,500+ GP, which the spell consumes', 'Floating Disk', '60 feet', 'Transmutation', 'Use the spell slot’s level for the spell’s level in the stat block.', '2026-05-15 05:45:35.483105+00'),
	('10 minutes', '2026-05-15 05:45:35.483105+00', 'You open a gateway to the Far Realm, a region infested with unspeakable horrors. A 20-foot-radius Sphere of Darkness appears, centered on a point with range and lasting for the duration. The Sphere is Difficult Terrain, and it is filled with strange whispers and slurping noises, which can be heard up to 30 feet away. No light, magical or otherwise, can illuminate the area, and creatures fully within it have the Blinded condition. Any creature that starts its turn in the area takes 2d6 Cold damage. Any creature that ends its turn there must succeed on a Dexterity saving throw or take 2d6 Acid damage from otherworldly tentacles.', 'Concentration, up to 1 minute', '6272cc4b-9097-429c-8e17-e9d4b855901d', false, false, false, false, true, 1, 'lead-based ink worth 10 GP', 'Mass Cure Wounds', 'Self (30-foot Emanation)', 'Evocation', 'The healing increases by 2d4 for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('1 minute or Ritual', '2026-05-15 05:45:35.483105+00', 'The creature that damaged you is momentarily surrounded by green flames. It makes a Dexterity saving throw, taking 2d10 Fire damage on a failed save or half as much damage on a successful one.', 'Instantaneous', '3fcedaa5-e756-47d2-ad7f-44d34cd8cc62', false, false, false, true, true, 5, 'a yew leaf', 'Incendiary Cloud', '60 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You call forth a Dragon spirit. It manifests in an unoccupied space that you can see within range and uses the Draconic Spirit stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends. The creature is an ally to you and your allies. In combat, the creature shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the Dodge action and uses its movement to avoid danger. Draconic Spirit Large Dragon, Neutral AC 14 + the spell’s level HP 50 + 10 for each spell level above 5 Speed 30 ft., Fly 60 ft., Swim 30 ft. Mod Save STR 19 +4 +4 DEX 14 +2 +2 CON 17 +3 +3 Mod Save INT 10 +0 +0 WIS 14 +2 +2 CHA 14 +2 +2 Resistances Acid, Cold, Fire, Lightning, Poison Immunities Charmed, Frightened, Poisoned Senses Blindsight 30 ft., Darkvision 60 ft.; Passive Perception 12 Languages Draconic, understands the languages you know CR None (XP 0; PB equals your Proficiency Bonus) Traits Shared Resistances. When you summon the spirit, choose one of its Resistances. You have Resistance to the chosen damage type until the spell ends. Actions Multiattack. The spirit makes a number of Rend attacks equal to half the spell’s level (round down), and it uses Breath Weapon. Rend. Melee Attack Roll: Bonus equals your spell attack modifier, reach 10 feet. Hit: 1d6 + 4 + the spell’s level Piercing damage. Breath Weapon. Dexterity Saving Throw: DC equals your spell save DC, each creature in a 30-foot Cone. Failure: 2d6 damage of a type this spirit has Resistance to (your choice when you cast the spell). Success: Half damage.', 'Concentration, up to 1 minute', 'd2b8571f-d251-4cb6-a98b-b08546293200', true, true, false, true, true, 5, 'a statuette of the target worth 5,000+ GP', 'Fire Storm', '30 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'For the duration, you can sense the presence and location of poisons, poisonous creatures, and diseases within 30 feet of you.', 'Instantaneous', '69d6edd1-1e32-4f7e-9c0c-f6294fb762e2', false, true, false, false, true, 5, 'powdered diamond worth 1,000+ GP, which the spell consumes', 'Major Image', '30 feet', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Each creature in a 5-foot Emanation originating from you must succeed on a Constitution saving throw or take 1d6 Thunder damage. The spell’s thunderous sound can be heard up to 100 feet away. Cantrip Upgrade. The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).', 'Instantaneous', 'ce0aba11-6ac0-400e-80b8-4802e3bd7804', true, false, false, true, true, 3, 'a gem-encrusted bowl worth 1,000+ GP, which the spell consumes', 'Spider Climb', 'Touch', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Until the spell ends, one willing creature you touch has Resistance to Bludgeoning, Piercing, and Slashing damage.', 'Instantaneous', '6391356d-e40c-49f8-8496-6a490d5451a9', false, true, false, false, true, 7, NULL, 'Elemental Weapon', '60 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'This spell grants the creature you touch the ability to understand any spoken or signed language that it hears or sees. Moreover, when the target communicates by speaking or signing, any creature that knows at least one language can understand it if that creature can hear the speech or see the signing.', 'Concentration, up to 1 minute', '1a9334e8-dddc-4134-86a5-33303dead27a', true, true, false, false, true, 2, 'rare oils worth 1,000+ GP, which the spell consumes', 'Locate Animals or Plants', 'Touch', 'Enchantment', 'Use the spell slot’s level for the spell’s level in the stat block.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You call forth an Undead spirit. It manifests in an unoccupied space that you can see within range and uses the Undead Spirit stat block. When you cast the spell, choose the creature’s form: Ghostly, Putrid, or Skeletal. The spirit resembles an Undead creature with the chosen form, which determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends. The creature is an ally to you and your allies. In combat, the creature shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the Dodge action and uses its movement to avoid danger. Undead Spirit Medium Undead, Neutral AC 11 + the spell’s level HP 30 (Ghostly and Putrid only) or 20 (Skeletal only) + 10 for each spell level above 3 Speed 30 ft.; Fly 40 ft. (hover; Ghostly only) Mod Save STR 12 +1 +1 DEX 16 +3 +3 CON 15 +2 +2 Mod Save INT 4 -3 -3 WIS 10 +0 +0 CHA 9 -1 -1 Immunities Necrotic, Poison; Exhaustion, Frightened, Paralyzed, Poisoned Senses Darkvision 60 ft.; Passive Perception 10 Languages Understands the languages you know CR None (XP 0; PB equals your Proficiency Bonus) Traits Festering Aura (Putrid Only). Constitution Saving Throw: DC equals your spell save DC, any creature (other than you) that starts its turn within a 5-foot Emanation originating from the spirit. Failure: The creature has the Poisoned condition until the start of its next turn. Incorporeal Passage (Ghostly Only). The spirit can move through other creatures and objects as if they were Difficult Terrain. If it ends its turn inside an object, it is shunted to the nearest unoccupied space and takes 1d10 Force damage for every 5 feet traveled. Actions Multiattack. The spirit makes a number of attacks equal to half this spell’s level (round down). Deathly Touch (Ghostly Only). Melee Attack Roll: Bonus equals your spell attack modifier, reach 5 ft. Hit: 1d8 + 3 + the spell’s level Necrotic damage, and the target has the Frightened condition until the end of its next turn. Grave Bolt (Skeletal Only). Ranged Attack Roll: Bonus equals your spell attack modifier, range 150 ft. Hit: 2d4 + 3 + the spell’s level Necrotic damage. Rotting Claw (Putrid Only). Melee Attack Roll: Bonus equals your spell attack modifier, reach 5 ft. Hit: 1d6 + 3 + the spell’s level Slashing damage. If the target has the Poisoned condition, it has the Paralyzed condition until the end of its next turn.', '8 hours', '185dc40f-95d6-40ca-90dd-eb7ff409ed5a', false, true, false, true, true, 2, NULL, 'Mass Cure Wounds', 'Self', 'Evocation', 'You can target one additional creature for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Bonus Action, which you take immediately after hitting a creature with a Melee weapon or an Unarmed Strike', '2026-05-15 05:45:35.483105+00', 'You create a 10-foot-radius, 20-foot-tall Cylinder of magical energy centered on a point on the ground that you can see within range. Glowing runes appear wherever the Cylinder intersects with the floor or other surface. Choose one or more of the following types of creatures: Celestials, Elementals, Fey, Fiends, or Undead. The circle affects a creature of the chosen type in the following ways: The creature can’t willingly enter the Cylinder by nonmagical means. If the creature tries to use teleportation or interplanar travel to do so, it must first succeed on a Charisma saving throw. The creature has Disadvantage on attack rolls against targets within the Cylinder. Targets within the Cylinder can’t be possessed by or gain the Charmed or Frightened condition from the creature. Each time you cast this spell, you can cause its magic to operate in the reverse direction, preventing a creature of the specified type from leaving the Cylinder and protecting targets outside it.', 'Concentration, up to 10 minutes', '5bcf5858-4f1c-4f61-be45-c912cd1a1be3', false, false, true, true, true, 5, NULL, 'Sanctuary', '60 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You attempt to turn a creature you can see into stone. The target makes a Constitution save. On three failures, it has the Petrified condition. On three successes, the spell ends.', 'Concentration, up to 1 minute', '25547344-8a26-4dc7-959b-dda89c039737', false, true, false, true, true, 5, 'a short reed', 'Heroes'' Feast', 'Self', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You have Advantage on Charisma checks directed at one non-hostile creature. When the spell ends, the creature realizes you used magic to influence it and may become hostile.', 'Concentration, up to 1 minute', '4cb5ca4e-bcd6-4937-9877-f45984843485', false, true, false, true, true, 1, 'a jewel worth 1,000+ GP, which the spell consumes', 'Telekinesis', 'Self', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 minute', '2026-05-15 05:45:35.483105+00', 'You create a magical zone that guards against deception in a 15-foot-radius Sphere centered on a point within range. Until the spell ends, a creature that enters the spell’s area for the first time on a turn or starts its turn there makes a Charisma saving throw. On a failed save, a creature can’t speak a deliberate lie while in the radius. You know whether a creature succeeds or fails on this save. An affected creature is aware of the spell and can avoid answering questions to which it would normally respond with a lie. Such a creature can be evasive yet must be truthful.', 'Instantaneous', 'e2833c6c-216a-401a-94d7-654aa702b701', true, true, false, false, false, 6, NULL, 'Gust of Wind', 'Self', 'Conjuration', 'The damage increases by 1d8 for each spell slot level above 2.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You make an area within range magically secure. The area is a Cube that can be as small as 5 feet to as large as 100 feet on each side. The spell lasts for the duration. When you cast the spell, you decide what sort of security the spell provides, choosing any of the following properties: Sound can’t pass through the barrier at the edge of the warded area. The barrier of the warded area appears dark and foggy, preventing vision (including Darkvision) through it. Sensors created by Divination spells can’t appear inside the protected area or pass through the barrier at its perimeter. Creatures in the area can’t be targeted by Divination spells. Nothing can teleport into or out of the warded area. Planar travel is blocked within the warded area. Casting this spell on the same spot every day for 365 days makes the spell last until dispelled.', 'Concentration, up to 10 minutes', 'aade3990-370f-4e40-8da7-e95df342e778', false, true, true, true, true, 3, NULL, 'Wall of Force', 'Touch', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 minute', '2026-05-15 05:45:35.483105+00', 'A frigid beam of blue-white light streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, it takes 1d8 Cold damage, and its Speed is reduced by 10 feet until the start of your next turn. Cantrip Upgrade. The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).', 'Concentration, up to 1 hour', '3af65b9e-1cfb-4568-b7a5-1e49241dbab3', true, false, false, true, true, 2, 'rare inks worth 50+ GP, which the spell consumes', 'Hunter’s Mark', 'Self', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You surround yourself with unearthly majesty in a 10-foot Emanation. Whenever the Emanation enters the space of a creature you can see and whenever a creature you can see enters the Emanation or ends its turn there, you can force that creature to make a Wisdom saving throw. On a failed save, the target takes 4d6 Psychic damage and has the Prone condition, and you can push it up to 10 feet away. On a successful save, the target takes half as much damage only. A creature makes this save only once per turn.', '10 minutes', '7363a7f1-7056-40b2-a85c-07519c13ca13', false, true, true, true, false, 2, 'a mushroom', 'Dispel Magic', 'Touch', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Choose up to three creatures within range. Each target’s Hit Point maximum and current Hit Points increase by 5 for the duration.', 'Concentration, up to 1 hour', '4a49c5bd-0a73-4740-812f-4e029224063d', true, false, false, true, true, 7, NULL, 'Power Word Heal', '150 feet', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You reduce the target''s Exhaustion level by one or end one of the following: Charmed, Petrified, a curse, an ability score reduction, or a maximum HP reduction.', 'Concentration, up to 1 minute', '3cfed935-4379-4583-b779-fbde3bd396d3', true, false, false, true, true, 1, 'salt and copper pieces', 'Find Greater Steed', '60 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'Ten berries appear in your hand and are infused with magic for the duration. A creature can take a Bonus Action to eat one berry. Eating a berry restores 1 Hit Point, and the berry provides enough nourishment to sustain a creature for one day. Uneaten berries disappear when the spell ends.', 'Instantaneous', '90079e78-84ed-43ac-894a-13f7e5a08967', false, false, false, false, true, 5, 'a crystal bead', 'Nystul’s Magic Aura', 'Self', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('10 minutes', '2026-05-15 05:45:35.483105+00', 'You attempt to reshape another creature’s memories. One creature that you can see within range makes a Wisdom saving throw. If you are fighting the creature, it has Advantage on the save. On a failed save, the target has the Charmed condition for the duration. While Charmed in this way, the target also has the Incapacitated condition and is unaware of its surroundings, though it can hear you. If it takes any damage or is targeted by another spell, this spell ends, and no memories are modified. While this charm lasts, you can affect the target’s memory of an event that it experienced within the last 24 hours and that lasted no more than 10 minutes. You can permanently eliminate all memory of the event, allow the target to recall the event with perfect clarity, change its memory of the event’s details, or create a memory of some other event. You must speak to the target to describe how its memories are affected, and it must be able to understand your language for the modified memories to take root. Its mind fills in any gaps in the details of your description. If the spell ends before you finish describing the modified memories, the creature’s memory isn’t altered. Otherwise, the modified memories take hold when the spell ends. A modified memory doesn’t necessarily affect how a creature behaves, particularly if the memory contradicts the creature’s natural inclinations, alignment, or beliefs. An illogical modified memory, such as a false memory of how much the creature enjoyed swimming in acid, is dismissed as a bad dream. The DM might deem a modified memory too nonsensical to affect a creature. A Remove Curse or Greater Restoration spell cast on the target restores the creature’s true memory.', 'Up to 1 hour', 'ee382a54-d6b1-4316-996e-2113b6342be0', false, false, true, true, true, 1, 'a glass bead', 'Summon Undead', 'Touch', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('24 hours', '2026-05-15 05:45:35.483105+00', 'Briefly surrounded by silvery mist, you teleport up to 30 feet to an unoccupied space you can see.', '10 minutes', '3259fc41-c84d-4d5c-bad1-0b3987ca8151', false, true, false, true, true, 2, NULL, 'Harm', 'Touch', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'A creature of your choice that you can see within range regains Hit Points equal to 2d4 plus your spellcasting ability modifier.', 'Instantaneous', 'e3da70fc-9575-4541-9e3a-15e812b46f68', false, false, false, true, true, 3, NULL, 'Melf’s Acid Arrow', '30 feet', 'Divination', 'The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).', '2026-05-15 05:45:35.483105+00'),
	('12 hours', '2026-05-15 05:45:35.483105+00', 'You conjure a mass of sticky webbing at a point within range. The webs fill a 20-foot Cube there for the duration. The webs are Difficult Terrain, and the area within them is Lightly Obscured. If the webs aren’t anchored between two solid masses (such as walls or trees) or layered across a floor, wall, or ceiling, the web collapses on itself, and the spell ends at the start of your next turn. Webs layered over a flat surface have a depth of 5 feet. The first time a creature enters the webs on a turn or starts its turn there, it must succeed on a Dexterity saving throw or have the Restrained condition while in the webs or until it breaks free. A creature Restrained by the webs can take an action to make a Strength (Athletics) check against your spell save DC. If it succeeds, it is no longer Restrained. The webs are flammable. Any 5-foot Cube of webs exposed to fire burns away in 1 round, dealing 2d4 Fire damage to any creature that starts its turn in the fire.', 'Concentration, up to 1 minute', 'd4c9c457-3602-4bbb-9f1d-713767dba8bf', true, false, false, true, true, 3, NULL, 'Friends', '60 feet', 'Evocation', 'The damage increases by 1d10 for each spell slot level above 2.', '2026-05-15 05:45:35.483105+00'),
	('24 hours', '2026-05-15 05:45:35.483105+00', 'A Line of strong wind 60 feet long and 10 feet wide blasts from you in a direction you choose for the duration. Each creature in the Line must succeed on a Strength saving throw or be pushed 15 feet away from you in a direction following the Line. A creature that ends its turn in the Line must make the same save. Any creature in the Line must spend 2 feet of movement for every 1 foot it moves when moving closer to you. The gust disperses gas or vapor, and it extinguishes candles and similar unprotected flames in the area. It causes protected flames, such as those of lanterns, to dance wildly and has a 50 percent chance to extinguish them. As a Bonus Action on your later turns, you can change the direction in which the Line blasts from you.', '1 hour', '0403d31f-70bc-4838-b4a2-6c4fd56c7df6', true, true, false, false, true, 2, NULL, 'Find Steed', '30 feet', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('Reaction, which you take in response to taking damage from a creature that you can see within 60 feet of yourself', '2026-05-15 05:45:35.483105+00', 'You implant a message within an object in range—a message that is uttered when a trigger condition is met. Choose an object that you can see and that isn’t being worn or carried by another creature. Then speak the message, which must be 25 words or fewer, though it can be delivered over as long as 10 minutes. Finally, determine the circumstance that will trigger the spell to deliver your message. When that trigger occurs, a magical mouth appears on the object and recites the message in your voice and at the same volume you spoke. If the object you chose has a mouth or something that looks like a mouth (for example, the mouth of a statue), the magical mouth appears there, so the words appear to come from the object’s mouth. When you cast this spell, you can have the spell end after it delivers its message, or it can remain and repeat its message whenever the trigger occurs. The trigger can be as general or as detailed as you like, though it must be based on visual or audible conditions that occur within 30 feet of the object. For example, you could instruct the mouth to speak when any creature moves within 30 feet of the object or when a silver bell rings within 30 feet of it.', 'Concentration, up to 1 minute', 'a632d7c8-a7a1-4b1d-9c02-90bfe768973f', false, true, false, true, true, 3, 'a prayer scroll', 'Darkness', '120 feet', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Burning radiance erupts from you in a 5-foot Emanation. Each creature of your choice that you can see in it must succeed on a Constitution saving throw or take 1d6 Radiant damage. Cantrip Upgrade. The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).', '8 hours', '03f260c3-b3d6-46fd-a0d8-4a15610aba93', false, true, false, true, true, 6, 'a pinch of lime, water, and earth', 'Heroism', '120 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A beam of crackling energy streaks toward a creature within range. Make a ranged spell attack. On a hit, the target takes 1d10 Force damage.', 'Concentration, up to 1 minute', 'aec9e31b-1ae8-4bdb-b0b5-0f79cd24476e', false, true, false, true, true, 5, NULL, 'Gate', '60 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'This spell creates an Invisible, mindless, shapeless, Medium force that performs simple tasks at your command until the spell ends. The servant springs into existence in an unoccupied space on the ground within range. It has AC 10, 1 Hit Point, and a Strength of 2, and it can’t attack. If it drops to 0 Hit Points, the spell ends. Once on each of your turns as a Bonus Action, you can mentally command the servant to move up to 15 feet and interact with an object. The servant can perform simple tasks that a human could do, such as fetching things, cleaning, mending, folding clothes, lighting fires, serving food, and pouring drinks. Once you give the command, the servant performs the task to the best of its ability until it completes the task, then waits for your next command. If you command the servant to perform a task that would move it more than 60 feet away from you, the spell ends.', '8 hours', '46159cf9-9cd1-4229-ba77-31c2fbd297ff', true, true, false, true, true, 1, 'diamond dust worth 100 GP', 'Hold Monster', 'Self', 'Conjuration', 'The Cold or Acid damage (your choice) increases by 1d6 for each spell slot level above 3.', '2026-05-15 05:45:35.483105+00'),
	('24 hours', '2026-05-15 05:45:35.483105+00', 'You create a tiny nature-based magical effect, such as predicting weather, making a flower bloom, or creating a sound of rustling leaves.', 'Concentration, up to 1 day', '5618ae04-8ca6-4c07-aeb6-575065a31870', false, false, false, true, true, 8, 'diamond dust worth 100+ GP, which the spell consumes', 'Dimension Door', 'Touch', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('10 minutes', '2026-05-15 05:45:35.483105+00', 'You create a magical effect within range. Choose the effect from the options below. If you cast this spell multiple times, you can have up to three of its non-instantaneous effects active at a time. Sensory Effect. You create an instantaneous, harmless sensory effect, such as a shower of sparks, a puff of wind, faint musical notes, or an odd odor. Fire Play. You instantaneously light or snuff out a candle, a torch, or a small campfire. Clean or Soil. You instantaneously clean or soil an object no larger than 1 cubic foot. Minor Sensation. You chill, warm, or flavor up to 1 cubic foot of nonliving material for 1 hour. Magic Mark. You make a color, a small mark, or a symbol appear on an object or a surface for 1 hour. Minor Creation. You create a nonmagical trinket or an illusory image that can fit in your hand. It lasts until the end of your next turn. A trinket can deal no damage and has no monetary worth.', 'Concentration, up to 1 hour', '5e5ee417-ea5b-44bb-97fb-435636ab94ac', true, true, false, true, true, 0, 'herbs, oils, and incense worth 1,000 GP', 'Stinking Cloud', 'Touch', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'The next time you hit a creature with a ranged weapon attack, thorns rain down. The target and each creature within 5 feet take 1d10 Piercing damage (DEX save for half).', 'Instantaneous', '31b037bd-d8c3-48e8-a131-90317a0ead10', false, true, false, true, true, 2, NULL, 'Find Traps', '60 feet', 'Necromancy', 'The amount of Temporary Hit Points increases by 5 for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A shimmering sphere encloses a Large or smaller creature or object within range. An unwilling creature must succeed on a Dexterity saving throw or be enclosed for the duration. Nothing—not physical objects, energy, or other spell effects—can pass through the barrier, in or out, though a creature in the sphere can breathe there. The sphere is immune to all damage, and a creature or object inside can’t be damaged by attacks or effects originating from outside, nor can a creature inside the sphere damage anything outside it. The sphere is weightless and just large enough to contain the creature or object inside. An enclosed creature can take an action to push against the sphere’s walls and thus roll the sphere at up to half the creature’s Speed. Similarly, the globe can be picked up and moved by other creatures. A Disintegrate spell targeting the globe destroys it without harming anything inside.', 'Instantaneous', '2614be26-3006-4158-802a-61fa675c483d', true, true, false, false, true, 5, 'a piece of seaweed', 'Invisibility', '60 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'The target takes an extra 1d6 Necrotic damage from the attack, and it must succeed on a Wisdom saving throw or have the Frightened condition until the spell ends. At the end of each of its turns, the Frightened target repeats the save, ending the spell on itself on a success.', 'Instantaneous', 'ba2b0543-6555-48fc-872e-8b1ea100adc6', false, false, false, true, true, 9, 'a diamond worth 1,000+ GP, which the spell consumes', 'Shield of Faith', '60 feet', 'Necromancy', 'The damage increases by 1d10 for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Make a melee spell attack against a creature you can reach. On a hit, the target takes 3d10 Necrotic damage.', '10 minutes', 'e655fe6b-0ccc-4ab8-825b-62146bc98548', true, false, false, true, true, 4, NULL, 'Earthquake', '60 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Reaction, which you take in response to taking damage from a creature that you can see within 60 feet of yourself', '2026-05-15 05:45:35.483105+00', 'You create a vine-like whip covered in thorns that lashes out at your command toward a creature in range. Make a melee spell attack against the target. On a hit, the target takes 1d6 Piercing damage, and if it is Large or smaller, you can pull it up to 10 feet closer to you. Cantrip Upgrade. The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).', '8 hours', 'fe82193b-ba10-42fe-b566-0feeece5b93f', false, true, true, true, true, 0, 'a drop of honey', 'Jallarzi’s Storm of Radiance', '120 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Ten berries appear in your hand and are infused with magic for the duration. A creature can take a Bonus Action to eat one berry. Eating a berry restores 1 Hit Point, and the berry provides enough nourishment to sustain a creature for one day. Uneaten berries disappear when the spell ends.', 'Up to 1 minute', '6164e217-346e-40d3-80a9-2962a485887c', true, true, false, true, true, 4, 'a fan and a feather', 'Sunbeam', '150 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A churning storm cloud forms for the duration, centered on a point within range and spreading to a radius of 300 feet. Each creature under the cloud when it appears must succeed on a Constitution saving throw or take 2d6 Thunder damage and have the Deafened condition for the duration. At the start of each of your later turns, the storm produces different effects, as detailed below. Turn 2. Acidic rain falls. Each creature and object under the cloud takes 4d6 Acid damage. Turn 3. You call six bolts of lightning from the cloud to strike six different creatures or objects beneath it. Each target makes a Dexterity saving throw, taking 10d6 Lightning damage on a failed save or half as much damage on a successful one. Turn 4. Hailstones rain down. Each creature under the cloud takes 2d6 Bludgeoning damage. Turns 5–10. Gusts and freezing rain assail the area under the cloud. Each creature there takes 1d6 Cold damage. Until the spell ends, the area is Difficult Terrain and Heavily Obscured, ranged attacks with weapons are impossible there, and strong wind blows through the area.', 'Instantaneous', '8dccd849-a372-42b2-aa02-61f111554a8d', false, true, false, true, true, 4, 'a firefly or phosphorescent moss', 'Pass without Trace', 'Touch', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 hour', '2026-05-15 05:45:35.483105+00', 'You point at a location within range, and a glowing, 1-foot-diameter ball of acid streaks there and explodes in a 20-foot-radius Sphere. Each creature in that area makes a Dexterity saving throw. On a failed save, a creature takes 10d4 Acid damage and another 5d4 Acid damage at the end of its next turn. On a successful save, a creature takes half the initial damage only.', 'Concentration, up to 1 minute', '9d3b7606-ff35-4324-a5bf-a37a4d0d2d3c', true, true, false, true, true, 5, 'a prayer scroll', 'Daylight', 'Self', 'Necromancy', 'The Radiant and Thunder damage increase by 1d10 for each spell slot level above 5.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'The target takes an extra 4d6 Psychic damage from the attack, and the target must succeed on a Wisdom saving throw or have the Stunned condition until the end of your next turn.', '8 hours', '2d3be379-f7e7-46ea-95d9-39b1805a8203', true, true, false, true, true, 5, NULL, 'Produce Flame', '120 feet', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Name or describe a famous person, place, or object. The spell brings to your mind a brief summary of the significant lore about that famous thing, as described by the DM. The lore might consist of important details, amusing revelations, or even secret lore that has never been widely known. The more information you already know about the thing, the more precise and detailed the information you receive is. That information is accurate but might be couched in figurative language or poetry, as determined by the DM. If the famous thing you chose isn’t actually famous, you hear sad musical notes played on a trombone, and the spell fails.', '1 hour', '813c2f75-0477-406f-ad33-f5d1f8b3ded6', false, true, false, true, true, 6, NULL, 'Synaptic Static', '90 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You suggest a course of activity—described in no more than 25 words—to twelve or fewer creatures you can see within range that can hear and understand you. The suggestion must sound achievable and not involve anything that would obviously deal damage to any of the targets or their allies. For example, you could say, “Walk to the village down that road, and help the villagers there harvest crops until sunset.” Or you could say, “Now is not the time for violence. Drop your weapons, and dance! Stop in an hour.” Each target must succeed on a Wisdom saving throw or have the Charmed condition for the duration or until you or your allies deal damage to the target. Each Charmed target pursues the suggestion to the best of its ability. The suggested activity can continue for the entire duration, but if the suggested activity can be completed in a shorter time, the spell ends for a target upon completing it.', '24 hours', 'ccfb457a-7786-471e-9b32-824c1970532d', true, true, false, false, true, 1, 'an object with the image of a dragon engraved on it worth 500+ GP', 'Invisibility', '120 feet', 'Divination', 'The damage increases by 1d6 for each spell slot level above 3.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A stroke of lightning forming a 100-foot-long, 5-foot-wide Line blasts out from you in a direction you choose. Each creature in the Line makes a Dexterity saving throw, taking 8d6 Lightning damage on a failed save or half as much damage on a successful one.', 'Concentration, up to 1 hour', '82431903-b494-49b1-a264-9439a1767ea2', false, true, false, true, true, 1, 'the petrified eye of a newt', 'Prayer of Healing', '120 feet', 'Abjuration', 'The creature''s HP increases by 10 for each spell slot level above 2.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You beseech an otherworldly entity for aid. The being must be known to you: a god, a demon prince, or some other being of cosmic power. That entity sends a Celestial, an Elemental, or a Fiend loyal to it to aid you, making the creature appear in an unoccupied space within range. If you know a specific creature’s name, you can speak that name when you cast this spell to request that creature, though you might get a different creature anyway (DM’s choice). When the creature appears, it is under no compulsion to behave a particular way. You can ask it to perform a service in exchange for payment, but it isn’t obliged to do so. The requested task could range from simple (fly us across the chasm, or help us fight a battle) to complex (spy on our enemies, or protect us during our foray into the dungeon). You must be able to communicate with the creature to bargain for its services. Payment can take a variety of forms. A Celestial might require a sizable donation of gold or magic items to an allied temple, while a Fiend might demand a living sacrifice or a gift of treasure. Some creatures might exchange their service for a quest undertaken by you. A task that can be measured in minutes requires a payment worth 100 GP per minute. A task measured in hours requires 1,000 GP per hour. And a task measured in days (up to 10 days) requires 10,000 GP per day. The DM can adjust these payments based on the circumstances under which you cast the spell. If the task is aligned with the creature’s ethos, the payment might be halved or even waived. Nonhazardous tasks typically require only half the suggested payment, while especially dangerous tasks might require a greater gift. Creatures rarely accept tasks that seem suicidal. After the creature completes the task, or when the agreed-upon duration of service expires, the creature returns to its home plane after reporting back to you if possible. If you are unable to agree on a price for the creature’s service, the creature immediately returns to its home plane.', 'Concentration, up to 1 hour', 'f40a58e3-f0cc-49f3-a80e-db620947b6b7', true, true, false, true, true, 1, NULL, 'Mordenkainen’s Sword', '30 feet', 'Transmutation', 'The extra damage increases by 1d6 for each spell slot level above 4.', '2026-05-15 05:45:35.483105+00'),
	('1 minute', '2026-05-15 05:45:35.483105+00', 'You touch a rope. One end of it hovers upward until the rope hangs perpendicular to the ground or the rope reaches a ceiling. At the rope’s upper end, an Invisible 3-foot-by-5-foot portal opens to an extradimensional space that lasts until the spell ends. That space can be reached by climbing the rope, which can be pulled into or dropped out of it. The space can hold up to eight Medium or smaller creatures. Attacks, spells, and other effects can’t pass into or out of the space, but creatures inside it can see through the portal. Anything inside the space drops out when the spell ends.', 'Concentration, up to 10 minutes', '8c39ae2a-766f-424c-8808-294052166248', false, true, false, true, true, 1, NULL, 'Searing Smite', '60 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch a creature. The target’s Speed increases by 10 feet until the spell ends.', '1 hour', '01dbc1fc-a326-4349-90dd-a887f774ced2', false, true, false, true, true, 1, 'a set of divinatory tools worth 100+ GP', 'Guidance', '150 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A willing creature is immune to being Frightened and gains Temporary HP equal to your spellcasting ability modifier at the start of each of its turns.', '8 hours', '23465625-b9eb-4db7-a07f-39ddbc1af187', false, false, false, true, true, 1, NULL, 'Grease', '120 feet', 'Abjuration', 'The damage increases by 1d6 for each spell slot level above 6.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You fortify up to six creatures you can see within range. The spell bestows 120 Temporary Hit Points, which you divide among the spell’s recipients.', 'Instantaneous', '3b11e2fb-c4a4-4892-a95e-9f9e34c08ad5', true, false, false, true, true, 9, 'a speck of glass or crystal', 'Heal', '15 feet', 'Transmutation', 'The damage the wall deals when it appears increases by 2d6 and the damage from passing through the sheet of frigid air increases by 1d6 for each spell slot level above 6.', '2026-05-15 05:45:35.483105+00'),
	('Bonus Action, which you take immediately after hitting or missing a target with a ranged attack using a weapon', '2026-05-15 05:45:35.483105+00', 'You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 20-foot Cube. The image appears at a spot that you can see within range and lasts for the duration. It seems real, including sounds, smells, and temperature appropriate to the thing depicted, but it can’t deal damage or cause conditions. If you are within range of the illusion, you can take a Magic action to cause the image to move to any other spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking. Similarly, you can cause the illusion to make different sounds at different times, even making it carry on a conversation, for example. Physical interaction with the image reveals it to be an illusion, for things can pass through it. A creature that takes a Study action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and its other sensory qualities become faint to the creature.', 'Concentration, up to 8 hours', '677a3198-06bb-451a-b1d3-5e2b8306b804', true, true, false, true, true, 7, 'either a pinch of dried carrot or an agate', 'Finger of Death', '120 feet', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You can see and hear a creature you choose that is on the same plane of existence as you. The target makes a Wisdom saving throw, which is modified (see the tables below) by how well you know the target and the sort of physical connection you have to it. The target doesn’t know what it is making the save against, only that it feels uneasy. Your Knowledge of the Target Is... Save Modifier Secondhand (heard of the target) +5 Firsthand (met the target) +0 Extensive (know the target well) -5 You Have the Target’s... Save Modifier Picture or other likeness -2 Garment or other possession -4 Body part, lock of hair, or bit of nail -10 On a successful save, the target isn’t affected, and you can’t use this spell on it again for 24 hours. On a failed save, the spell creates an Invisible, intangible sensor within 10 feet of the target. You can see and hear through the sensor as if you were there. The sensor moves with the target, remaining within 10 feet of it for the duration. If something can see the sensor, it appears as a luminous orb about the size of your fist. Instead of targeting a creature, you can target a location you have seen. When you do so, the sensor appears at that location and doesn’t move.', 'Concentration, up to 1 hour', '430e95c2-b991-4dcf-ac30-041e57101ade', false, true, false, true, true, 0, 'a small crystal or glass sphere', 'Regenerate', '300 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action, which you take immediately after hitting a target with a Melee weapon or an Unarmed Strike', '2026-05-15 05:45:35.483105+00', 'You touch a corpse or other remains. For the duration, the target is protected from decay and can’t become Undead. The spell also effectively extends the time limit on raising the target from the dead, since days spent under the influence of this spell don’t count against the time limit of spells such as Raise Dead.', 'Instantaneous', '584d73c7-fc42-42bc-b5ea-4a7576503356', false, false, false, false, true, 5, NULL, 'Detect Evil and Good', 'Touch', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 hour', '2026-05-15 05:45:35.483105+00', 'You inscribe a harmful glyph either on a surface (such as a section of floor or wall) or within an object that can be closed (such as a book or chest). The glyph can cover an area no larger than 10 feet in diameter. If you choose an object, it must remain in place; if it is moved more than 10 feet from where you cast this spell, the glyph is broken, and the spell ends without being triggered. The glyph is nearly imperceptible and requires a successful Wisdom (Perception) check against your spell save DC to notice. When you inscribe the glyph, you set its trigger and choose which effect the symbol bears: Death, Discord, Fear, Pain, Sleep, or Stunning. Each one is explained below. Set the Trigger. You decide what triggers the glyph when you cast the spell. For glyphs inscribed on a surface, common triggers include touching or stepping on the glyph, removing another object covering it, or approaching within a certain distance of it. For glyphs inscribed within an object, common triggers include opening that object or seeing the glyph. You can refine the trigger so that only creatures of certain types activate it (for example, the glyph could be set to affect Aberrations). You can also set conditions for creatures that don’t trigger the glyph, such as those who say a certain password. Once triggered, the glyph glows, filling a 60-foot-radius Sphere with Dim Light for 10 minutes, after which time the spell ends. Each creature in the Sphere when the glyph activates is targeted by its effect, as is a creature that enters the Sphere for the first time on a turn or ends its turn there. A creature is targeted only once per turn. Death. Each target makes a Constitution saving throw, taking 10d10 Necrotic damage on a failed save or half as much damage on a successful save. Discord. Each target makes a Wisdom saving throw. On a failed save, a target argues with other creatures for 1 minute. During this time, it is incapable of meaningful communication and has Disadvantage on attack rolls and ability checks. Fear. Each target must succeed on a Wisdom saving throw or have the Frightened condition for 1 minute. While Frightened, the target must move at least 30 feet away from the glyph on each of its turns, if able. Pain. Each target must succeed on a Constitution saving throw or have the Incapacitated condition for 1 minute. Sleep. Each target must succeed on a Wisdom saving throw or have the Unconscious condition for 10 minutes. A creature awakens if it takes damage or if someone takes an action to shake it awake. Stunning. Each target must succeed on a Wisdom saving throw or have the Stunned condition for 1 minute.', 'Instantaneous', '44c1e8ae-fb64-46e1-ac1b-c3a75f173e33', false, true, false, true, false, 4, 'stone, twig, and green leaf', 'Glibness', '30 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'For the duration, you can sense the presence and location of poisons, poisonous creatures, and diseases within 30 feet of you.', 'Instantaneous', '62159c6a-7a31-42fc-95cc-8e7e7797f720', false, false, false, true, true, 3, 'powdered ruby worth 1,500+ GP, which the spell consumes', 'Heroes'' Feast', '120 feet', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A willing creature is immune to being Frightened and gains Temporary HP equal to your spellcasting ability modifier at the start of each of its turns.', '1 minute', 'b4ca8799-31bd-4bc6-b3a7-5a22317c28c3', false, false, false, true, true, 4, NULL, 'Sending', 'Touch', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You conjure a portal to a precise location on a different plane of existence. You can name a specific creature to pull them through the gate to your side, provided they are on a different plane.', '8 hours', '2c7c8d35-3b65-4d85-ad7c-34cc7780e054', true, true, false, true, false, 6, 'gauze and smoke', 'Holy Aura', '60 feet', 'Conjuration', 'The damage increases by 1d6 for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'When you make a Charisma check, you can replace the roll with a 15. Magic that would determine if you are lying indicates you are telling the truth regardless of what you say.', 'Instantaneous', 'e1ee5389-4f13-490a-87b8-135f800f7220', false, false, false, true, true, 9, 'a pickled tentacle', 'Locate Creature', '60 feet', 'Divination', 'The bonus to attack rolls increases to +2 and the damage to 2d4 at level 5, and +3 and 3d4 at level 7+.', '2026-05-15 05:45:35.483105+00'),
	('1 minute', '2026-05-15 05:45:35.483105+00', 'When you make a Charisma check, you can replace the roll with a 15. Magic that would determine if you are lying indicates you are telling the truth regardless of what you say.', 'Concentration, up to 1 minute', 'aa6063ff-ae9d-4bf8-9a88-a0270c3d2cea', false, true, false, true, true, 2, NULL, 'Dispel Evil and Good', '60 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You send negative energy coursing through a creature. The target takes 7d8 + 30 Necrotic damage (Con save for half). If the target is killed, it rises as a Zombie.', 'Concentration, up to 10 minutes', '85c2ae0e-cc57-4584-a276-45f830f9fd72', true, true, false, true, true, 8, 'gem-encrusted bowl worth 1,000 GP', 'Mislead', '120 feet', 'Abjuration', 'The damage increases by 1d10 for each spell slot level above 5.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You unleash a wave of thunderous energy. Each creature in a 15-foot Cube originating from you makes a Constitution saving throw. On a failed save, a creature takes 2d8 Thunder damage and is pushed 10 feet away from you. On a successful save, a creature takes half as much damage only. In addition, unsecured objects that are entirely within the Cube are pushed 10 feet away from you, and a thunderous boom is audible within 300 feet.', 'Concentration, up to 10 minutes', '1854af0d-c20f-4ef7-8b18-de484c572fa5', false, true, false, true, true, 5, NULL, 'Expeditious Retreat', 'Self', 'Conjuration', 'You can target one additional creature for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A churning storm cloud forms for the duration, centered on a point within range and spreading to a radius of 300 feet. Each creature under the cloud when it appears must succeed on a Constitution saving throw or take 2d6 Thunder damage and have the Deafened condition for the duration. At the start of each of your later turns, the storm produces different effects, as detailed below. Turn 2. Acidic rain falls. Each creature and object under the cloud takes 4d6 Acid damage. Turn 3. You call six bolts of lightning from the cloud to strike six different creatures or objects beneath it. Each target makes a Dexterity saving throw, taking 10d6 Lightning damage on a failed save or half as much damage on a successful one. Turn 4. Hailstones rain down. Each creature under the cloud takes 2d6 Bludgeoning damage. Turns 5–10. Gusts and freezing rain assail the area under the cloud. Each creature there takes 1d6 Cold damage. Until the spell ends, the area is Difficult Terrain and Heavily Obscured, ranged attacks with weapons are impossible there, and strong wind blows through the area.', '1 minute', 'bf8ef9e2-d95e-4e55-92bd-2023e08a29ad', true, true, false, true, true, 2, 'a pinch of dirt, a piece of rock, and a lump of clay', 'Illusory Script', 'Touch', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action or Ritual', '2026-05-15 05:45:35.483105+00', 'You create a ward that protects up to 2,500 square feet of floor space. The warded area can be up to 20 feet tall, and you shape it as one 50-foot square, one hundred 5-foot squares that are contiguous, or twenty-five 10-foot squares that are contiguous. When you cast this spell, you can specify individuals that are unaffected by the spell’s effects. You can also specify a password that, when spoken aloud within 5 feet of the warded area, makes the speaker immune to its effects. The spell creates the effects below within the warded area. Dispel Magic has no effect on Guards and Wards itself, but each of the following effects can be dispelled. If all four are dispelled, Guards and Wards ends. If you cast the spell every day for 365 days on the same area, the spell thereafter lasts until all its effects are dispelled. Corridors. Fog fills all the warded corridors, making them Heavily Obscured. In addition, at each intersection or branching passage offering a choice of direction, there is a 50 percent chance that a creature other than you believes it is going in the opposite direction from the one it chooses. Doors. All doors in the warded area are magically locked, as if sealed by the Arcane Lock spell. In addition, you can cover up to ten doors with an illusion to make them appear as plain sections of wall. Stairs. Webs fill all stairs in the warded area from top to bottom, as in the Web spell. These strands regrow in 10 minutes if they are destroyed while Guards and Wards lasts. Other Spell Effect. Place one of the following magical effects within the warded area: Dancing Lights in four corridors, with a simple program that the lights repeat as long as Guards and Wards lasts Magic Mouth in two locations Stinking Cloud in two locations (the vapors return within 10 minutes if dispersed while Guards and Wards lasts) Gust of Wind in one corridor or room (the wind blows continuously while the spell lasts) Suggestion in one 5-foot square; any creature that enters that square receives the suggestion mentally', 'Concentration, up to 1 minute', 'a4331ede-d47d-4f85-843c-95e5d3271cba', true, false, false, true, false, 0, 'diamond dust worth 100 GP', 'Fireball', '30 feet', 'Enchantment', 'You can target one additional creature for each spell slot level above 3.', '2026-05-15 05:45:35.483105+00'),
	('10 minutes', '2026-05-15 05:45:35.483105+00', 'For the duration, you can comprehend and verbally communicate with Beasts, and you can use any of the Influence action’s skill options with them. Most Beasts have little to say about topics that don’t pertain to survival or companionship, but at minimum, a Beast can give you information about nearby locations and monsters, including whatever it has perceived within the past day.', 'Concentration, up to 1 minute', 'a36bd007-1372-4c48-baca-343f6b59f132', false, false, false, true, true, 2, NULL, 'Guards and Wards', 'Self', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A creature you touch has the Invisible condition until the spell ends.', 'Concentration, up to 1 minute', 'da45643b-bb23-4407-a3b2-c1f2263b8b00', false, false, false, true, true, 3, 'a short reed', 'Geas', '90 feet', 'Evocation', 'The Cold or Acid damage (your choice) increases by 1d6 for each spell slot level above 3.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Creatures of your choice in the aura have Advantage on all saving throws, and other creatures have Disadvantage on attack rolls against them. When a Fiend or Undead hits a target in the aura, the attacker is Blinded (CON save).', 'Concentration, up to 1 minute', '2ff84c82-f8f2-4c35-899b-148e57ddd6d4', false, true, false, true, true, 0, NULL, 'Scrying', '150 feet', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'For the duration, you can comprehend and verbally communicate with Beasts, and you can use any of the Influence action’s skill options with them. Most Beasts have little to say about topics that don’t pertain to survival or companionship, but at minimum, a Beast can give you information about nearby locations and monsters, including whatever it has perceived within the past day.', 'Concentration, up to 1 minute', '1634f9b7-54a4-4db8-9d21-7d5b557f2854', false, true, false, true, true, 2, 'two eggs', 'Unseen Servant', 'Touch', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A beam of enervating energy shoots from you toward a creature within range. The target must make a Constitution saving throw. On a successful save, the target has Disadvantage on the next attack roll it makes until the start of your next turn. On a failed save, the target has Disadvantage on Strength-based d20 Tests for the duration. During that time, it also subtracts 1d8 from all its damage rolls. The target repeats the save at the end of each of its turns, ending the spell on a success.', 'Concentration, up to 1 minute', 'ce97f08f-f14a-46f4-9b4b-24d786fe9cb1', true, false, false, true, true, 1, 'ashes from burned mistletoe', 'Gate', '500 feet', 'Transmutation', 'The duration increases to 8 hours if cast with a level 9 spell slot.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You magically mark one creature you can see within range as your quarry. Until the spell ends, you deal an extra 1d6 Force damage to the target whenever you hit it with an attack roll. You also have Advantage on any Wisdom (Perception or Survival) check you make to find it. If the target drops to 0 Hit Points before this spell ends, you can take a Bonus Action to move the mark to a new creature you can see within range.', '1 minute', 'fa88dd30-a8e8-40b5-9084-fe5972ddc7ca', false, false, false, true, true, 6, NULL, 'Chromatic Orb', '100 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'You call forth an Undead spirit. It manifests in an unoccupied space that you can see within range and uses the Undead Spirit stat block. When you cast the spell, choose the creature’s form: Ghostly, Putrid, or Skeletal. The spirit resembles an Undead creature with the chosen form, which determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends. The creature is an ally to you and your allies. In combat, the creature shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the Dodge action and uses its movement to avoid danger. Undead Spirit Medium Undead, Neutral AC 11 + the spell’s level HP 30 (Ghostly and Putrid only) or 20 (Skeletal only) + 10 for each spell level above 3 Speed 30 ft.; Fly 40 ft. (hover; Ghostly only) Mod Save STR 12 +1 +1 DEX 16 +3 +3 CON 15 +2 +2 Mod Save INT 4 -3 -3 WIS 10 +0 +0 CHA 9 -1 -1 Immunities Necrotic, Poison; Exhaustion, Frightened, Paralyzed, Poisoned Senses Darkvision 60 ft.; Passive Perception 10 Languages Understands the languages you know CR None (XP 0; PB equals your Proficiency Bonus) Traits Festering Aura (Putrid Only). Constitution Saving Throw: DC equals your spell save DC, any creature (other than you) that starts its turn within a 5-foot Emanation originating from the spirit. Failure: The creature has the Poisoned condition until the start of its next turn. Incorporeal Passage (Ghostly Only). The spirit can move through other creatures and objects as if they were Difficult Terrain. If it ends its turn inside an object, it is shunted to the nearest unoccupied space and takes 1d10 Force damage for every 5 feet traveled. Actions Multiattack. The spirit makes a number of attacks equal to half this spell’s level (round down). Deathly Touch (Ghostly Only). Melee Attack Roll: Bonus equals your spell attack modifier, reach 5 ft. Hit: 1d8 + 3 + the spell’s level Necrotic damage, and the target has the Frightened condition until the end of its next turn. Grave Bolt (Skeletal Only). Ranged Attack Roll: Bonus equals your spell attack modifier, range 150 ft. Hit: 2d4 + 3 + the spell’s level Necrotic damage. Rotting Claw (Putrid Only). Melee Attack Roll: Bonus equals your spell attack modifier, reach 5 ft. Hit: 1d6 + 3 + the spell’s level Slashing damage. If the target has the Poisoned condition, it has the Paralyzed condition until the end of its next turn.', '1 hour', '75ab9171-ae6f-4f99-93a8-f7bb5de2bfd3', false, true, false, true, true, 5, NULL, 'Hail of Thorns', 'Touch', 'Divination', 'Use the spell slot’s level for the spell’s level in the stat block.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Until the spell ends, one willing creature you touch gains the ability to move up, down, and across vertical surfaces and along ceilings, while leaving its hands free. The target also gains a Climb Speed equal to its Speed.', 'Instantaneous', '32b10a16-3753-4eca-be20-238f6ee4dca1', true, false, false, true, true, 9, NULL, 'Summon Aberration', 'Touch', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A spectral, floating hand appears at a point you choose within range. The hand lasts for the duration. The hand vanishes if it is ever more than 30 feet away from you or if you cast this spell again. When you cast the spell, you can use the hand to manipulate an object, open an unlocked door or container, stow or retrieve an item from an open container, or pour the contents out of a vial. As a Magic action on your later turns, you can control the hand thus again. As part of that action, you can move the hand up to 30 feet. The hand can’t attack, activate magic items, or carry more than 10 pounds.', 'Concentration, up to 1 minute', '0ee6e66f-7f90-41ef-ae70-8952df2c6b2e', true, true, false, false, true, 5, 'a pinch of dirt, a piece of rock, and a lump of clay', 'Resistance', '30 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch one Large or smaller object that isn’t being worn or carried by someone else. Until the spell ends, the object sheds Bright Light in a 20-foot radius and Dim Light for an additional 20 feet. The light can be colored as you like. Covering the object with something opaque blocks the light. The spell ends if you cast it again.', 'Instantaneous', '98410373-2838-420c-9d82-7bc083773337', false, false, false, true, true, 1, 'a yew leaf', 'Giant Insect', 'Touch', 'Abjuration', 'The bonus to attack rolls increases to +2 and the damage to 2d4 at level 5, and +3 and 3d4 at level 7+.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create a tiny nature-based magical effect, such as predicting weather, making a flower bloom, or creating a sound of rustling leaves.', '1 hour', '359b2978-faef-4b4d-877e-d0fc6fade9eb', true, true, false, true, true, 3, 'a mitten', 'Wall of Thorns', 'Self', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action, which you take immediately after hitting a creature with a Melee weapon or an Unarmed Strike', '2026-05-15 05:45:35.483105+00', 'A flickering flame appears in your hand and remains there for the duration. While there, the flame emits no heat and ignites nothing, and it sheds Bright Light in a 20-foot radius and Dim Light for an additional 20 feet. The spell ends if you cast it again. Until the spell ends, you can take a Magic action to hurl fire at a creature or an object within 60 feet of you. Make a ranged spell attack. On a hit, the target takes 1d8 Fire damage. Cantrip Upgrade. The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).', 'Concentration, up to 1 minute', 'bb3e3b84-3b34-4efc-a69b-760e7501f79f', true, true, true, true, true, 4, 'a shard of glass', 'Otto’s Irresistible Dance', 'Touch', 'Transmutation', 'The duration increases by 1 hour for each spell slot level above 3.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You utter a divine word. Each creature of your choice within range that can hear you must make a Charisma save. Various debilitating effects occur based on the target''s current HP.', 'Instantaneous', 'c87574d2-ea50-4c76-acf5-050c0f2ade5d', false, false, false, true, true, 7, 'pickled octopus tentacle', 'Mass Heal', '10 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A bright streak flashes from your pointing finger to a point within range and then blossoms with a low roar into an explosion of flame. Creatures take 8d6 Fire damage (Dex save for half).', 'Concentration, up to 1 hour', '46706499-08f8-4505-bf03-09f0b0d85b92', false, false, false, true, true, 3, 'a gilded flower worth 300+ GP', 'Sleet Storm', 'Touch', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 hour', '2026-05-15 05:45:35.483105+00', 'A flash of light streaks toward a creature. On a hit, it takes 4d6 Radiant damage, and the next attack roll made against this target before the end of your next turn has Advantage.', 'Concentration, up to 1 minute', 'ff7a1498-9493-4739-a23b-19a17c724554', true, true, false, true, true, 8, NULL, 'Aid', '60 feet', 'Abjuration', 'The Cold damage increases by 1d6 for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Make a melee spell attack against a creature you can reach. On a hit, the target takes 3d10 Necrotic damage.', 'Concentration, up to 8 hours', '3cec5207-1aea-405e-a008-d6327ec44f93', true, true, false, true, true, 6, 'gauze and smoke', 'Steel Wind Strike', '300 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You inscribe a glyph that later unleashes a magical effect. You inscribe it either on a surface (such as a table or a section of floor) or within an object that can be closed (such as a book or chest) to conceal the glyph. The glyph can cover an area no larger than 10 feet in diameter. If the surface or object is moved more than 10 feet from where you cast this spell, the glyph is broken, and the spell ends without being triggered. The glyph is nearly imperceptible and requires a successful Wisdom (Perception) check against your spell save DC to notice. When you inscribe the glyph, you set its trigger and choose whether it’s an explosive rune or a spell glyph, as explained below. Set the Trigger. You decide what triggers the glyph when you cast the spell. For glyphs inscribed on a surface, common triggers include touching or stepping on the glyph, removing another object covering it, or approaching within a certain distance of it. For glyphs inscribed within an object, common triggers include opening that object or seeing the glyph. Once a glyph is triggered, this spell ends. You can refine the trigger so that only creatures of certain types activate it (for example, the glyph could be set to affect Aberrations). You can also set conditions for creatures that don’t trigger the glyph, such as those who say a certain password. Explosive Rune. When triggered, the glyph erupts with magical energy in a 20-foot-radius Sphere centered on the glyph. Each creature in the area makes a Dexterity saving throw. A creature takes 5d8 Acid, Cold, Fire, Lightning, or Thunder damage (your choice when you create the glyph) on a failed save or half as much damage on a successful one. Spell Glyph. You can store a prepared spell of level 3 or lower in the glyph by casting it as part of creating the glyph. The spell must target a single creature or an area. The spell being stored has no immediate effect when cast in this way. When the glyph is triggered, the stored spell takes effect. If the spell has a target, it targets the creature that triggered the glyph. If the spell affects an area, the area is centered on that creature. If the spell summons Hostile creatures or creates harmful objects or traps, they appear as close as possible to the intruder and attack it. If the spell requires Concentration, it lasts until the end of its full duration.', '1 round', '3c709371-884b-4a00-b8eb-d3f5ec1eb871', false, false, false, true, true, 1, 'a straight piece of iron', 'Dominate Monster', '30 feet', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 hour', '2026-05-15 05:45:35.483105+00', 'Choose an area of terrain no larger than 40 feet on a side within range. You can reshape dirt, sand, or clay in the area in any manner you choose for the duration. You can raise or lower the area’s elevation, create or fill in a trench, erect or flatten a wall, or form a pillar. The extent of any such changes can’t exceed half the area’s largest dimension. For example, if you affect a 40-foot square, you can create a pillar up to 20 feet high, raise or lower the square’s elevation by up to 20 feet, dig a trench up to 20 feet deep, and so on. It takes 10 minutes for these changes to complete. Because the terrain’s transformation occurs slowly, creatures in the area can’t usually be trapped or injured by the ground’s movement. At the end of every 10 minutes you spend concentrating on the spell, you can choose a new area of terrain to affect within range. This spell can’t manipulate natural stone or stone construction. Rocks and structures shift to accommodate the new terrain. If the way you shape the terrain would make a structure unstable, it might collapse. Similarly, this spell doesn’t directly affect plant growth. The moved earth carries any plants along with it.', 'Concentration, up to 10 minutes', 'e707af86-72ff-4be5-93f3-151069e13a55', false, true, false, true, true, 8, 'a miniature shovel', 'Speak with Plants', 'Self', 'Abjuration', 'The spell lasts until dispelled, without requiring Concentration, if cast with a level 4+ spell slot.', '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'A creature you touch becomes Invisible. The spell ends early if the target attacks or casts a spell.', '1 round', '62c68cde-3ca6-4c76-8b7e-61fd1053ec5b', false, false, false, false, true, 1, 'a piece of cork', 'Thunderclap', '60 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'For the duration, the willing creature you touch has Truesight with a range of 120 feet.', 'Instantaneous', '1b2452a6-a21b-402b-8bc7-d20b6bbe2096', true, false, false, true, true, 1, 'a prayer scroll', 'Lightning Bolt', '60 feet', 'Enchantment', 'Both types of damage increase by 1d8 for each spell slot level above 6.', '2026-05-15 05:45:35.483105+00'),
	('1 hour', '2026-05-15 05:45:35.483105+00', 'A creature you touch makes a Constitution saving throw, taking 2d10 Necrotic damage on a failed save or half as much damage on a successful one.', '10 minutes', 'd96ba7a8-2626-4f44-9398-40f82bbdad8b', true, false, false, true, true, 2, 'a set of divinatory tools worth 100+ GP', 'Storm of Vengeance', '60 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'With a touch, you revive a dead creature if it has been dead no longer than 10 days and it wasn’t Undead when it died. The creature returns to life with 1 Hit Point. This spell also neutralizes any poisons that affected the creature at the time of death. This spell closes all mortal wounds, but it doesn’t restore missing body parts. If the creature is lacking body parts or organs integral for its survival—its head, for instance—the spell automatically fails. Coming back from the dead is an ordeal. The target takes a -4 penalty to d20 Tests. Every time the target finishes a Long Rest, the penalty is reduced by 1 until it becomes 0.', 'Concentration, up to 1 hour', 'ec6703a0-a35e-49ce-b1cf-b7d8a234fb3b', false, false, false, true, true, 1, 'a pinch of confetti', 'Misty Step', '60 feet', 'Transmutation', 'The damage increases by 1d8 for each spell slot level above 2.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A churning storm cloud forms for the duration, centered on a point within range and spreading to a radius of 300 feet. Each creature under the cloud when it appears must succeed on a Constitution saving throw or take 2d6 Thunder damage and have the Deafened condition for the duration. At the start of each of your later turns, the storm produces different effects, as detailed below. Turn 2. Acidic rain falls. Each creature and object under the cloud takes 4d6 Acid damage. Turn 3. You call six bolts of lightning from the cloud to strike six different creatures or objects beneath it. Each target makes a Dexterity saving throw, taking 10d6 Lightning damage on a failed save or half as much damage on a successful one. Turn 4. Hailstones rain down. Each creature under the cloud takes 2d6 Bludgeoning damage. Turns 5–10. Gusts and freezing rain assail the area under the cloud. Each creature there takes 1d6 Cold damage. Until the spell ends, the area is Difficult Terrain and Heavily Obscured, ranged attacks with weapons are impossible there, and strong wind blows through the area.', 'Instantaneous', 'd9d35aae-6207-4a49-83f4-ff3fe51dc7b6', true, true, true, true, true, 2, 'a glass sphere', 'Hail of Thorns', 'Touch', 'Divination', 'The duration increases to Concentration, up to 10 minutes (level 6), 1 hour (level 7), or 8 hours (level 8+).', '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'One creature or loose object of your choice that you can see within range rises vertically up to 20 feet and remains suspended there for the duration. The spell can levitate an object that weighs up to 500 pounds. An unwilling creature that succeeds on a Constitution saving throw is unaffected. The target can move only by pushing or pulling against a fixed object or surface within reach (such as a wall or a ceiling), which allows it to move as if it were climbing. You can change the target’s altitude by up to 20 feet in either direction on your turn. If you are the target, you can move up or down as part of your move. Otherwise, you can take a Magic action to move the target, which must remain within the spell’s range. When the spell ends, the target floats gently to the ground if it is still aloft.', 'Concentration, up to 1 minute', 'cad16f46-9443-4d25-b392-2414ec0e6a3d', true, true, false, true, true, 0, 'salt and copper pieces', 'Feather Fall', 'Self', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('10 minutes', '2026-05-15 05:45:35.483105+00', 'You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 15-foot Cube. The image appears at a spot within range and lasts for the duration. The image is purely visual; it isn’t accompanied by sound, smell, or other sensory effects. As a Magic action, you can cause the image to move to any spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking. Physical interaction with the image reveals it to be an illusion, since things can pass through it. A creature that takes a Study action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image.', '1 minute', '6d53ce60-b63b-497d-a310-651b623c1780', false, true, false, false, true, 7, NULL, 'Grease', '150 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('10 minutes', '2026-05-15 05:45:35.483105+00', 'A wave of healing energy washes out from a point you can see within range. Choose up to six creatures in a 30-foot-radius Sphere centered on that point. Each target regains Hit Points equal to 5d8 plus your spellcasting ability modifier.', 'Concentration, up to 1 minute', '0ba98641-da15-493c-9a97-e9106576a7c5', false, true, false, true, true, 6, NULL, 'Greater Restoration', '120 feet', 'Enchantment', 'You can target one additional creature for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You place a magical command on a creature you can see. If it deviates from your instructions, it takes 5d10 psychic damage (once per day). Removing the spell requires Remove Curse, Greater Restoration, or Wish.', 'Instantaneous', 'dc6617d0-bd83-4379-b090-af1700b441eb', false, true, false, true, true, 2, 'a drop of water or a piece of ice', 'Fire Shield', '30 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You call forth an aberrant spirit. It manifests in an unoccupied space that you can see within range and uses the Aberrant Spirit stat block. When you cast the spell, choose Beholderkin, Mind Flayer, or Slaad. The creature resembles an Aberration of that kind, which determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends. The creature is an ally to you and your allies. In combat, it shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the Dodge action and uses its movement to avoid danger. Aberrant Spirit Medium Aberration, Neutral AC 11 + the spell’s level HP 40 + 10 for each spell level above 4 Speed 30 ft.; Fly 30 ft. (hover; Beholderkin only) Mod Save STR 16 +3 +3 DEX 10 +0 +0 CON 15 +2 +2 Mod Save INT 16 +3 +3 WIS 10 +0 +0 CHA 6 -2 -2 Immunities Psychic Senses Darkvision 60 ft.; Passive Perception 10 Languages Deep Speech, understands the languages you know CR None (XP 0; PB equals your Proficiency Bonus) Traits Regeneration (Slaad Only). The spirit regains 5 Hit Points at the start of its turn if it has at least 1 Hit Point. Whispering Aura (Mind Flayer Only). At the start of each of the spirit’s turns, the spirit emits psionic energy if it doesn’t have the Incapacitated condition. Wisdom Saving Throw: DC equals your spell save DC, each creature (other than you) within 5 feet of the spirit. Failure: 2d6 Psychic damage. Actions Multiattack. The spirit makes a number of attacks equal to half this spell’s level (round down). Claw (Slaad Only). Melee Attack Roll: Bonus equals your spell attack modifier, reach 5 ft. Hit: 1d10 + 3 + the spell’s level Slashing damage, and the target can’t regain Hit Points until the start of the spirit’s next turn. Eye Ray (Beholderkin Only). Ranged Attack Roll: Bonus equals your spell attack modifier, range 150 ft. Hit: 1d8 + 3 + the spell’s level Psychic damage. Psychic Slam (Mind Flayer Only). Melee Attack Roll: Bonus equals your spell attack modifier, reach 5 ft. Hit: 1d8 + 3 + the spell’s level Psychic damage.', 'Concentration, up to 1 minute', '2a94ac0a-6832-4133-8bfa-fbed3e12d60c', true, false, false, true, true, 2, 'a silver whistle', 'Wall of Thorns', 'Self', 'Evocation', 'You can target one additional Humanoid for each spell slot level above 2.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch a corpse to protect it from decay and prevent it from becoming Undead. The duration doesn’t count against the time limit of spells like Raise Dead or Revivify.', 'Until dispelled', '697b8f74-d815-4112-9a25-751ad6ab9edc', true, true, false, false, true, 0, 'a miniature ziggurat', 'Expeditious Retreat', '90 feet', 'Abjuration', 'The damage increases by 3d6 for each spell slot level above 6.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Describe or name a specific kind of Beast, Plant creature, or nonmagical plant. You learn the direction and distance to the closest creature or plant of that kind within 5 miles, if any are present.', '10 minutes', '09d84160-0f72-471a-8ebc-0d65ee2726e8', true, false, false, false, false, 5, 'a forked twig', 'Hunter''s Mark', '10 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'The target takes an extra 4d6 Psychic damage from the attack, and the target must succeed on a Wisdom saving throw or have the Stunned condition until the end of your next turn.', 'Instantaneous', '0e7f4546-37f7-4500-add5-cbb05bc3101a', false, true, false, true, true, 8, 'a leaf of sumac', 'Wall of Fire', 'Self', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create a simulacrum of one Beast or Humanoid that is within 10 feet of you for the entire casting of the spell. You finish the casting by touching both the creature and a pile of ice or snow that is the same size as that creature, and the pile turns into the simulacrum, which is a creature. It uses the game statistics of the original creature at the time of casting, except it is a Construct, its Hit Point maximum is half as much, and it can’t cast this spell. The simulacrum is Friendly to you and creatures you designate. It obeys your commands and acts on your turn in combat. The simulacrum can’t gain levels, and it can’t take Short or Long Rests. If the simulacrum takes damage, the only way to restore its Hit Points is to repair it as you take a Long Rest, during which you expend components worth 100 GP per Hit Point restored. The simulacrum must stay within 5 feet of you for the repair. The simulacrum lasts until it drops to 0 Hit Points, at which point it reverts to snow and melts away. If you cast this spell again, any simulacrum you created with this spell is instantly destroyed.', 'Concentration, up to 1 hour', '56de1182-f741-4782-a3f3-10e949ce3b2f', false, false, false, true, true, 0, 'a weapon with which you have proficiency and that is worth 1+ CP', 'Find Familiar', 'Self', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Eight rays of light flash from you in a 60-foot Cone. Each creature in the Cone makes a Dexterity saving throw. For each target, roll 1d8 to determine which color ray affects it, consulting the Prismatic Rays table. Roll Table to VTT Prismatic Rays 1d8 Ray 1 Red. Failed Save: 12d6 Fire damage. Successful Save: Half as much damage. 2 Orange. Failed Save: 12d6 Acid damage. Successful Save: Half as much damage. 3 Yellow. Failed Save: 12d6 Lightning damage. Successful Save: Half as much damage. 4 Green. Failed Save: 12d6 Poison damage. Successful Save: Half as much damage. 5 Blue. Failed Save: 12d6 Cold damage. Successful Save: Half as much damage. 6 Indigo. Failed Save: The target has the Restrained condition and makes a Constitution saving throw at the end of each of its turns. If it successfully saves three times, the condition ends. If it fails three times, it has the Petrified condition until it is freed by an effect like the Greater Restoration spell. The successes and failures needn’t be consecutive; keep track of both until the target collects three of a kind. 7 Violet. Failed Save: The target has the Blinded condition and makes a Wisdom saving throw at the start of your next turn. On a successful save, the condition ends. On a failed save, the condition ends, and the creature teleports to another plane of existence (DM’s choice). 8 Special. The target is struck by two rays. Roll twice, rerolling any 8.', 'Concentration, up to 1 minute', '38928f58-7161-4967-aa51-41bcd49aec02', true, true, false, true, true, 3, NULL, 'Power Word Fortify', '60 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'A vertical column of divine fire roars down from the heavens. Each creature in a 10-foot-radius, 40-foot-high Cylinder takes 4d6 Fire damage and 4d6 Radiant damage (Dex save for half).', 'Instantaneous', '65d47934-e29f-469a-abcd-867a042beac0', true, true, false, true, true, 3, 'a pinch of powdered iron', 'Protection from Evil and Good', 'Touch', 'Enchantment', 'The damage increases by 1d8 for each spell slot level above 2.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You and up to ten willing creatures of your choice within range assume gaseous forms for the duration, appearing as wisps of cloud. While in this cloud form, a target has a Fly Speed of 300 feet and can hover; it has Immunity to the Prone condition; and it has Resistance to Bludgeoning, Piercing, and Slashing damage. The only actions a target can take in this form are the Dash action or a Magic action to begin reverting to its normal form. Reverting takes 1 minute, during which the target has the Stunned condition. Until the spell ends, the target can revert to cloud form, which also requires a Magic action followed by a 1-minute transformation. If a target is in cloud form and flying when the effect ends, the target descends 60 feet per round for 1 minute until it lands, which it does safely. If it can’t land after 1 minute, it falls the remaining distance.', 'Instantaneous', '3d5665a6-598a-4f9e-90a0-a2d3a450535b', false, true, false, true, true, 1, NULL, 'Dissonant Whispers', 'Self', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A flash of light streaks toward a creature. On a hit, it takes 4d6 Radiant damage, and the next attack roll made against this target before the end of your next turn has Advantage.', 'Until dispelled', '2b9589e8-9138-4b3b-b18e-336c3ed413cf', false, true, false, true, true, 5, NULL, 'Tasha’s Bubbling Cauldron', '1 mile', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 minute or Ritual', '2026-05-15 05:45:35.483105+00', 'You project a phantasmal image of a creature''s worst fears in a 60-foot Cone. Each creature in the area must succeed on a Wisdom save or have the Frightened condition.', 'Instantaneous', 'c2915e9b-6a7c-4ec9-8128-df891e02153f', true, true, false, true, true, 0, NULL, 'Thaumaturgy', '30 feet', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You or a creature you touch becomes Invisible. Unlike standard Invisibility, the spell does not end if the target attacks or casts a spell.', 'Concentration, up to 10 minutes', '47251f90-fbda-449f-b387-fc57858192d2', true, true, true, true, true, 9, 'a firefly or phosphorescent moss', 'Otiluke’s Freezing Sphere', '120 feet', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('24 hours', '2026-05-15 05:45:35.483105+00', 'You make yourself—including your clothing, armor, weapons, and other belongings on your person—look different until the spell ends or until you use your action to dismiss it.', '1 minute', '6b23f90f-d1c5-42ba-9ec5-9dc51894ed95', false, true, false, true, true, 5, 'diamond dust worth 100+ GP, which the spell consumes', 'Dissonant Whispers', '60 feet', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'You touch a willing creature. For the duration, its movement is unaffected by Difficult Terrain, and spells and other magical effects can''t reduce its Speed or cause it to be Paralyzed or Restrained.', 'Instantaneous', '0a388f2e-3f64-4e89-85d5-b4795e9a408a', false, true, false, true, true, 0, NULL, 'Flesh to Stone', 'Self', 'Conjuration', 'The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).', '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'A churning storm cloud forms for the duration, centered on a point within range and spreading to a radius of 300 feet. Each creature under the cloud when it appears must succeed on a Constitution saving throw or take 2d6 Thunder damage and have the Deafened condition for the duration. At the start of each of your later turns, the storm produces different effects, as detailed below. Turn 2. Acidic rain falls. Each creature and object under the cloud takes 4d6 Acid damage. Turn 3. You call six bolts of lightning from the cloud to strike six different creatures or objects beneath it. Each target makes a Dexterity saving throw, taking 10d6 Lightning damage on a failed save or half as much damage on a successful one. Turn 4. Hailstones rain down. Each creature under the cloud takes 2d6 Bludgeoning damage. Turns 5–10. Gusts and freezing rain assail the area under the cloud. Each creature there takes 1d6 Cold damage. Until the spell ends, the area is Difficult Terrain and Heavily Obscured, ranged attacks with weapons are impossible there, and strong wind blows through the area.', 'Instantaneous', '023ce7da-ce6a-4621-9671-cb9d58adaf07', true, false, false, true, true, 9, 'a chip of mica', 'Summon Elemental', '60 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch a creature and magically remove one of the following effects from it: 1 Exhaustion level The Charmed or Petrified condition A curse, including the target’s Attunement to a cursed magic item Any reduction to one of the target’s ability scores Any reduction to the target’s Hit Point maximum', 'Concentration, up to 1 minute', '57e3fb74-951a-4590-9eec-7df5e4e7eef0', false, true, false, true, true, 0, 'herbs, oils, and incense worth 1,000 GP', 'Planar Binding', '150 feet', 'Abjuration', 'The duration increases to Concentration, up to 10 minutes (level 5), 1 hour (level 6), or 8 hours (level 7+).', '2026-05-15 05:45:35.483105+00'),
	('Reaction', '2026-05-15 05:45:35.483105+00', 'You grant the semblance of life to a corpse of your choice within range, allowing it to answer questions you pose. The corpse must have a mouth, and this spell fails if the deceased creature was Undead when it died. The spell also fails if the corpse was the target of this spell within the past 10 days. Until the spell ends, you can ask the corpse up to five questions. The corpse knows only what it knew in life, including the languages it knew. Answers are usually brief, cryptic, or repetitive, and the corpse is under no compulsion to offer a truthful answer if you are antagonistic toward it or it recognizes you as an enemy. This spell doesn’t return the creature’s soul to its body, only its animating spirit. Thus, the corpse can’t learn new information, doesn’t comprehend anything that has happened since it died, and can’t speculate about future events.', 'Concentration, up to 1 hour', '3286e552-fcf3-4c46-bbc1-cac8997f7495', false, false, false, true, true, 5, 'a gem, crystal, or reliquary worth 500+ GP', 'Word of Recall', 'Touch', 'Abjuration', 'The duration increases to 8 hours if cast with a level 9 spell slot.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create a 20-foot-radius Sphere of fog centered on a point. The sphere spreads around corners, and its area is Heavily Obscured.', 'Concentration, up to 1 minute', '8dff7897-8bd8-497b-956f-2b8487a5f777', true, true, false, true, true, 6, 'a piece of cured leather', 'Tasha’s Bubbling Cauldron', 'Self', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'You magically mark one creature you can see within range as your quarry. Until the spell ends, you deal an extra 1d6 Force damage to the target whenever you hit it with an attack roll. You also have Advantage on any Wisdom (Perception or Survival) check you make to find it. If the target drops to 0 Hit Points before this spell ends, you can take a Bonus Action to move the mark to a new creature you can see within range.', 'Until dispelled', 'df100f32-df69-467b-beea-b30b17549d73', false, true, false, true, true, 1, 'a bit of spiderweb', 'Locate Animals or Plants', 'Touch', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create a ward that protects up to 2,500 square feet of floor space. The warded area can be up to 20 feet tall, and you shape it as one 50-foot square, one hundred 5-foot squares that are contiguous, or twenty-five 10-foot squares that are contiguous. When you cast this spell, you can specify individuals that are unaffected by the spell’s effects. You can also specify a password that, when spoken aloud within 5 feet of the warded area, makes the speaker immune to its effects. The spell creates the effects below within the warded area. Dispel Magic has no effect on Guards and Wards itself, but each of the following effects can be dispelled. If all four are dispelled, Guards and Wards ends. If you cast the spell every day for 365 days on the same area, the spell thereafter lasts until all its effects are dispelled. Corridors. Fog fills all the warded corridors, making them Heavily Obscured. In addition, at each intersection or branching passage offering a choice of direction, there is a 50 percent chance that a creature other than you believes it is going in the opposite direction from the one it chooses. Doors. All doors in the warded area are magically locked, as if sealed by the Arcane Lock spell. In addition, you can cover up to ten doors with an illusion to make them appear as plain sections of wall. Stairs. Webs fill all stairs in the warded area from top to bottom, as in the Web spell. These strands regrow in 10 minutes if they are destroyed while Guards and Wards lasts. Other Spell Effect. Place one of the following magical effects within the warded area: Dancing Lights in four corridors, with a simple program that the lights repeat as long as Guards and Wards lasts Magic Mouth in two locations Stinking Cloud in two locations (the vapors return within 10 minutes if dispersed while Guards and Wards lasts) Gust of Wind in one corridor or room (the wind blows continuously while the spell lasts) Suggestion in one 5-foot square; any creature that enters that square receives the suggestion mentally', 'Concentration, up to 1 minute', 'ea6068e0-0bb4-41c4-8ba8-475aa588ef31', false, true, false, false, true, 3, 'a pinch of diamond dust worth 25+ GP, which the spell consumes', 'Word of Recall', 'Self', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 hour or Ritual', '2026-05-15 05:45:35.483105+00', 'Choose up to three creatures within range. Each target’s Hit Point maximum and current Hit Points increase by 5 for the duration.', 'Concentration, up to 1 hour', '6dc31000-cc20-49e7-ae7d-04ad1e539b96', false, true, false, true, true, 3, 'a piece of iron and a flame', 'Enthrall', '30 feet', 'Necromancy', 'The damage of an explosive rune increases by 1d8 for each spell slot level above 3. If you create a spell glyph, you can store any spell of up to the same level as the spell slot you use for the Glyph of Warding.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You cause a metal object to glow red-hot. Any creature in contact with it takes 2d8 Fire damage. You can use a Bonus Action on subsequent turns to deal this damage again. If the target is wearing metal armor, it has Disadvantage on attacks and checks.', 'Concentration, up to 8 hours', '1b5c66ba-4646-4972-a24b-33e3ffc2b234', false, true, false, false, true, 2, NULL, 'Power Word Heal', 'Self', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'This spell channels vitality into plants. The casting time you use determines whether the spell has the Overgrowth or the Enrichment effect below. Overgrowth. Choose a point within range. All normal plants in a 100-foot-radius Sphere centered on that point become thick and overgrown. A creature moving through that area must spend 4 feet of movement for every 1 foot it moves. You can exclude one or more areas of any size within the spell’s area from being affected. Enrichment. All plants in a half-mile radius centered on a point within range become enriched for 365 days. The plants yield twice the normal amount of food when harvested. They can benefit from only one Plant Growth per year.', 'Instantaneous', '62ca634f-e0b4-4773-be6c-994dc9fef8ed', true, false, true, true, true, 1, NULL, 'Magic Weapon', 'Self', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 minute', '2026-05-15 05:45:35.483105+00', 'Describe or name a specific kind of Beast, Plant creature, or nonmagical plant. You learn the direction and distance to the closest creature or plant of that kind within 5 miles, if any are present.', '10 days', 'c137aa41-8af3-41a1-a40b-8c9c9d589e58', false, true, false, true, true, 1, NULL, 'Summon Fey', 'Touch', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You shape-shift into another creature for the duration or until you take a Magic action to shape-shift into a different eligible form. The new form must be of a creature that has a Challenge Rating no higher than your level or Challenge Rating. You must have seen the sort of creature before, and it can’t be a Construct or an Undead. When you cast the spell, you gain a number of Temporary Hit Points equal to the Hit Points of the first form into which you shape-shift. These Temporary Hit Points vanish if any remain when the spell ends. Your game statistics are replaced by the stat block of the chosen form, but you retain your creature type; alignment; personality; Intelligence, Wisdom, and Charisma scores; Hit Points; Hit Point Dice; proficiencies; and ability to communicate. If you have the Spellcasting feature, you retain it too. Upon shape-shifting, you determine whether your equipment drops to the ground or changes in size and shape to fit the new form while you’re in it.', 'Instantaneous', 'cdec8c06-daa4-4fc8-af9f-289ec92b220a', false, true, false, true, true, 3, 'a drop of mercury', 'Summon Fey', 'Self', 'Conjuration', 'Use the spell slot’s level for the spell’s level in the stat block.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A 10-foot Emanation springs into existence around you and remains stationary for the duration. The spell fails when you cast it if the Emanation isn’t big enough to fully encapsulate all creatures in its area. Creatures and objects within the Emanation when you cast the spell can move through it freely. All other creatures and objects are barred from passing through it. Spells of level 3 or lower can’t be cast through it, and the effects of such spells can’t extend into it. The atmosphere inside the Emanation is comfortable and dry, regardless of the weather outside. Until the spell ends, you can command the interior to have Dim Light or Darkness (no action required). The Emanation is opaque from the outside and of any color you choose, but it’s transparent from the inside. The spell ends early if you leave the Emanation or if you cast it again.', 'Instantaneous', 'd8dbf44d-ac17-47a4-b8b7-58d7ac41b467', true, true, false, false, true, 1, 'a small feather or a piece of down', 'Find Greater Steed', 'Sight', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You conjure a portal linking an unoccupied space you can see within range to a precise location on a different plane of existence. The portal is a circular opening, which you can make 5 to 20 feet in diameter. You can orient the portal in any direction you choose. The portal lasts for the duration, and the portal’s destination is visible through it. The portal has a front and a back on each plane where it appears. Travel through the portal is possible only by moving through its front. Anything that does so is instantly transported to the other plane, appearing in the unoccupied space nearest to the portal. Deities and other planar rulers can prevent portals created by this spell from opening in their presence or anywhere within their domains. When you cast this spell, you can speak the name of a specific creature (a pseudonym, title, or nickname doesn’t work). If that creature is on a plane other than the one you are on, the portal opens next to the named creature and transports it to the nearest unoccupied space on your side of the portal. You gain no special power over the creature, and it is free to act as the DM deems appropriate. It might leave, attack you, or help you.', 'Concentration, up to 1 minute', '2c0af5d0-d786-4cbc-b3b8-e4b59cb67adb', false, true, false, true, true, 1, 'a lodestone and a pinch of dust', 'Mind Spike', 'Self', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You attempt to beguile a Humanoid. It makes a Wisdom save or has the Charmed condition. While Charmed, you have a telepathic link and can issue commands.', 'Concentration, up to 10 minutes', '65516d34-bc09-422c-88e9-23e570b15336', false, false, false, false, true, 1, NULL, 'Levitate', '60 feet', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action (Overgrowth) or 8 hours (Enrichment)', '2026-05-15 05:45:35.483105+00', 'One creature of your choice that you can see within range makes a Wisdom saving throw. On a failed save, it has the Prone and Incapacitated conditions for the duration. During that time, it laughs uncontrollably if it’s capable of laughter, and it can’t end the Prone condition on itself. At the end of each of its turns and each time it takes damage, it makes another Wisdom saving throw. The target has Advantage on the save if the save is triggered by damage. On a successful save, the spell ends.', 'Until dispelled', 'f510824f-d4d1-40f9-ac43-f2c37f89f156', false, false, false, true, true, 3, 'powdered rhubarb leaf', 'Teleportation Circle', '60 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You shape a creature''s dreams. You or a messenger appears in the dreams of a target you know and can converse with it as long as it is asleep.', '10 days', '9fc6c0dc-2b68-4841-ab0c-b65e4e29425b', false, true, false, true, true, 0, 'the petrified eye of a newt', 'Mass Heal', '120 feet', 'Transmutation', 'Use the spell slot’s level for the spell’s level in the stat block.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch a creature that has died within the last minute. That creature revives with 1 Hit Point. This spell can’t revive a creature that has died of old age, nor does it restore any missing body parts.', 'Concentration, up to 1 minute', 'ead35d40-f985-4b8d-8d6d-640842b8cde9', false, false, false, true, true, 1, NULL, 'Power Word Heal', 'Touch', 'Evocation', 'The damage of an explosive rune increases by 1d8 for each spell slot level above 3. If you create a spell glyph, you can store any spell of up to the same level as the spell slot you use for the Glyph of Warding.', '2026-05-15 05:45:35.483105+00'),
	('1 minute or Ritual', '2026-05-15 05:45:35.483105+00', 'An imperceptible barrier of magical force protects you. Until the start of your next turn, you have a +5 bonus to AC, including against the triggering attack, and you take no damage from Magic Missile.', 'Until dispelled', 'd4d37b68-c303-4e79-8f91-b1c9dcb1d3c1', false, true, false, true, true, 3, NULL, 'Hail of Thorns', '10 feet', 'Evocation', 'You can target one additional creature for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'For the duration, you sense the presence of magic within 30 feet of you. You can take a Magic action to see a faint aura around visible creatures or objects that bear magic.', 'Concentration, up to 10 minutes', 'b0f95337-0c43-4d82-a346-98739050e5db', false, true, false, false, false, 5, 'a small amount of makeup applied to the face as this spell is cast', 'Tasha’s Bubbling Cauldron', 'Touch', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You shape a creature''s dreams. You or a messenger appears in the dreams of a target you know and can converse with it as long as it is asleep.', 'Concentration, up to 1 day', '355b25f8-b12c-4a50-9b4a-0466f0f37c3c', false, true, false, true, true, 5, 'a locust', 'Goodberry', '60 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action or Ritual', '2026-05-15 05:45:35.483105+00', 'Name or describe a famous person, place, or object. The spell brings to your mind a brief summary of the significant lore about that famous thing, as described by the DM. The lore might consist of important details, amusing revelations, or even secret lore that has never been widely known. The more information you already know about the thing, the more precise and detailed the information you receive is. That information is accurate but might be couched in figurative language or poetry, as determined by the DM. If the famous thing you chose isn’t actually famous, you hear sad musical notes played on a trombone, and the spell fails.', 'Concentration, up to 1 hour', '43343e04-f3de-43b8-8214-e6a3d555e1f1', false, true, false, true, true, 5, NULL, 'Mind Blank', 'Self', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You point at a location within range, and a glowing, 1-foot-diameter ball of acid streaks there and explodes in a 20-foot-radius Sphere. Each creature in that area makes a Dexterity saving throw. On a failed save, a creature takes 10d4 Acid damage and another 5d4 Acid damage at the end of its next turn. On a successful save, a creature takes half the initial damage only.', 'Instantaneous', 'db1a62d1-c20e-485d-892d-e1936a1d47ed', false, true, false, true, true, 6, 'mistletoe', 'Reincarnate', '90 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You surround yourself with unearthly majesty in a 10-foot Emanation. Whenever the Emanation enters the space of a creature you can see and whenever a creature you can see enters the Emanation or ends its turn there, you can force that creature to make a Wisdom saving throw. On a failed save, the target takes 4d6 Psychic damage and has the Prone condition, and you can push it up to 10 feet away. On a successful save, the target takes half as much damage only. A creature makes this save only once per turn.', '10 minutes', 'b09d35e0-89e2-46de-8cbc-8c7a915a45e7', false, true, true, true, true, 3, NULL, 'Daylight', '60 feet', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You strike the ground, creating a shockwave in a 30-foot Emanation. Each creature of your choice takes 5d6 Thunder damage and 5d6 Radiant or Necrotic damage and is knocked Prone (Con save for half).', 'Concentration, up to 10 minutes', 'c8626e39-d3b9-47e4-82e4-ad0aaa691666', true, true, false, false, true, 5, 'a leather strap, bound around the arm or a similar appendage', 'Heroes'' Feast', 'Self', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'This spell grants the creature you touch the ability to understand any spoken or signed language that it hears or sees. Moreover, when the target communicates by speaking or signing, any creature that knows at least one language can understand it if that creature can hear the speech or see the signing.', 'Concentration, up to 1 minute', 'f480b70f-e04c-4231-b003-b8af639ecf7e', true, true, true, true, false, 2, NULL, 'See Invisibility', 'Touch', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 minute', '2026-05-15 05:45:35.483105+00', 'You touch a willing creature and bestow a limited ability to see into the immediate future. The target has Advantage on attack rolls, ability checks, and saving throws.', '8 hours', '252b20ce-6ef3-4b81-a45a-2b519284a8f5', false, true, false, true, true, 0, NULL, 'Speak with Animals', '60 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Choose a creature that you can see within range. The target must succeed on a Wisdom saving throw or have the Paralyzed condition for the duration. At the end of each of its turns, the target repeats the save, ending the spell on itself on a success.', 'Instantaneous', 'c3e46480-5b38-47d9-985f-8fc969f10a5a', true, false, true, true, true, 1, 'a drop of bitumen and a spider', 'Forbiddance', '120 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'This spell channels vitality into plants. The casting time you use determines whether the spell has the Overgrowth or the Enrichment effect below. Overgrowth. Choose a point within range. All normal plants in a 100-foot-radius Sphere centered on that point become thick and overgrown. A creature moving through that area must spend 4 feet of movement for every 1 foot it moves. You can exclude one or more areas of any size within the spell’s area from being affected. Enrichment. All plants in a half-mile radius centered on a point within range become enriched for 365 days. The plants yield twice the normal amount of food when harvested. They can benefit from only one Plant Growth per year.', '1 round', '39c58cfc-9102-4f0f-ad2c-f38870f96a35', false, false, false, true, true, 7, 'a bit of fleece', 'Summon Undead', 'Self', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('10 minutes', '2026-05-15 05:45:35.483105+00', 'A creature you touch becomes Invisible. The spell ends early if the target attacks or casts a spell.', 'Concentration, up to 10 minutes', '090abae9-46f5-44a3-9647-87aeb337b7e9', false, false, false, true, true, 5, NULL, 'Divine Smite', '90 feet', 'Divination', 'The initial damage increases by 1d12 for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A churning storm cloud forms for the duration, centered on a point within range and spreading to a radius of 300 feet. Each creature under the cloud when it appears must succeed on a Constitution saving throw or take 2d6 Thunder damage and have the Deafened condition for the duration. At the start of each of your later turns, the storm produces different effects, as detailed below. Turn 2. Acidic rain falls. Each creature and object under the cloud takes 4d6 Acid damage. Turn 3. You call six bolts of lightning from the cloud to strike six different creatures or objects beneath it. Each target makes a Dexterity saving throw, taking 10d6 Lightning damage on a failed save or half as much damage on a successful one. Turn 4. Hailstones rain down. Each creature under the cloud takes 2d6 Bludgeoning damage. Turns 5–10. Gusts and freezing rain assail the area under the cloud. Each creature there takes 1d6 Cold damage. Until the spell ends, the area is Difficult Terrain and Heavily Obscured, ranged attacks with weapons are impossible there, and strong wind blows through the area.', 'Concentration, up to 1 minute', '86170e30-4bbb-44fd-b3f6-4fb0d2d75381', false, true, false, true, true, 1, NULL, 'Greater Restoration', '60 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create a floating, spectral force that resembles a weapon of your choice and lasts for the duration. The force appears within range in a space of your choice, and you can immediately make one melee spell attack against one creature within 5 feet of the force. On a hit, the target takes Force damage equal to 1d8 plus your spellcasting ability modifier. As a Bonus Action on your later turns, you can move the force up to 20 feet and repeat the attack against a creature within 5 feet of it.', 'Instantaneous', '774fd8fa-c62b-440a-b909-3fcbacd359c1', false, false, false, true, true, 1, 'a pair of linked silver rings', 'Haste', 'Self', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'As your attack hits or misses the target, the weapon or ammunition you’re using transforms into a lightning bolt. Instead of taking any damage or other effects from the attack, the target takes 4d8 Lightning damage on a hit or half as much damage on a miss. Each creature within 10 feet of the target then makes a Dexterity saving throw, taking 2d8 Lightning damage on a failed save or half as much damage on a successful one. The weapon or ammunition then returns to its normal form.', 'Concentration, up to 1 hour', '1bd5b73b-dc29-4eb1-874d-f3930148e8dd', false, true, false, false, true, 4, NULL, 'Incendiary Cloud', '60 feet', 'Evocation', 'The damage increases by 1d10 for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You summon a spirit that takes the form of an unusually intelligent, strong, and loyal steed. While mounted, you can make any spell you cast that targets only you also target your steed.', '24 hours', 'dd68b6ff-b6ed-4d5e-add0-0fce7b52db92', false, true, false, true, true, 6, 'a small amount of alcohol or distilled spirits', 'Disintegrate', 'Self', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A beam of enervating energy shoots from you toward a creature within range. The target must make a Constitution saving throw. On a successful save, the target has Disadvantage on the next attack roll it makes until the start of your next turn. On a failed save, the target has Disadvantage on Strength-based d20 Tests for the duration. During that time, it also subtracts 1d8 from all its damage rolls. The target repeats the save at the end of each of its turns, ending the spell on a success.', 'Instantaneous', '25793cec-693c-4e87-93de-d4aef6a2a70f', false, true, false, true, true, 3, 'a jade circlet worth 1,500+ GP', 'Find Steed', '60 feet', 'Evocation', 'Your Concentration can last longer with a spell slot of level 2 (up to 4 hours), 3–4 (up to 8 hours), or 5+ (24 hours).', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You hurl a mote of fire at a creature or object within range. Make a ranged spell attack. On a hit, the target takes 1d10 Fire damage.', 'Instantaneous', 'f1f07c37-e412-4812-b204-0a585b027e0a', true, false, false, false, true, 1, 'seven thorns', 'Sleet Storm', '30 feet', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You remove poison and rot from nonmagical food and drink in a 5-foot-radius Sphere centered on a point within range.', 'Concentration, up to 1 hour', 'b3397e52-ada0-46fe-a23f-046cdb7eddb5', true, true, true, true, true, 2, 'lead-based ink worth 10 GP', 'Harm', '60 feet', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Reaction, which you take when you are hit by an attack roll or targeted by the Magic Missile spell', '2026-05-15 05:45:35.483105+00', 'You transform a willing creature and its gear into a misty cloud. The target has a flying speed of 10 feet, resistance to nonmagical damage, and advantage on STR, DEX, and CON saves. It can pass through small holes but cannot attack or cast spells.', 'Concentration, up to 1 minute', 'da080096-c94c-4e87-a540-c4b3c87caff9', false, true, false, true, false, 5, 'a bit of fleece', 'Wall of Fire', '120 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You gain the ability to enter a tree and move from inside it to inside another tree of the same kind within 500 feet. Both trees must be living and at least the same size as you. You must use 5 feet of movement to enter a tree. You instantly know the location of all other trees of the same kind within 500 feet and, as part of the move used to enter the tree, can either pass into one of those trees or step out of the tree you’re in. You appear in a spot of your choice within 5 feet of the destination tree, using another 5 feet of movement. If you have no movement left, you appear within 5 feet of the tree you entered. You can use this transportation ability only once on each of your turns. You must end each turn outside a tree.', 'Concentration, up to 1 minute', '46cf868c-fdff-417d-b5ac-f02a37cb4ab4', true, true, true, true, false, 1, NULL, 'Stone Shape', '150 feet', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'Choose a willing creature that you can see within range. Until the spell ends, the target’s Speed is doubled, it gains a +2 bonus to Armor Class, it has Advantage on Dexterity saving throws, and it gains an additional action on each of its turns. That action can be used to take only the Attack (one attack only), Dash, Disengage, Hide, or Utilize action. When the spell ends, the target is Incapacitated and has a Speed of 0 until the end of its next turn, as a wave of lethargy washes over it.', 'Instantaneous', '04597f87-c86d-42ee-8187-50a8d6e2641f', false, false, false, true, true, 5, NULL, 'Harm', 'Touch', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 minute', '2026-05-15 05:45:35.483105+00', 'A swirling cloud of white-hot embers spreads in a 20-foot-radius sphere. Creatures in the cloud take 10d8 Fire damage (DEX save for half). The cloud moves 10 feet away from you at the start of each of your turns.', 'Concentration, up to 1 minute', '34ca608f-aad2-4bf2-a8ed-a225690f1170', true, true, false, true, true, 9, 'a live insect', 'Dancing Lights', 'Touch', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You beseech an otherworldly entity for aid. The being must be known to you: a god, a demon prince, or some other being of cosmic power. That entity sends a Celestial, an Elemental, or a Fiend loyal to it to aid you, making the creature appear in an unoccupied space within range. If you know a specific creature’s name, you can speak that name when you cast this spell to request that creature, though you might get a different creature anyway (DM’s choice). When the creature appears, it is under no compulsion to behave a particular way. You can ask it to perform a service in exchange for payment, but it isn’t obliged to do so. The requested task could range from simple (fly us across the chasm, or help us fight a battle) to complex (spy on our enemies, or protect us during our foray into the dungeon). You must be able to communicate with the creature to bargain for its services. Payment can take a variety of forms. A Celestial might require a sizable donation of gold or magic items to an allied temple, while a Fiend might demand a living sacrifice or a gift of treasure. Some creatures might exchange their service for a quest undertaken by you. A task that can be measured in minutes requires a payment worth 100 GP per minute. A task measured in hours requires 1,000 GP per hour. And a task measured in days (up to 10 days) requires 10,000 GP per day. The DM can adjust these payments based on the circumstances under which you cast the spell. If the task is aligned with the creature’s ethos, the payment might be halved or even waived. Nonhazardous tasks typically require only half the suggested payment, while especially dangerous tasks might require a greater gift. Creatures rarely accept tasks that seem suicidal. After the creature completes the task, or when the agreed-upon duration of service expires, the creature returns to its home plane after reporting back to you if possible. If you are unable to agree on a price for the creature’s service, the creature immediately returns to its home plane.', 'Concentration, up to 1 minute', '7c477782-cb7b-4cba-97fb-a25036a0b9f7', false, true, false, true, true, 7, 'a sprig of mistletoe', 'Hunter’s Mark', '300 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create a magical effect within range. Choose the effect from the options below. If you cast this spell multiple times, you can have up to three of its non-instantaneous effects active at a time. Sensory Effect. You create an instantaneous, harmless sensory effect, such as a shower of sparks, a puff of wind, faint musical notes, or an odd odor. Fire Play. You instantaneously light or snuff out a candle, a torch, or a small campfire. Clean or Soil. You instantaneously clean or soil an object no larger than 1 cubic foot. Minor Sensation. You chill, warm, or flavor up to 1 cubic foot of nonliving material for 1 hour. Magic Mark. You make a color, a small mark, or a symbol appear on an object or a surface for 1 hour. Minor Creation. You create a nonmagical trinket or an illusory image that can fit in your hand. It lasts until the end of your next turn. A trinket can deal no damage and has no monetary worth.', 'Concentration, up to 10 minutes', '9ac14f79-ec79-4d4c-b941-7c694570250d', false, true, false, true, true, 2, NULL, 'Longstrider', 'Touch', 'Necromancy', 'The damage increases by 1d6 for each spell slot level above 3.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Flame-like radiance descends on a creature that you can see within range. The target must succeed on a Dexterity saving throw or take 1d8 Radiant damage. The target gains no benefit from Half Cover or Three-Quarters Cover for this save. Cantrip Upgrade. The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).', '1 hour', 'b8c1f9aa-1eed-40d7-b58b-d0acae4f1f8b', true, true, true, false, true, 0, NULL, 'Acid Splash', 'Touch', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'This spell channels vitality into plants. The casting time you use determines whether the spell has the Overgrowth or the Enrichment effect below. Overgrowth. Choose a point within range. All normal plants in a 100-foot-radius Sphere centered on that point become thick and overgrown. A creature moving through that area must spend 4 feet of movement for every 1 foot it moves. You can exclude one or more areas of any size within the spell’s area from being affected. Enrichment. All plants in a half-mile radius centered on a point within range become enriched for 365 days. The plants yield twice the normal amount of food when harvested. They can benefit from only one Plant Growth per year.', '8 hours', 'f96da067-2fef-4a5b-b46d-277ff9e55964', false, true, false, true, true, 1, NULL, 'Greater Invisibility', '120 feet', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'The target takes an extra 1d6 Necrotic damage from the attack, and it must succeed on a Wisdom saving throw or have the Frightened condition until the spell ends. At the end of each of its turns, the Frightened target repeats the save, ending the spell on itself on a success.', 'Instantaneous', 'dbccbb38-2b0e-4e3c-a802-05439f24faa9', true, false, false, true, true, 5, NULL, 'Water Breathing', '60 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Thin and wispy flames wreathe your body. You have Resistance to Cold or Fire damage, and creatures that hit you with a melee attack take 2d8 damage of the other type.', 'Concentration, up to 1 hour', 'e02f43ca-520f-448e-b06c-3d5441d70641', true, false, false, true, true, 4, 'a miniature tiara', 'Summon Elemental', '60 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'This spell instantly transports you and up to eight willing creatures that you can see within range, or a single object that you can see within range, to a destination you select. If you target an object, it must be Large or smaller, and it can’t be held or carried by an unwilling creature. The destination you choose must be known to you, and it must be on the same plane of existence as you. Your familiarity with the destination determines whether you arrive there successfully. The DM rolls 1d100 and consults the Teleportation Outcome table and the explanations after it. Teleportation Outcome Familiarity Mishap Similar Area Off Target On Target Permanent circle — — — 01–00 Linked object — — — 01–00 Very familiar 01–05 06–13 14–24 25–00 Seen casually 01–33 34–43 44–53 54–00 Viewed once or described 01–43 44–53 54–73 74–00 False destination 01–50 51–00 — — Familiarity. Here are the meanings of the terms in the table’s Familiarity column: “Permanent circle” means a permanent teleportation circle whose sigil sequence you know. “Linked object” means you possess an object taken from the desired destination within the last six months, such as a book from a wizard’s library. “Very familiar” is a place you have visited often, a place you have carefully studied, or a place you can see when you cast the spell. “Seen casually” is a place you have seen more than once but with which you aren’t very familiar. “Viewed once or described” is a place you have seen once, possibly using magic, or a place you know through someone else’s description, perhaps from a map. “False destination” is a place that doesn’t exist. Perhaps you tried to scry an enemy’s sanctum but instead viewed an illusion, or you are attempting to teleport to a location that no longer exists. Mishap. The spell’s unpredictable magic results in a difficult journey. Each teleporting creature (or the target object) takes 3d10 Force damage, and the DM rerolls on the table to see where you wind up (multiple mishaps can occur, dealing damage each time). Similar Area. You and your group (or the target object) appear in a different area that’s visually or thematically similar to the target area. You appear in the closest similar place. If you are heading for your home laboratory, for example, you might appear in another person’s laboratory in the same city. Off Target. You and your group (or the target object) appear 2d12 miles away from the destination in a random direction. Roll 1d8 for the direction: 1, east; 2, southeast; 3, south; 4, southwest; 5, west; 6, northwest; 7, north; or 8, northeast. On Target. You and your group (or the target object) appear where you intended.', 'Instantaneous', '1acd8295-b0ff-4b67-84f4-3d4fdc14442f', false, false, true, true, true, 9, 'a caterpillar cocoon', 'Transport via Plants', '60 feet', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Until the spell ends, one willing creature you touch has Immunity to Psychic damage and the Charmed condition. The target is also unaffected by anything that would sense its emotions or alignment, read its thoughts, or magically detect its location, and no spell—not even Wish —can gather information about the target, observe it remotely, or control its mind.', 'Concentration, up to 1 minute', '81872f5b-d7fa-4eaf-ae71-032dae82b782', false, true, false, true, true, 4, NULL, 'Fire Bolt', '30 feet', 'Evocation', 'The damage increases by 1d6 for each spell slot level above 3.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You sense the presence of any trap within range that is within your line of sight. A trap, for the purpose of this spell, includes anything that would inflict a sudden or unexpected effect.', 'Instantaneous', 'a671ed0a-905d-4a5d-a815-6d07ba6a3a69', false, true, false, false, true, 2, 'a mix of salt, powdered silver, and holy water worth 1,000+ GP, which the spell consumes', 'Hunter’s Mark', 'Touch', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You attempt to beguile a creature. It makes a Wisdom save or has the Charmed condition. While Charmed, you have a telepathic link and can issue commands.', 'Instantaneous', '4f7f641f-de7b-4b2e-8953-3503ca389e57', false, true, false, true, true, 2, 'a snake’s tongue', 'Silence', 'Touch', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('10 minutes', '2026-05-15 05:45:35.483105+00', 'One creature or loose object of your choice that you can see within range rises vertically up to 20 feet and remains suspended there for the duration. The spell can levitate an object that weighs up to 500 pounds. An unwilling creature that succeeds on a Constitution saving throw is unaffected. The target can move only by pushing or pulling against a fixed object or surface within reach (such as a wall or a ceiling), which allows it to move as if it were climbing. You can change the target’s altitude by up to 20 feet in either direction on your turn. If you are the target, you can move up or down as part of your move. Otherwise, you can take a Magic action to move the target, which must remain within the spell’s range. When the spell ends, the target floats gently to the ground if it is still aloft.', 'Concentration, up to 10 minutes', '6344cae8-3cb7-4eb9-9e7d-e506e12c75cb', true, false, false, true, false, 3, NULL, 'Mirage Arcane', 'Self', 'Evocation', 'The damage increases by 1d6 for every two spell slot levels above 2.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch a stone object of Medium size or smaller or a section of stone no more than 5 feet in any dimension and form it into any shape you like. For example, you could shape a large rock into a weapon, statue, or coffer, or you could make a small passage through a wall that is 5 feet thick. You could also shape a stone door or its frame to seal the door shut. The object you create can have up to two hinges and a latch, but finer mechanical detail isn’t possible.', 'Concentration, up to 10 minutes', '10a19a3b-6143-43bc-9114-d5772e1d7841', false, true, false, true, true, 5, 'a pair of linked silver rings', 'Shapechange', '30 feet', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'The target hit by the strike takes an extra 2d6 Radiant damage from the attack. Until the spell ends, the target sheds Bright Light in a 5-foot radius, attack rolls against it have Advantage, and it can’t benefit from the Invisible condition.', '1 hour', '0216c32e-5950-45b4-a402-b834e28d4bc3', false, true, false, true, true, 2, NULL, 'Lightning Arrow', '5 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 minute or Ritual', '2026-05-15 05:45:35.483105+00', 'A tiny yellow bead streaks to a point and lingers. When the spell ends or you detonate it, creatures in a 20-foot-radius Sphere take 12d6 Fire damage (Dex save for half). Damage increases if you wait to detonate.', 'Concentration, up to 1 hour', 'bfbc85bf-f57d-46f4-bcc6-b11c7f107ec2', true, true, false, false, true, 3, 'a gilded skull worth 300+ GP', 'Starry Wisp', 'Self', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You briefly stop the flow of time for everyone but yourself. No time passes for other creatures, while you take 1d4 + 1 turns in a row, during which you can use actions and move as normal. This spell ends if one of the actions you use during this period, or any effects that you create during it, affects a creature other than you or an object being worn or carried by someone other than you. In addition, the spell ends if you move to a place more than 1,000 feet from the location where you cast it.', '1 hour', 'b4cc9fb0-0c52-4516-9068-35377067816d', false, true, false, false, true, 0, NULL, 'Power Word Stun', 'Touch', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You attempt to craft an illusion in the mind of a creature you can see within range. The target makes an Intelligence saving throw. On a failed save, you create a phantasmal object, creature, or other phenomenon that is no larger than a 10-foot Cube and that is perceivable only to the target for the duration. The phantasm includes sound, temperature, and other stimuli. The target can take a Study action to examine the phantasm with an Intelligence (Investigation) check against your spell save DC. If the check succeeds, the target realizes that the phantasm is an illusion, and the spell ends. While affected by the spell, the target treats the phantasm as if it were real and rationalizes any illogical outcomes from interacting with it. For example, if the target steps through a phantasmal bridge and survives the fall, it believes the bridge exists and something else caused it to fall. An affected target can even take damage from the illusion if the phantasm represents a dangerous creature or hazard. On each of your turns, such a phantasm can deal 2d8 Psychic damage to the target if it is in the phantasm’s area or within 5 feet of the phantasm. The target perceives the damage as a type appropriate to the illusion.', 'Concentration, up to 10 minutes', '819e14ca-eaf9-427c-9e9b-f51c9bf5cf9b', true, true, true, true, true, 1, 'pickled octopus tentacle', 'Heat Metal', 'Self', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A frigid globe streaks from you to a point of your choice within range, where it explodes in a 60-foot-radius Sphere. Each creature in that area makes a Constitution saving throw, taking 10d6 Cold damage on a failed save or half as much damage on a successful one. If the globe strikes a body of water, it freezes the water to a depth of 6 inches over an area 30 feet square. This ice lasts for 1 minute. Creatures that were swimming on the surface of frozen water are trapped in the ice and have the Restrained condition. A trapped creature can take an action to make a Strength (Athletics) check against your spell save DC to break free. You can refrain from firing the globe after completing the spell’s casting. If you do so, a globe about the size of a sling bullet, cool to the touch, appears in your hand. At any time, you or a creature you give the globe to can throw the globe (to a range of 40 feet) or hurl it with a sling (to the sling’s normal range). It shatters on impact, with the same effect as a normal casting of the spell. You can also set the globe down without shattering it. After 1 minute, if the globe hasn’t already shattered, it explodes.', 'Instantaneous', 'e91654b3-c402-40ca-8966-fcc40cbc5b08', true, false, false, false, true, 9, 'a diamond worth 50+ GP', 'Gaseous Form', '60 feet', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You compel one creature you can see within range to die. If the target has 100 Hit Points or fewer, it dies. Otherwise, it takes 12d12 Psychic damage.', '1 hour', '838e4e43-5306-40db-874f-d4500d1996a4', true, false, false, true, true, 1, NULL, 'Magic Missile', '300 feet', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'You surge positive energy into a creature, restoring 70 HP. It also ends Blinded, Deafened, and any diseases.', '8 hours', 'b29a49e0-71b1-473d-98ff-2d89ccd134f5', false, false, false, true, true, 5, NULL, 'Unseen Servant', 'Self', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch a creature that has died within the last minute. That creature revives with 1 Hit Point. This spell can’t revive a creature that has died of old age, nor does it restore any missing body parts.', 'Instantaneous', '120a2f26-d2c8-49e8-8a49-467ab89006ce', false, false, false, true, true, 0, 'mistletoe', 'Detect Thoughts', 'Self', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Lightning springs from you to a creature that you try to touch. Make a melee spell attack against the target. On a hit, the target takes 1d8 Lightning damage, and it can’t make Opportunity Attacks until the start of its next turn. Cantrip Upgrade. The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).', 'Instantaneous', 'f49aa03c-50db-4591-9fdb-bf5fbd3ff5e9', true, true, false, true, true, 9, 'burning incense', 'Spiritual Weapon', 'Self', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action or Ritual', '2026-05-15 05:45:35.483105+00', 'Make a melee spell attack against a creature you can reach. On a hit, the target takes 3d10 Necrotic damage.', 'Concentration, up to 1 minute', '857fb463-7cf2-40d8-9d4a-5d15c114d389', false, false, false, true, true, 6, NULL, 'Ice Storm', '60 feet', 'Evocation', 'The damage increases by 1d10 for each spell slot level above 2.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'The target takes an extra 1d6 Necrotic damage from the attack, and it must succeed on a Wisdom saving throw or have the Frightened condition until the spell ends. At the end of each of its turns, the Frightened target repeats the save, ending the spell on itself on a success.', '8 hours', 'f68baf3a-7342-47e9-bfab-53389d697b52', false, true, false, false, true, 8, NULL, 'Water Breathing', 'Touch', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create a wall of tangled brush bristling with needle-sharp thorns. The wall appears within range on a solid surface and lasts for the duration. You choose to make the wall up to 60 feet long, 10 feet high, and 5 feet thick or a circle that has a 20-foot diameter and is up to 20 feet high and 5 feet thick. The wall blocks line of sight. When the wall appears, each creature in its area makes a Dexterity saving throw, taking 7d8 Piercing damage on a failed save or half as much damage on a successful one. A creature can move through the wall, albeit slowly and painfully. For every 1 foot a creature moves through the wall, it must spend 4 feet of movement. Furthermore, the first time a creature enters a space in the wall on a turn or ends its turn there, the creature makes a Dexterity saving throw, taking 7d8 Slashing damage on a failed save or half as much damage on a successful one. A creature makes this save only once per turn.', 'Concentration, up to 1 minute', 'dafed634-c577-4486-8eda-35d4f8e558f6', false, true, false, true, true, 7, NULL, 'Delayed Blast Fireball', '120 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Choose one creature or nonmagical object that you can see within range. The creature shape-shifts into a different creature or a nonmagical object, or the object shape-shifts into a creature (the object must be neither worn nor carried). The transformation lasts for the duration or until the target dies or is destroyed, but if you maintain Concentration on this spell for the full duration, the spell lasts until dispelled. An unwilling creature can make a Wisdom saving throw, and if it succeeds, it isn’t affected by this spell. Creature into Creature. If you turn a creature into another kind of creature, the new form can be any kind you choose that has a Challenge Rating equal to or less than the target’s Challenge Rating or level. The target’s game statistics are replaced by the stat block of the new form, but it retains its Hit Points, Hit Point Dice, alignment, and personality. The target gains a number of Temporary Hit Points equal to the Hit Points of the new form. These Temporary Hit Points vanish if any remain when the spell ends. The target is limited in the actions it can perform by the anatomy of its new form, and it can’t speak or cast spells. The target’s gear melds into the new form. The creature can’t use or otherwise benefit from any of that equipment. Object into Creature. You can turn an object into any kind of creature, as long as the creature’s size is no larger than the object’s size and the creature has a Challenge Rating of 9 or lower. The creature is Friendly to you and your allies. In combat, it takes its turns immediately after yours, and it obeys your commands. If the spell lasts more than an hour, you no longer control the creature. It might remain Friendly to you, depending on how you have treated it. Creature into Object. If you turn a creature into an object, it transforms along with whatever it is wearing and carrying into that form, as long as the object’s size is no larger than the creature’s size. The creature’s statistics become those of the object, and the creature has no memory of time spent in this form after the spell ends and it returns to normal.', 'Concentration, up to 1 minute', '207ff1be-9ad4-4479-9797-4bcf9d59e92f', false, true, false, true, true, 1, 'rare inks worth 50+ GP, which the spell consumes', 'Programmed Illusion', '120 feet', 'Transmutation', 'You can target one additional Humanoid for each spell slot level above 2.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch a creature and grant it a measure of protection from death. The first time it would drop to 0 HP, it drops to 1 HP instead. It also neutralizes effects that would kill it instantly.', 'Concentration, up to 1 minute', '214940b1-5c3e-4de1-bd16-af9ab1012fc5', true, false, false, true, true, 6, 'a miniature umbrella', 'Mass Heal', '120 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 hour', '2026-05-15 05:45:35.483105+00', 'You call forth an aberrant spirit. It manifests in an unoccupied space that you can see within range and uses the Aberrant Spirit stat block. When you cast the spell, choose Beholderkin, Mind Flayer, or Slaad. The creature resembles an Aberration of that kind, which determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends. The creature is an ally to you and your allies. In combat, it shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the Dodge action and uses its movement to avoid danger. Aberrant Spirit Medium Aberration, Neutral AC 11 + the spell’s level HP 40 + 10 for each spell level above 4 Speed 30 ft.; Fly 30 ft. (hover; Beholderkin only) Mod Save STR 16 +3 +3 DEX 10 +0 +0 CON 15 +2 +2 Mod Save INT 16 +3 +3 WIS 10 +0 +0 CHA 6 -2 -2 Immunities Psychic Senses Darkvision 60 ft.; Passive Perception 10 Languages Deep Speech, understands the languages you know CR None (XP 0; PB equals your Proficiency Bonus) Traits Regeneration (Slaad Only). The spirit regains 5 Hit Points at the start of its turn if it has at least 1 Hit Point. Whispering Aura (Mind Flayer Only). At the start of each of the spirit’s turns, the spirit emits psionic energy if it doesn’t have the Incapacitated condition. Wisdom Saving Throw: DC equals your spell save DC, each creature (other than you) within 5 feet of the spirit. Failure: 2d6 Psychic damage. Actions Multiattack. The spirit makes a number of attacks equal to half this spell’s level (round down). Claw (Slaad Only). Melee Attack Roll: Bonus equals your spell attack modifier, reach 5 ft. Hit: 1d10 + 3 + the spell’s level Slashing damage, and the target can’t regain Hit Points until the start of the spirit’s next turn. Eye Ray (Beholderkin Only). Ranged Attack Roll: Bonus equals your spell attack modifier, range 150 ft. Hit: 1d8 + 3 + the spell’s level Psychic damage. Psychic Slam (Mind Flayer Only). Melee Attack Roll: Bonus equals your spell attack modifier, reach 5 ft. Hit: 1d8 + 3 + the spell’s level Psychic damage.', 'Concentration, up to 1 minute', '30924ed0-fdf5-4ec6-b274-8661d352e316', true, true, false, true, true, 1, NULL, 'Goodberry', '60 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Triggered when you take damage from a creature. The target must make a DEX save or take 2d10 Fire damage (half on success).', 'Instantaneous', 'c5831778-1afc-494b-b5fc-a5806ac1abed', true, false, false, true, true, 3, NULL, 'Longstrider', '10 feet', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Choose a Humanoid that you can see within range. The target must succeed on a Wisdom saving throw or have the Paralyzed condition for the duration. At the end of each of its turns, the target repeats the save, ending the spell on itself on a success.', '8 hours', '7d31899f-32d9-48b4-8bcb-7e109ecd4204', false, false, false, true, true, 6, 'an eyelash in gum arabic', 'Leomund’s Tiny Hut', '30 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You place a magical command on a creature you can see. If it deviates from your instructions, it takes 5d10 psychic damage (once per day). Removing the spell requires Remove Curse, Greater Restoration, or Wish.', 'Instantaneous', '8ba3efa1-6c1e-46df-baf2-79ae23d7b8c8', true, true, false, true, true, 4, 'a chip of mica', 'Gate', '5 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Reaction', '2026-05-15 05:45:35.483105+00', 'You give a verbal command to a creature that you can see within range, ordering it to carry out some service or refrain from an action or a course of activity as you decide. The target must succeed on a Wisdom saving throw or have the Charmed condition for the duration. The target automatically succeeds if it can’t understand your command. While Charmed, the creature takes 5d10 Psychic damage if it acts in a manner directly counter to your command. It takes this damage no more than once each day. You can issue any command you choose, short of an activity that would result in certain death. Should you issue a suicidal command, the spell ends. A Remove Curse, Greater Restoration, or Wish spell ends this spell.', 'Instantaneous', '0374e28e-e56d-47f5-a5a6-d84d1ad093c6', true, true, false, true, true, 2, NULL, 'Protection from Energy', 'Self', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Focus your mind to read the thoughts of others. You can read surface thoughts or probe deeper, though the target can make a Wisdom save to resist.', '24 hours', 'd2cd7a1a-585d-41f9-bd55-aca8f79e9e4f', false, true, false, false, true, 5, 'a mix of salt, powdered silver, and holy water worth 1,000+ GP, which the spell consumes', 'Leomund’s Secret Chest', 'Self', 'Transmutation', 'The damage increases by 1d10 for each spell slot level above 5.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Brilliant sunlight flashes in a 60-foot-radius Sphere centered on a point you choose within range. Each creature in the Sphere makes a Constitution saving throw. On a failed save, a creature takes 12d6 Radiant damage and has the Blinded condition for 1 minute. On a successful save, it takes half as much damage only. A creature Blinded by this spell makes another Constitution saving throw at the end of each of its turns, ending the effect on itself on a success. This spell dispels Darkness in its area that was created by any spell.', 'Instantaneous', '9e7b0ae4-c1a5-4a7b-a623-17423de930aa', false, false, false, true, true, 2, 'a bit of pork rind or butter', 'Power Word Stun', 'Self', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You sense the presence of any trap within range that is within your line of sight. A trap, for the purpose of this spell, includes anything that would inflict a sudden or unexpected effect.', 'Instantaneous', 'a9e02932-1b9f-40d4-8de0-3354b6d8980c', true, true, false, true, true, 4, 'pearl worth 100 GP and an owl feather', 'Tasha’s Hideous Laughter', '90 feet', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'You call forth an aberrant spirit. It manifests in an unoccupied space that you can see within range and uses the Aberrant Spirit stat block. When you cast the spell, choose Beholderkin, Mind Flayer, or Slaad. The creature resembles an Aberration of that kind, which determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends. The creature is an ally to you and your allies. In combat, it shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don’t issue any, it takes the Dodge action and uses its movement to avoid danger. Aberrant Spirit Medium Aberration, Neutral AC 11 + the spell’s level HP 40 + 10 for each spell level above 4 Speed 30 ft.; Fly 30 ft. (hover; Beholderkin only) Mod Save STR 16 +3 +3 DEX 10 +0 +0 CON 15 +2 +2 Mod Save INT 16 +3 +3 WIS 10 +0 +0 CHA 6 -2 -2 Immunities Psychic Senses Darkvision 60 ft.; Passive Perception 10 Languages Deep Speech, understands the languages you know CR None (XP 0; PB equals your Proficiency Bonus) Traits Regeneration (Slaad Only). The spirit regains 5 Hit Points at the start of its turn if it has at least 1 Hit Point. Whispering Aura (Mind Flayer Only). At the start of each of the spirit’s turns, the spirit emits psionic energy if it doesn’t have the Incapacitated condition. Wisdom Saving Throw: DC equals your spell save DC, each creature (other than you) within 5 feet of the spirit. Failure: 2d6 Psychic damage. Actions Multiattack. The spirit makes a number of attacks equal to half this spell’s level (round down). Claw (Slaad Only). Melee Attack Roll: Bonus equals your spell attack modifier, reach 5 ft. Hit: 1d10 + 3 + the spell’s level Slashing damage, and the target can’t regain Hit Points until the start of the spirit’s next turn. Eye Ray (Beholderkin Only). Ranged Attack Roll: Bonus equals your spell attack modifier, range 150 ft. Hit: 1d8 + 3 + the spell’s level Psychic damage. Psychic Slam (Mind Flayer Only). Melee Attack Roll: Bonus equals your spell attack modifier, reach 5 ft. Hit: 1d8 + 3 + the spell’s level Psychic damage.', 'Concentration, up to 1 minute', 'b0b64fbd-3b92-4bd2-a684-578ba6f47e3b', false, true, false, true, true, 8, NULL, 'Gust of Wind', '300 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Ten berries appear in your hand. A creature can use a Bonus Action to eat one, restoring 1 HP and providing nourishment for a day.', 'Instantaneous', 'cdef9dcd-706c-4003-ae2a-59efde65ebef', false, true, false, true, true, 6, 'a tart and a feather', 'Sanctuary', 'Self', 'Abjuration', 'The damage increases by 1d8 for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You beseech an otherworldly entity for aid. The being must be known to you: a god, a demon prince, or some other being of cosmic power. That entity sends a Celestial, an Elemental, or a Fiend loyal to it to aid you, making the creature appear in an unoccupied space within range. If you know a specific creature’s name, you can speak that name when you cast this spell to request that creature, though you might get a different creature anyway (DM’s choice). When the creature appears, it is under no compulsion to behave a particular way. You can ask it to perform a service in exchange for payment, but it isn’t obliged to do so. The requested task could range from simple (fly us across the chasm, or help us fight a battle) to complex (spy on our enemies, or protect us during our foray into the dungeon). You must be able to communicate with the creature to bargain for its services. Payment can take a variety of forms. A Celestial might require a sizable donation of gold or magic items to an allied temple, while a Fiend might demand a living sacrifice or a gift of treasure. Some creatures might exchange their service for a quest undertaken by you. A task that can be measured in minutes requires a payment worth 100 GP per minute. A task measured in hours requires 1,000 GP per hour. And a task measured in days (up to 10 days) requires 10,000 GP per day. The DM can adjust these payments based on the circumstances under which you cast the spell. If the task is aligned with the creature’s ethos, the payment might be halved or even waived. Nonhazardous tasks typically require only half the suggested payment, while especially dangerous tasks might require a greater gift. Creatures rarely accept tasks that seem suicidal. After the creature completes the task, or when the agreed-upon duration of service expires, the creature returns to its home plane after reporting back to you if possible. If you are unable to agree on a price for the creature’s service, the creature immediately returns to its home plane.', '1 hour', '43eb1927-cd72-43b1-975e-407d0101c13e', false, false, false, true, true, 3, NULL, 'Gate', '120 feet', 'Evocation', 'The damage increases by 1d8 for each spell slot level above 3.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch a willing creature. For the duration, its movement is unaffected by Difficult Terrain, and spells and other magical effects can''t reduce its Speed or cause it to be Paralyzed or Restrained.', 'Concentration, up to 10 minutes', 'f73f6fd0-d2cb-46e9-9dbf-69e877323f99', false, false, false, true, true, 0, 'a diamond worth 50+ GP', 'Magic Jar', '60 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You shoot a greenish ray at a creature within range. Make a ranged spell attack against the target. On a hit, the target takes 2d8 Poison damage and has the Poisoned condition until the end of your next turn.', 'Instantaneous', 'b1847c09-c5a0-4891-91fd-414dda7e82b9', false, false, false, true, true, 4, 'a copper wire', 'Freezing Sphere', '60 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'This spell grants up to ten willing creatures of your choice within range the ability to breathe underwater until the spell ends. Affected creatures also retain their normal mode of respiration.', '1 hour', '7422b7cc-cdf4-45aa-8fbb-4d3a1039ac2b', false, true, false, true, true, 2, NULL, 'Guardian of Faith', '60 feet', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch a willing creature. The target gains a flying Speed of 60 feet for the duration. When the spell ends, the target falls if it is still aloft.', 'Concentration, up to 1 hour', 'b7f52c68-59c7-4b53-a291-f2fb256099b9', false, false, false, true, true, 8, '2 Copper Pieces, which the spell consumes', 'Thunderclap', 'Touch', 'Enchantment', 'The damage increases by 1d6 for every two spell slot levels above 2.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'The next time you hit a creature with a ranged weapon attack, thorns rain down. The target and each creature within 5 feet take 1d10 Piercing damage (DEX save for half).', '1 hour', '1728aed2-a547-496e-85b6-e96523609b97', true, false, false, true, true, 4, NULL, 'Enlarge/Reduce', 'Self', 'Evocation', 'You can target one additional creature for each spell slot level above 3.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You gain the service of a familiar, a spirit that takes an animal form you choose. It obeys your commands and can deliver touch spells for you.', '1 hour', '63659b26-52a5-4bff-b550-9c9f3fe2d954', false, false, false, true, true, 6, 'a piece of ice or glass', 'Greater Invisibility', 'Self', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'You place a curse on a creature that you can see within range. Until the spell ends, you deal an extra 1d6 Necrotic damage to the target whenever you hit it with an attack roll. Also, choose one ability when you cast the spell. The target has Disadvantage on ability checks made with the chosen ability. If the target drops to 0 Hit Points before this spell ends, you can take a Bonus Action on a later turn to curse a new creature.', '30 days', '693adace-295d-4715-8c9d-0caab280721f', true, false, true, true, true, 1, NULL, 'Prestidigitation', '120 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Protective spirits flit around you in a 15-foot Emanation for the duration. If you are good or neutral, their spectral form appears angelic or fey (your choice). If you are evil, they appear fiendish. When you cast this spell, you can designate creatures to be unaffected by it. Any other creature’s Speed is halved in the Emanation, and whenever the Emanation enters a creature’s space and whenever a creature enters the Emanation or ends its turn there, the creature must make a Wisdom saving throw. On a failed save, the creature takes 3d8 Radiant damage (if you are good or neutral) or 3d8 Necrotic damage (if you are evil). On a successful save, the creature takes half as much damage. A creature makes this save only once per turn.', '30 days', '7999e393-a3a6-4b67-959c-5e666f3e1d6a', false, true, false, true, true, 9, 'a leaf of sumac', 'Detect Evil and Good', 'Self', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You conjure a phantom watchdog in an unoccupied space that you can see within range. The hound remains for the duration or until the two of you are more than 300 feet apart from each other. No one but you can see the hound, and it is intangible and invulnerable. When a Small or larger creature comes within 30 feet of it without first speaking the password that you specify when you cast this spell, the hound starts barking loudly. The hound has Truesight with a range of 30 feet. At the start of each of your turns, the hound attempts to bite one enemy within 5 feet of it. That enemy must succeed on a Dexterity saving throw or take 4d8 Force damage. On your later turns, you can take a Magic action to move the hound up to 30 feet.', 'Instantaneous', '1b21114e-dd6b-45b2-bed6-c0c5eebd5042', false, false, false, true, true, 8, 'a diamond worth 5,000+ GP', 'True Seeing', '60 feet', 'Evocation', 'You can target one additional Humanoid for each spell slot level above 2.', '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'You gain the ability to move or manipulate creatures or objects by thought. When you cast the spell and as a Magic action on your later turns before the spell ends, you can exert your will on one creature or object that you can see within range, causing the appropriate effect below. You can affect the same target round after round or choose a new one at any time. If you switch targets, the prior target is no longer affected by the spell. Creature. You can try to move a Huge or smaller creature. The target must succeed on a Strength saving throw, or you move it up to 30 feet in any direction within the spell’s range. Until the end of your next turn, the creature has the Restrained condition, and if you lift it into the air, it is suspended there. It falls at the end of your next turn unless you use this option on it again and it fails the save. Object. You can try to move a Huge or smaller object. If the object isn’t being worn or carried, you automatically move it up to 30 feet in any direction within the spell’s range. If the object is worn or carried by a creature, that creature must succeed on a Strength saving throw, or you pull the object away and move it up to 30 feet in any direction within the spell’s range. You can exert fine control on objects with your telekinetic grip, such as manipulating a simple tool, opening a door or a container, stowing or retrieving an item from an open container, or pouring the contents from a vial.', 'Concentration, up to 1 minute', 'efc0790d-3628-4956-b09e-408d76aca382', true, true, false, true, false, 1, 'a prayer scroll', 'Mind Sliver', '120 feet', 'Evocation', 'The damage increases by 3d6 for each spell slot level above 6.', '2026-05-15 05:45:35.483105+00'),
	('1 minute or Ritual', '2026-05-15 05:45:35.483105+00', 'You place a magical command on a creature you can see. If it deviates from your instructions, it takes 5d10 psychic damage (once per day). Removing the spell requires Remove Curse, Greater Restoration, or Wish.', 'Concentration, up to 1 minute', '48e7ca5a-a6e2-4092-a5d6-a811f6453796', false, true, true, true, true, 5, NULL, 'Hallucinatory Terrain', '100 feet', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You curse a creature. You deal an extra 1d6 Necrotic damage to it whenever you hit it with an attack. Also, choose one ability; the target has Disadvantage on checks with that ability.', 'Instantaneous', 'f6ecf47c-1eac-4e29-8bfb-7b5143f810ed', true, false, false, true, true, 4, 'a bit of string and of wood', 'Demiplane', '60 feet', 'Necromancy', 'The damage increases by 1d8 for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create a telepathic link between yourself and a willing creature with which you are familiar. The creature can be anywhere on the same plane of existence as you. The spell ends if you or the target are no longer on the same plane. Until the spell ends, you and the target can instantly share words, images, sounds, and other sensory messages with each other through the link, and the target recognizes you as the creature it is communicating with. The spell enables a creature to understand the meaning of your words and any sensory messages you send to it.', 'Instantaneous', '7f120997-51e3-4a3e-baca-91e48d5a8f41', true, false, false, true, true, 6, NULL, 'Shield', '300 feet', 'Evocation', 'You can alter the target’s memories of an event that took place up to 7 days ago (level 6 spell slot), 30 days ago (level 7 spell slot), 365 days ago (level 8 spell slot), or any time in the creature’s past (level 9 spell slot).', '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'When you cast the spell and as a Bonus Action until it ends, you can make two attacks with a weapon that fires Arrows or Bolts, such as a Longbow or a Light Crossbow. The spell magically creates the ammunition needed for each attack. Each Arrow or Bolt created by the spell deals damage like a nonmagical piece of ammunition of its kind and disintegrates immediately after it hits or misses.', 'Concentration, up to 10 minutes', '6d7fe2a1-b245-44c2-bbee-a28370ccac27', false, true, false, true, true, 1, NULL, 'Witch Bolt', 'Self', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Choose an area of terrain no larger than 40 feet on a side within range. You can reshape dirt, sand, or clay in the area in any manner you choose for the duration. You can raise or lower the area’s elevation, create or fill in a trench, erect or flatten a wall, or form a pillar. The extent of any such changes can’t exceed half the area’s largest dimension. For example, if you affect a 40-foot square, you can create a pillar up to 20 feet high, raise or lower the square’s elevation by up to 20 feet, dig a trench up to 20 feet deep, and so on. It takes 10 minutes for these changes to complete. Because the terrain’s transformation occurs slowly, creatures in the area can’t usually be trapped or injured by the ground’s movement. At the end of every 10 minutes you spend concentrating on the spell, you can choose a new area of terrain to affect within range. This spell can’t manipulate natural stone or stone construction. Rocks and structures shift to accommodate the new terrain. If the way you shape the terrain would make a structure unstable, it might collapse. Similarly, this spell doesn’t directly affect plant growth. The moved earth carries any plants along with it.', 'Instantaneous', '84592bce-6d0c-42b5-94a2-2eb6f5f01d94', true, true, false, true, false, 7, 'a pinch of dirt', 'Telekinesis', '30 feet', 'Conjuration', 'The spell''s duration becomes ''Until Dispelled'' if you cast it in the same location every day for 30 days.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch a creature that has died within the last minute. That creature revives with 1 Hit Point. This spell can’t revive a creature that has died of old age, nor does it restore any missing body parts.', 'Concentration, up to 1 minute', 'ee1b9a29-1e7e-4c19-8ca5-2dac6439306c', true, true, false, true, true, 0, NULL, 'True Polymorph', '60 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You write a message that appears as whatever you want to everyone except those you designate. To others, it might look like gibberish or a completely different text.', '24 hours', '3f9410da-d99f-4a15-b7cb-5927a06d77c0', true, true, false, false, true, 2, 'a piece of charcoal', 'Identify', '300 feet', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You project a phantasmal image of a creature''s worst fears in a 60-foot Cone. Each creature in the area must succeed on a Wisdom save or have the Frightened condition.', '1 hour', '286f4e1a-0e20-4b2d-aab0-c277acc8dabe', false, true, false, true, true, 9, NULL, 'Silence', '60 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You forge a telepathic link among up to eight willing creatures of your choice within range, psychically linking each creature to all the others for the duration. Creatures that can’t communicate in any languages aren’t affected by this spell. Until the spell ends, the targets can communicate telepathically through the bond whether or not they share a language. The communication is possible over any distance, though it can’t extend to other planes of existence.', 'Concentration, up to 10 minutes', '5cc3526b-be73-4b43-b591-0e735a1d6feb', false, false, false, false, false, 2, 'a miniature ziggurat', 'Mage Hand', '300 feet', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Choose an object that you can see within range. The object can be a door, a box, a chest, a set of manacles, a padlock, or another object that contains a mundane or magical means that prevents access. A target that is held shut by a mundane lock or that is stuck or barred becomes unlocked, unstuck, or unbarred. If the object has multiple locks, only one of them is unlocked. If the target is held shut by Arcane Lock, that spell is suppressed for 10 minutes, during which time the target can be opened and closed. When you cast the spell, a loud knock, audible up to 300 feet away, emanates from the target.', '24 hours', '2af3a5ac-b227-4795-8c3f-51a65203d615', true, true, false, true, true, 2, 'gauze and smoke', 'Misty Step', 'Touch', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You gain the service of a familiar, a spirit that takes an animal form you choose. It obeys your commands and can deliver touch spells for you.', 'Concentration, up to 1 hour', '5a57b4da-1475-45aa-8b77-e42b4982939f', true, true, false, true, true, 5, 'a tiny ball of bat guano and sulfur', 'Demiplane', '1 mile', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action or Ritual', '2026-05-15 05:45:35.483105+00', 'A loud noise erupts from a point of your choice within range. Each creature in a 10-foot-radius Sphere centered there makes a Constitution saving throw, taking 3d8 Thunder damage on a failed save or half as much damage on a successful one. A Construct has Disadvantage on the save. A nonmagical object that isn’t being worn or carried also takes the damage if it’s in the spell’s area.', '10 minutes', 'aae4d8b7-1909-4cb2-9f26-196fcc903611', true, false, false, true, true, 6, NULL, 'Earthquake', 'Self', 'Enchantment', 'The duration increases to 8 hours if cast with a level 9 spell slot.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Each creature in a 5-foot Emanation originating from you must succeed on a Constitution saving throw or take 1d6 Thunder damage. The spell’s thunderous sound can be heard up to 100 feet away. Cantrip Upgrade. The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).', 'Concentration, up to 1 hour', '816a01c8-144e-447b-bf36-ba83d1cd77d2', false, false, false, true, true, 6, 'ruby dust worth 1,500+ GP', 'Expeditious Retreat', '60 feet', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('24 hours', '2026-05-15 05:45:35.483105+00', 'You gain the Invisible condition at the same time that an illusory double of you appears where you are standing. The double lasts for the duration, but the invisibility ends immediately after you make an attack roll, deal damage, or cast a spell. As a Magic action, you can move the illusory double up to twice your Speed and make it gesture, speak, and behave in whatever way you choose. It is intangible and invulnerable. You can see through its eyes and hear through its ears as if you were located where it is.', 'Concentration, up to 1 hour', '722a0274-e402-4977-b1e5-2b8a32487cb6', false, true, false, true, true, 9, 'a yew leaf', 'Stoneskin', '60 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch a willing creature. Once before the spell ends, the target can roll a d4 and add the number to one ability check of its choice.', 'Instantaneous', '38f0b6d9-620d-4457-b51a-73b6bfcee0e4', false, true, false, true, true, 1, 'a forked, metal rod worth 250+ GP and attuned to a plane of existence', 'Enlarge/Reduce', 'Touch', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Choose a creature that you can see within range. Positive energy washes through the target, restoring 70 Hit Points. This spell also ends the Blinded, Deafened, and Poisoned conditions on the target.', 'Instantaneous', '29cb5ee3-b2e4-41b0-b26d-8713765e0473', false, false, false, true, true, 6, NULL, 'Fly', 'Self', 'Necromancy', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You hurl an orb of energy at a target within range. Choose Acid, Cold, Fire, Lightning, Poison, or Thunder for the type of orb you create, and then make a ranged spell attack against the target. On a hit, the target takes 3d8 damage of the chosen type. If you roll the same number on two or more of the d8s, the orb leaps to a different target of your choice within 30 feet of the target. Make an attack roll against the new target, and make a new damage roll. The orb can’t leap again unless you cast the spell with a level 2+ spell slot.', 'Instantaneous', '6350c7fe-a0fd-483d-a353-9007639789a7', true, false, false, true, true, 0, NULL, 'Enlarge/Reduce', '30 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'You ward a creature within range. Until the spell ends, any creature who targets the warded creature with an attack roll or a damaging spell must succeed on a Wisdom saving throw or either choose a new target or lose the attack or spell. This spell doesn’t protect the warded creature from areas of effect. The spell ends if the warded creature makes an attack roll, casts a spell, or deals damage.', 'Instantaneous', 'fb42c162-de9c-4744-a4d9-4375b7456a19', true, false, false, true, true, 6, 'diamond dust worth 100+ GP, which the spell consumes', 'Speak with Plants', '120 feet', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Choose a willing creature that you can see within range. Until the spell ends, the target’s Speed is doubled, it gains a +2 bonus to Armor Class, it has Advantage on Dexterity saving throws, and it gains an additional action on each of its turns. That action can be used to take only the Attack (one attack only), Dash, Disengage, Hide, or Utilize action. When the spell ends, the target is Incapacitated and has a Speed of 0 until the end of its next turn, as a wave of lethargy washes over it.', 'Instantaneous', 'b73a4244-b92c-4751-88ef-b9c87fb3b4db', true, true, false, true, true, 4, NULL, 'Heroes’ Feast', '60 feet', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You radiate a concealing aura in a 30-foot Emanation for the duration. While in the aura, you and each creature you choose have a +10 bonus to Dexterity (Stealth) checks and leave no tracks.', 'Until dispelled', '8625963f-96ff-4d77-9b79-967febcdb5ed', true, true, false, true, true, 9, 'a forked twig', 'Prismatic Spray', '120 feet', 'Evocation', 'The healing increases by 1d8 for each spell slot level above 5.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch one Large or smaller object that isn’t being worn or carried by someone else. Until the spell ends, the object sheds Bright Light in a 20-foot radius and Dim Light for an additional 20 feet. The light can be colored as you like. Covering the object with something opaque blocks the light. The spell ends if you cast it again.', 'Instantaneous', 'fda3174b-079f-4d97-ade5-776155ba8948', true, true, false, true, true, 3, NULL, 'Detect Thoughts', 'Touch', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action or Ritual', '2026-05-15 05:45:35.483105+00', 'This spell repairs a single break or tear in an object you touch, such as a broken chain link, two halves of a broken key, a torn cloak, or a leaking wineskin. As long as the break or tear is no larger than 1 foot in any dimension, you mend it, leaving no trace of the former damage. This spell can physically repair a magic item, but it can’t restore magic to such an object.', '10 days', 'e8d70a7b-1ba8-4bdc-9c72-28bb67d1689d', false, true, true, true, true, 8, NULL, 'Power Word Fortify', '30 feet', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You make yourself—including your clothing, armor, weapons, and other belongings on your person—look different until the spell ends or until you use your action to dismiss it.', 'Instantaneous', 'ea1ff260-538d-410b-89e8-d4104d13c4b6', true, false, false, true, true, 1, NULL, 'Seeming', 'Self', 'Conjuration', 'You can target one additional creature for each spell slot level above 3.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Your eyes become an inky void. One creature you can see makes a Wisdom save or suffers one of three effects: Asleep, Panicked, or Sickened.', 'Instantaneous', '21e69f68-8f22-4772-8e9b-890bae0627f8', false, true, false, true, true, 9, 'a piece of seaweed', 'Magic Missile', '30 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 hour', '2026-05-15 05:45:35.483105+00', 'Choose a creature you can see. It must succeed on a WIS save or be Paralyzed. It repeats the save at the end of each of its turns.', 'Concentration, up to 1 minute', 'f1b24cc6-4637-41e4-a3c1-32e06a164886', false, true, false, true, true, 1, 'powdered diamond worth 200+ GP, which the spell consumes', 'Shield', 'Self', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A 10-foot-radius Sphere of cold energy streaks from your fingers. Creatures in the area take 10d6 Cold damage (Con save for half). If the area includes water, it freezes to a depth of 6 inches.', '8 hours', 'e49330ab-1817-4275-a672-5c6bd37aa5a1', false, true, false, true, true, 0, 'an object with the image of a dragon engraved on it worth 500+ GP', 'Sending', '300 feet', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A tiny yellow bead streaks to a point and lingers. When the spell ends or you detonate it, creatures in a 20-foot-radius Sphere take 12d6 Fire damage (Dex save for half). Damage increases if you wait to detonate.', 'Instantaneous', 'cea8172f-7378-45da-a1c6-2c22bf184385', true, true, false, true, true, 3, 'a legume seed', 'Dominate Person', 'Self', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You choose a creature and mark it as your quarry. You deal an extra 1d6 damage to the target whenever you hit it with a weapon attack, and you have Advantage on Perception or Survival checks to find it.', 'Concentration, up to 1 hour', '988b3d7f-7c52-4a0e-a505-2f15effc5834', false, false, false, true, true, 1, NULL, 'Forcecage', 'Touch', 'Evocation', 'The healing increases by 1d4 for each spell slot level above 3.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'One creature that you can see within range must make a Wisdom saving throw. On a successful save, the target dances comically until the end of its next turn, during which it must spend all its movement to dance in place. On a failed save, the target has the Charmed condition for the duration. While Charmed, the target dances comically, must use all its movement to dance in place, and has Disadvantage on Dexterity saving throws and attack rolls, and other creatures have Advantage on attack rolls against it. On each of its turns, the target can take an action to collect itself and repeat the save, ending the spell on itself on a success.', '10 minutes', '3b628a24-0d92-4294-bcff-d1d291bc2ab4', true, true, false, true, true, 1, 'an eyelash in gum arabic', 'Hunger of Hadar', 'Self', 'Necromancy', 'The amount of Temporary Hit Points increases by 5 for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A swirling cloud of embers and smoke fills a 20-foot-radius Sphere centered on a point within range. The cloud’s area is Heavily Obscured. It lasts for the duration or until a strong wind (like that created by Gust of Wind) disperses it. When the cloud appears, each creature in it makes a Dexterity saving throw, taking 10d8 Fire damage on a failed save or half as much damage on a successful one. A creature must also make this save when the Sphere moves into its space and when it enters the Sphere or ends its turn there. A creature makes this save only once per turn. The cloud moves 10 feet away from you in a direction you choose at the start of each of your turns.', 'Instantaneous', 'b6a5e12d-d7a3-4145-9378-4f52d2dc254a', false, true, false, true, true, 2, NULL, 'Magic Jar', 'Touch', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Bonus Action', '2026-05-15 05:45:35.483105+00', 'A shimmering sphere encloses a Large or smaller creature or object within range. An unwilling creature must succeed on a Dexterity saving throw or be enclosed for the duration. Nothing—not physical objects, energy, or other spell effects—can pass through the barrier, in or out, though a creature in the sphere can breathe there. The sphere is immune to all damage, and a creature or object inside can’t be damaged by attacks or effects originating from outside, nor can a creature inside the sphere damage anything outside it. The sphere is weightless and just large enough to contain the creature or object inside. An enclosed creature can take an action to push against the sphere’s walls and thus roll the sphere at up to half the creature’s Speed. Similarly, the globe can be picked up and moved by other creatures. A Disintegrate spell targeting the globe destroys it without harming anything inside.', 'Instantaneous', '5c52c068-eeb9-4592-8fc6-95610d3c05a6', false, true, false, true, true, 0, 'powdered rhubarb leaf', 'Mass Cure Wounds', '30 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('1 minute', '2026-05-15 05:45:35.483105+00', 'You surge positive energy into a creature, restoring 70 HP. It also ends Blinded, Deafened, and any diseases.', 'Concentration, up to 1 hour', '9fe994f7-e2a8-4b4c-9adb-2c34bfa3b641', false, false, false, true, true, 3, NULL, 'Spiritual Weapon', '60 feet', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Flame-like radiance descends on a creature that you can see within range. The target must succeed on a Dexterity saving throw or take 1d8 Radiant damage. The target gains no benefit from Half Cover or Three-Quarters Cover for this save. Cantrip Upgrade. The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).', 'Concentration, up to 10 minutes', '35312ab4-5c9f-4d04-95b5-369000bd4671', true, true, false, false, true, 0, NULL, 'Freezing Sphere', 'Self', 'Enchantment', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A beam of crackling energy lances toward a creature within range, forming a sustained arc of lightning between you and the target. Make a ranged spell attack against it. On a hit, the target takes 2d12 Lightning damage. On each of your subsequent turns, you can take a Bonus Action to deal 1d12 Lightning damage to the target automatically, even if the first attack missed. The spell ends if the target is ever outside the spell’s range or if it has Total Cover from you.', 'Concentration, up to 1 minute', '33bec456-08c4-422e-8658-bb74846bdaae', false, true, false, true, true, 5, NULL, 'Spider Climb', '60 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You unleash virulent magic on a creature you can see within range. The target makes a Constitution saving throw. On a failed save, it takes 14d6 Necrotic damage, and its Hit Point maximum is reduced by an amount equal to the Necrotic damage it took. On a successful save, it takes half as much damage only. This spell can’t reduce a target’s Hit Point maximum below 1.', 'Concentration, up to 1 minute', '6da75fce-0a34-474d-9ae9-d2e86e3db5f2', true, true, false, true, true, 9, NULL, 'Giant Insect', 'Self', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You create an illusory copy of yourself that lasts for the duration. The copy can appear at any location within range that you have seen before, regardless of intervening obstacles. The illusion looks and sounds like you, but it is intangible. If the illusion takes any damage, it disappears, and the spell ends. You can see through the illusion’s eyes and hear through its ears as if you were in its space. As a Magic action, you can move it up to 60 feet and make it gesture, speak, and behave in whatever way you choose. It mimics your mannerisms perfectly. Physical interaction with the image reveals it to be illusory, since things can pass through it. A creature that takes the Study action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and any noise it makes sounds hollow to the creature.', 'Instantaneous', '5afdc947-13fc-4baa-b9f4-2f90271451e3', false, true, false, false, true, 3, 'a firefly or phosphorescent moss', 'Guards and Wards', '120 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Choose a Humanoid that you can see within range. The target must succeed on a Wisdom saving throw or have the Paralyzed condition for the duration. At the end of each of its turns, the target repeats the save, ending the spell on itself on a success.', 'Concentration, up to 1 minute', '040ecf37-317a-4529-90bd-c199a3b0fe3d', true, true, false, true, true, 2, 'diamonds worth 25,000+ GP, which the spell consumes', 'Greater Invisibility', '120 feet', 'Illusion', 'You automatically end the effects of a spell on the target if the spell’s level is equal to or less than the level of the spell slot used.', '2026-05-15 05:45:35.483105+00'),
	('Reaction', '2026-05-15 05:45:35.483105+00', 'You compel one creature you can see within range to die. If the target has 100 Hit Points or fewer, it dies. Otherwise, it takes 12d12 Psychic damage.', '10 minutes', 'b8662aa4-ff8b-4d64-883c-69f895a4c5c7', false, true, false, true, true, 8, 'a pinch of sand or rose petals', 'Gust of Wind', 'Touch', 'Abjuration', 'The damage increases by 1d10 for each spell slot level above 2.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You unleash a virulent disease. The target makes a CON save, taking 14d6 Necrotic damage on a failure (half on success). Its HP maximum is reduced by the damage taken for 1 hour.', 'Instantaneous', 'faed59c3-13ef-4d2e-ba6d-e2935c91484d', false, false, false, false, true, 3, NULL, 'Prismatic Wall', '60 feet', 'Abjuration', 'The damage increases by 1d10 for each spell slot level above 1.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You launch a mote of light at one creature or object within range. Make a ranged spell attack against the target. On a hit, the target takes 1d8 Radiant damage, and until the end of your next turn, it emits Dim Light in a 10-foot radius and can’t benefit from the Invisible condition. Cantrip Upgrade. The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).', '24 hours', '6d68995e-85e6-4372-8260-d7208179bf29', true, true, false, true, true, 0, 'a short reed', 'Enthrall', 'Self', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'Protective spirits flit around you in a 15-foot Emanation for the duration. If you are good or neutral, their spectral form appears angelic or fey (your choice). If you are evil, they appear fiendish. When you cast this spell, you can designate creatures to be unaffected by it. Any other creature’s Speed is halved in the Emanation, and whenever the Emanation enters a creature’s space and whenever a creature enters the Emanation or ends its turn there, the creature must make a Wisdom saving throw. On a failed save, the creature takes 3d8 Radiant damage (if you are good or neutral) or 3d8 Necrotic damage (if you are evil). On a successful save, the creature takes half as much damage. A creature makes this save only once per turn.', 'Concentration, up to 1 minute', '5ea56021-c725-4248-84ef-b908d1b6c099', false, false, false, true, true, 5, 'a miniature door worth 15+ GP', 'Starry Wisp', 'Touch', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A creature of your choice that you can see within range regains Hit Points equal to 2d4 plus your spellcasting ability modifier.', 'Until dispelled', 'f3ca4b45-7d7e-48d4-8d7a-9a2f087ca776', true, true, false, true, true, 8, 'a strip of white cloth', 'Freezing Sphere', 'Touch', 'Illusion', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'A flickering flame appears in your hand and remains there for the duration. While there, the flame emits no heat and ignites nothing, and it sheds Bright Light in a 20-foot radius and Dim Light for an additional 20 feet. The spell ends if you cast it again. Until the spell ends, you can take a Magic action to hurl fire at a creature or an object within 60 feet of you. Make a ranged spell attack. On a hit, the target takes 1d8 Fire damage. Cantrip Upgrade. The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).', '10 minutes', '4d79209d-7fcb-42d6-9062-dede334291ac', false, true, false, true, true, 7, 'burning incense, sulfur, and lead', 'Power Word Heal', '60 feet', 'Abjuration', 'The duration increases to Concentration, up to 10 minutes (level 5), 1 hour (level 6), or 8 hours (level 7+).', '2026-05-15 05:45:35.483105+00'),
	('Bonus Action, which you take immediately after hitting a creature with a Ranged weapon', '2026-05-15 05:45:35.483105+00', 'You write a message that appears as whatever you want to everyone except those you designate. To others, it might look like gibberish or a completely different text.', 'Until dispelled or triggered', '065b25b0-ae11-453d-9982-925644f764d2', false, true, false, true, true, 0, 'a rotten egg', 'Sacred Flame', '120 feet', 'Evocation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You hurl an orb of energy at a target within range. Choose Acid, Cold, Fire, Lightning, Poison, or Thunder for the type of orb you create, and then make a ranged spell attack against the target. On a hit, the target takes 3d8 damage of the chosen type. If you roll the same number on two or more of the d8s, the orb leaps to a different target of your choice within 30 feet of the target. Make an attack roll against the new target, and make a new damage roll. The orb can’t leap again unless you cast the spell with a level 2+ spell slot.', 'Instantaneous', 'df79c254-8b83-4026-8565-9c7f17a764c9', true, true, false, true, true, 1, NULL, 'Fire Bolt', 'Special', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'For the duration, the willing creature you touch has Truesight with a range of 120 feet.', 'Until dispelled', '9fab34ff-a40c-4f74-9dd7-5e9e81b72bde', false, true, false, true, true, 2, 'a small square of silk', 'Thorn Whip', '60 feet', 'Divination', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'This spell grants up to ten willing creatures of your choice within range the ability to breathe underwater until the spell ends. Affected creatures also retain their normal mode of respiration.', '1 hour', '1842918d-3478-4daa-81cb-7327c4d70db3', true, true, false, true, true, 3, 'a diamond worth 5,000+ GP', 'Power Word Fortify', 'Self', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'This spell grants up to ten willing creatures of your choice within range the ability to breathe underwater until the spell ends. Affected creatures also retain their normal mode of respiration.', 'Instantaneous', '1b24ff4f-c735-4d1f-a069-2b531156ca49', false, false, false, false, false, 6, NULL, 'Find Traps', '30 feet', 'Transmutation', NULL, '2026-05-15 05:45:35.483105+00'),
	('10 minutes', '2026-05-15 05:45:35.483105+00', 'You unleash virulent magic on a creature you can see within range. The target makes a Constitution saving throw. On a failed save, it takes 14d6 Necrotic damage, and its Hit Point maximum is reduced by an amount equal to the Necrotic damage it took. On a successful save, it takes half as much damage only. This spell can’t reduce a target’s Hit Point maximum below 1.', '10 minutes', 'b96f7845-5629-4a85-809a-9b475d6883a0', true, false, false, true, true, 1, 'a chest, 3 feet by 2 feet by 2 feet, constructed from rare materials worth 5,000+ GP, and a Tiny replica of the chest made from the same materials worth 50+ GP', 'Otto’s Irresistible Dance', '30 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'An immobile, shimmering barrier surrounds you. Any spell of level 5 or lower cast from outside cannot affect anything within the globe, even if upcast.', 'Concentration, up to 1 minute', 'c9ada779-50bb-418b-be18-07f0f1a7c252', true, true, true, true, true, 2, NULL, 'Find Familiar', '30 feet', 'Abjuration', 'The barrier blocks spells of 1 level higher for each spell slot level above 6.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You conjure a vine that sprouts from a surface in an unoccupied space that you can see within range. The vine lasts for the duration. Make a melee spell attack against a creature within 30 feet of the vine. On a hit, the target takes 4d8 Bludgeoning damage and is pulled up to 30 feet toward the vine; if the target is Huge or smaller, it has the Grappled condition (escape DC equal to your spell save DC). The vine can grapple only one creature at a time, and you can cause the vine to release a Grappled creature (no action required). As a Bonus Action on your later turns, you can repeat the attack against a creature within 30 feet of the vine.', 'Concentration, up to 10 minutes', '6ec37dd3-cac6-4720-ac30-d5f7b1fdd6ce', true, true, false, true, true, 1, 'a crystal bead', 'Leomund’s Tiny Hut', '30 feet', 'Conjuration', NULL, '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You touch an object throughout the spell’s casting. If the object is a magic item or some other magical object, you learn its properties and how to use them, whether it requires Attunement, and how many charges it has, if any. You learn whether any ongoing spells are affecting the item and what they are. If the item was created by a spell, you learn that spell’s name. If you instead touch a creature throughout the casting, you learn which ongoing spells, if any, are currently affecting it.', 'Instantaneous', 'f70e89d4-13b3-4ccd-8e10-1488e4d3f894', true, true, false, true, true, 3, 'pearl worth 100 GP and an owl feather', 'Leomund’s Tiny Hut', '90 feet', 'Evocation', 'The damage increases by 1d6 for every two spell slot levels above 2.', '2026-05-15 05:45:35.483105+00'),
	('Action', '2026-05-15 05:45:35.483105+00', 'You attempt to craft an illusion in the mind of a creature you can see within range. The target makes an Intelligence saving throw. On a failed save, you create a phantasmal object, creature, or other phenomenon that is no larger than a 10-foot Cube and that is perceivable only to the target for the duration. The phantasm includes sound, temperature, and other stimuli. The target can take a Study action to examine the phantasm with an Intelligence (Investigation) check against your spell save DC. If the check succeeds, the target realizes that the phantasm is an illusion, and the spell ends. While affected by the spell, the target treats the phantasm as if it were real and rationalizes any illogical outcomes from interacting with it. For example, if the target steps through a phantasmal bridge and survives the fall, it believes the bridge exists and something else caused it to fall. An affected target can even take damage from the illusion if the phantasm represents a dangerous creature or hazard. On each of your turns, such a phantasm can deal 2d8 Psychic damage to the target if it is in the phantasm’s area or within 5 feet of the phantasm. The target perceives the damage as a type appropriate to the illusion.', 'Instantaneous', '60a19f14-dd62-40b0-958e-c9ae1fa3be8e', false, false, false, false, true, 2, NULL, 'Shocking Grasp', '90 feet', 'Abjuration', NULL, '2026-05-15 05:45:35.483105+00');


